-- Poems batch 251
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fdc3e049-5a36-47d3-8778-09477ed028a0','偈頌一百零二首  其四四','釋紹曇','宋','宋诗','song-poetry','','[]','枯木糝瑶花，虛庭封玉砌。',38,'全唐诗/poet.song.226000.json','["枯木糝瑶花，虛庭封玉砌。", "少室謾安心，神光空折臂。", "不墮功勛一色邊，闌干誰共倚。"]'),
('6c5776e1-a4c7-4a71-af01-b4b8417cfca8','偈頌一百零二首  其四五','釋紹曇','宋','宋诗','song-poetry','','[]','四十九年，欺胡謾漢。',34,'全唐诗/poet.song.226000.json','["四十九年，欺胡謾漢。", "疾入涅槃，救得一半。", "諦觀紫磨金色身，涴却娘生眼。"]'),
('034befe2-64a8-4382-82ce-52844b07a0fc','偈頌一百零二首  其四六','釋紹曇','宋','宋诗','song-poetry','','[]','我有一機，極盡玄微。',40,'全唐诗/poet.song.226000.json','["我有一機，極盡玄微。", "饑來喫飯，寒來著衣。", "我有一句，包羅今古。", "犬吠枯樁，貓捉老鼠。"]'),
('d167cf84-d6e1-4837-8951-055a24c40971','偈頌一百零二首  其四七','釋紹曇','宋','宋诗','song-poetry','','[]','花錦蝶翻紅，柳烟鶑織曉。',62,'全唐诗/poet.song.226000.json','["花錦蝶翻紅，柳烟鶑織曉。", "曾不動機絲，奪盡春工巧。", "玄中玄，妙中妙。", "三世諸佛覷不破，歷代祖師窮不到。", "窮得到，寒食清明，家家拜掃。"]'),
('df2c6afe-3e73-424e-bf02-07e4e0122680','偈頌一百零二首  其四八','釋紹曇','宋','宋诗','song-poetry','','[]','路透清波，山橫翠壁。',20,'全唐诗/poet.song.226000.json','["路透清波，山橫翠壁。", "樓閣門開，從這裡入。"]'),
('2a84f7cc-2ed0-4d24-b155-da46de9b9616','偈頌一百零二首  其四九','釋紹曇','宋','宋诗','song-poetry','','[]','三十二相，八十種好。',40,'全唐诗/poet.song.226000.json','["三十二相，八十種好。", "馬頷馿腮，彌天羅過。", "新法華，因甚刺腦入膠盆。", "過在你，殃及我。"]'),
('bad8d3ee-4dfa-442a-994e-6c87f0a4d963','偈頌一百零二首  其五○','釋紹曇','宋','宋诗','song-poetry','','[]','正直聰明，風流儒雅。',28,'全唐诗/poet.song.226000.json','["正直聰明，風流儒雅。", "堅護法城，策勳千載。", "李將軍有佳聲在。"]'),
('0ec44283-a3cc-4bef-8cf9-03442a40289b','偈頌一百零二首  其五一','釋紹曇','宋','宋诗','song-poetry','','[]','靈鷲峰前，熱血相噴。',36,'全唐诗/poet.song.226000.json','["靈鷲峰前，熱血相噴。", "覺城東際，陷坑無底。", "失脚休論後與先，癡翁何似我風顛。"]'),
('2e70e607-cb31-432a-817e-260aaef95a9c','偈頌一百零二首  其五二','釋紹曇','宋','宋诗','song-poetry','','[]','智與理冥，神與境會。',32,'全唐诗/poet.song.226000.json','["智與理冥，神與境會。", "碎維摩床，斷毗盧髻。", "碧眼黄頭著眼覷，百雜碎。"]'),
('66432579-09a0-434b-b51a-d8c5dc9da5d8','偈頌一百零二首  其五三','釋紹曇','宋','宋诗','song-poetry','','[]','頂𩕳機，法空座。',26,'全唐诗/poet.song.226000.json','["頂𩕳機，法空座。", "不涉思而知，不動步而到，無端入荒草。"]'),
('12bae0fd-d3e2-4482-bd7f-c6c70064a607','偈頌一百零二首  其五四','釋紹曇','宋','宋诗','song-poetry','','[]','借家傳帝網絲，下公子仙鼇釣。',54,'全唐诗/poet.song.226000.json','["借家傳帝網絲，下公子仙鼇釣。", "捩轉衲僧鼻頭，撩撥諸方一笑。", "鯤化鵬飛總未知，推蓬對月平分破。", "却請維那，揚帆皷棹。"]'),
('d10df84e-07cf-4adb-a07a-f884196f5971','偈頌一百零二首  其五五','釋紹曇','宋','宋诗','song-poetry','','[]','韓柳肺腸，蘇黄骨髓。',28,'全唐诗/poet.song.226000.json','["韓柳肺腸，蘇黄骨髓。", "點著禪衣，香風匝地。", "七十二峰增秀氣。"]'),
('ae6adc4f-5722-42b8-8c01-b98a40461e82','偈頌一百零二首  其五六','釋紹曇','宋','宋诗','song-poetry','','[]','共飯江湖，何須晙鬭。',36,'全唐诗/poet.song.226000.json','["共飯江湖，何須晙鬭。", "含血噴人，先污其口。", "結成不共戴天冤，句句無非是駡門。"]'),
('8973871c-c83d-428f-bb17-01e7a153fce9','偈頌一百零二首  其五七','釋紹曇','宋','宋诗','song-poetry','','[]','三百斤鐵枷，數載無人荷。',40,'全唐诗/poet.song.226000.json','["三百斤鐵枷，數載無人荷。", "颺在壁根頭，只得冤讎到。", "口款分明不可翻，老肩無力也須擔。"]'),
('dc90772a-2ec8-4e52-a764-6cfadc9e0936','偈頌一百零二首  其五八','釋紹曇','宋','宋诗','song-poetry','','[]','尊貴中來，報土無差。',36,'全唐诗/poet.song.226000.json','["尊貴中來，報土無差。", "瓊琚庭院，錦綉樓臺。", "何似靈山聽法華，聯鑣穩駕白牛車。"]'),
('f274177c-8be1-4190-84b4-a2f8fce07760','偈頌一百零二首  其五九','釋紹曇','宋','宋诗','song-poetry','','[]','老倒住山，全無伎倆。',50,'全唐诗/poet.song.226000.json','["老倒住山，全無伎倆。", "揖客低腰，逢僧合掌。", "雖然俯順時宜，不礙當機收放。", "鯤化鵬飛羽翼齊，摶扶一舉青霄上。"]'),
('22294de8-801d-4408-835d-600b6770ae5b','偈頌一百零二首  其六○','釋紹曇','宋','宋诗','song-poetry','','[]','盧老無端颺下柴，碓頭舂出古菱花。',32,'全唐诗/poet.song.226000.json','["盧老無端颺下柴，碓頭舂出古菱花。", "惡聲千載成狼籍，養子誰人解克家。"]'),
('c884d229-f09b-479d-bae4-e36b5b93a29c','偈頌一百零二首  其六一','釋紹曇','宋','宋诗','song-poetry','','[]','三伏走人間，炎蒸汗如雨。',61,'全唐诗/poet.song.226000.json','["三伏走人間，炎蒸汗如雨。", "非無休歇時，亦無栖泊處。", "拄杖子，脊梁生鐵鑄，浩浩塵中能辨主。", "歸來息影翠微深，抹月披雲，截斷千差路。"]'),
('9e7cebfe-cda9-42ac-948d-d2bd192eeb4e','偈頌一百零二首  其六二','釋紹曇','宋','宋诗','song-poetry','','[]','籬菊鋪黄，茱萸噴香。',65,'全唐诗/poet.song.226000.json','["籬菊鋪黄，茱萸噴香。", "淵明錯會，耽賞重陽。", "何似林間衲子，無榮無辱，無可思量。", "飽噇香積飯，高卧古禪床。", "是佛是魔俱掃跡，獻花無路鳥空忙。"]'),
('122f1f5d-51b1-44ff-8776-a908e2b3ce68','偈頌一百零二首  其六三','釋紹曇','宋','宋诗','song-poetry','','[]','湖山蒼蒼，湖水茫茫。',37,'全唐诗/poet.song.226000.json','["湖山蒼蒼，湖水茫茫。", "丹楓飄錦，金橘鋪黄。", "明眼衲僧，隨境轉聖凡，無處覓行藏。"]'),
('b6c85acc-c9d5-43c4-ae1e-b63df4b81d24','偈頌一百零二首  其六四','釋紹曇','宋','宋诗','song-poetry','','[]','太白峰前施小伎，淵嘿雷霆人自畏。',58,'全唐诗/poet.song.226000.json','["太白峰前施小伎，淵嘿雷霆人自畏。", "瓦礫翻成釋梵宮，古佛門風重振起。", "不墮功勳，等閑遊戲。", "金毛獅子忽翻身，草木昆蟲俱收淚。"]'),
('cc0a01ad-f676-411b-a7ff-1d6cfb762acc','偈頌一百零二首  其六五','釋紹曇','宋','宋诗','song-poetry','','[]','覺城東際，小小叢林。',44,'全唐诗/poet.song.226000.json','["覺城東際，小小叢林。", "旃檀圍繞，獅子嚬呻。", "蘿月四窗雲萬壑，見成一片祖師心。", "眼裏無筋一世貧。"]'),
('e6999632-4629-43b3-820e-f131f39f53b1','偈頌一百零二首  其六六','釋紹曇','宋','宋诗','song-poetry','','[]','落寞山家，忙如火急。',46,'全唐诗/poet.song.226000.json','["落寞山家，忙如火急。", "趁晴刈茆，带霜收橘。", "山僧冷地思量，盡把家私狼籍。", "日日日東上，日日日西沒。"]'),
('5d47276c-0aa5-47a9-abac-edb84d71bbc1','偈頌一百零二首  其六七','釋紹曇','宋','宋诗','song-poetry','','[]','久病脚力衰，嬰兒學移步。',56,'全唐诗/poet.song.226000.json','["久病脚力衰，嬰兒學移步。", "喪盡目前機，辯得麈中主。", "鼻直眼橫，皮穿骨露。", "馿不成兮馬不成，且無描摸處。", "賺殺僧繇吳道子。"]'),
('ad18d80e-367f-4c76-aae3-5a8db20a6b50','偈頌一百零二首  其六八','釋紹曇','宋','宋诗','song-poetry','','[]','大康山，楊浮山。',36,'全唐诗/poet.song.226000.json','["大康山，楊浮山。", "撞頭搕額，共打鄉談。", "其中切脚無人會，一大藏教，華梵重翻。"]'),
('dbae45ee-77eb-49aa-bac7-2a6ff6ad5a70','偈頌一百零二首  其六九','釋紹曇','宋','宋诗','song-poetry','','["\u592a\u6e56"]','西風簇浪花，太湖連底凍。',47,'全唐诗/poet.song.226000.json','["西風簇浪花，太湖連底凍。", "冷照玉奩清，一片無瑕縫。", "面目分明，眼睛定動。", "不墯虛凝裂萬差，漆桶漆桶。"]'),
('d3bbd294-4862-4b2a-93de-fc9f2cb163f4','偈頌一百零二首  其七○','釋紹曇','宋','宋诗','song-poetry','','[]','梅開的皪花，徑糝模糊雪。',63,'全唐诗/poet.song.226000.json','["梅開的皪花，徑糝模糊雪。", "裝點早春容，慶賀新年節。", "少室家風，全機漏泄。", "堪笑神光不識瞥，白把一枝臂折。", "有屈難伸說，無端拄杖重饒舌。"]'),
('34212a95-ef3f-4e9c-838b-a6c1a60c67c9','偈頌一百零二首  其七一','釋紹曇','宋','宋诗','song-poetry','','[]','生諸馮，御飛龍。',42,'全唐诗/poet.song.226000.json','["生諸馮，御飛龍。", "昇平寰宇，舜日堯風。", "林下野人思報德，只憑拄杖爲流通。", "雲卧難逃至化中。"]'),
('53bd67e5-748b-4304-aa52-2f59a341f9e9','偈頌一百零二首  其七二','釋紹曇','宋','宋诗','song-poetry','','[]','楊岐栗棘蓬，臨際清凉樹。',58,'全唐诗/poet.song.226000.json','["楊岐栗棘蓬，臨際清凉樹。", "钁頭無柄，正好栽培，版齒生毛，不妨吞吐。", "一抽三，二添四，跛脚雲門，乾坤獨步。", "瞎人天眼分緇素。"]'),
('a1b38084-5fb9-43e8-b329-7599692b4d97','偈頌一百零二首  其七三','釋紹曇','宋','宋诗','song-poetry','','[]','人間萬斛金蓮，競賞元宵佳節。',59,'全唐诗/poet.song.226000.json','["人間萬斛金蓮，競賞元宵佳節。", "法華徹骨貧窮，鬭勝不如鬭劣。", "室內一盞燈，燦燦心花發。", "不夜光明照古今，見得分明，眼裏重添屑。"]'),
('ae1f8b03-de53-4142-b751-2a49dedbf99b','偈頌一百零二首  其七四','釋紹曇','宋','宋诗','song-poetry','','[]','脚跨馬師門，便有彌天過。',62,'全唐诗/poet.song.226000.json','["脚跨馬師門，便有彌天過。", "喝得耳朶聾，扭得鼻頭破。", "縱大雄老虎略露爪牙，脫百丈野狐不昧因果。", "說條念貫，監本無端，不獨瞞人亦自瞞。"]'),
('1c6b8cd3-e206-42a7-bce4-00caefd77969','偈頌一百零二首  其七五','釋紹曇','宋','宋诗','song-poetry','','[]','凍折枯梅，三兩枝亞。',58,'全唐诗/poet.song.226000.json','["凍折枯梅，三兩枝亞。", "香度野橋，影橫茆舍。", "道人鼻觀相忘，有眼如盲，不被這些留礙。", "可憐鬼窟藏身，喚起來，雪團打，雪團打。"]'),
('69079f6f-9f6f-4884-9bd8-07d8533940a8','偈頌一百零二首  其七六','釋紹曇','宋','宋诗','song-poetry','','[]','拽杖出烟霞，紅塵去路賒。',65,'全唐诗/poet.song.226000.json','["拽杖出烟霞，紅塵去路賒。", "淡金垂柳線，寒玉點梅花。", "觸目分羣象，當機裂萬差。", "豈不見太原孚上座，樓頭吹畫角，喪盡潑生涯。", "活與深深掘窖埋。"]'),
('a4af8be3-5240-4e26-bc9d-d5af9ec60ebe','偈頌一百零二首  其七七','釋紹曇','宋','宋诗','song-poetry','','[]','百鳥啼春風，村村自花柳。',70,'全唐诗/poet.song.226000.json','["百鳥啼春風，村村自花柳。", "揭示目前機，大地人知有。", "隨聲逐色，活陷重圍。", "蓋色騎聲，翻成窠臼。", "牢關擊碎，海岳平沈。", "山鳥自啼花自笑，到頭一點不關心。"]'),
('fd8eeade-7aed-4c22-9591-588faf8de89d','偈頌一百零二首  其七八','釋紹曇','宋','宋诗','song-poetry','','[]','家住雲坳，蓋頭把茆。',75,'全唐诗/poet.song.226000.json','["家住雲坳，蓋頭把茆。", "蓬門無鑰，誰解推敲。", "萬籟聲沈，鳥啼幽谷。", "千林色靜，月掛寒梢。", "風簷索寞人投宿，睡到平明手脚交。", "更問其中端的，床頭木枕子，葛坦半中凹。"]'),
('ff87c5c6-202e-4b9f-8923-941b629fde44','偈頌一百零二首  其七九','釋紹曇','宋','宋诗','song-poetry','','[]','毒窠蜂，惡相從。',69,'全唐诗/poet.song.226000.json','["毒窠蜂，惡相從。", "棒不至心死，喝不到耳聾。", "撥玄樞於機輪轉處，喪家私於小玉聲中。", "怨無窮，恨無窮。", "有口不能分雪得，一年一度，且聽落花啼鳥訴春風。"]'),
('7274eab3-7eb6-405a-b348-77d5ad3343ec','偈頌一百零二首  其八○','釋紹曇','宋','宋诗','song-poetry','','[]','拽轉十二時，不與諸塵對。',86,'全唐诗/poet.song.226000.json','["拽轉十二時，不與諸塵對。", "飽和羅飯，瘦策閑嬉。", "三箇成團，四箇作隊。", "向雲坳磵曲，采蕨蕈煎茶，縷筍芹爲膾。", "彌勒不知，釋迦不會。", "剛被春風透密機，高林破曉鶑吟碎。", "眼裏聞聲，且居門外。"]'),
('cf65e5bf-cabc-48f6-a22e-93beaf6d5322','偈頌一百零二首  其八一','釋紹曇','宋','宋诗','song-poetry','','[]','玩犀牛，呼小玉。',80,'全唐诗/poet.song.226000.json','["玩犀牛，呼小玉。", "一種風標，十分塵俗。", "勤巴子病入膏肓，老鹽官笑含鴆毒。", "花簇簇，錦簇簇，雲峰老人曾刮目。", "我從山水窟中來，自謂一生看不足。", "看不足，眨得眼來，雲歸幽谷。"]'),
('af48a426-f4c8-4682-92c5-b60abcd298a5','偈頌一百零二首  其八二','釋紹曇','宋','宋诗','song-poetry','','[]','路隔重湖，一塵不到。',80,'全唐诗/poet.song.226000.json','["路隔重湖，一塵不到。", "片段白雲，綿蠻幽鳥。", "靜倚石闌聽，穩拂苔衣卧，此樂只應林下有，人間少。", "衲僧家，眼裏著得須彌山，耳裏著得四大海，聲色堆頭，閑行閑坐，全身入荒草。"]'),
('7829911f-ea32-464f-b860-da2cf7954388','偈頌一百零二首  其八三','釋紹曇','宋','宋诗','song-poetry','','[]','水洗硬石頭，浪打枯楊樹。',50,'全唐诗/poet.song.226000.json','["水洗硬石頭，浪打枯楊樹。", "浄智裝嚴功德聚。", "雖然脫體無塵，未是透法身句。", "如何是透法身句，只有湖水無行路。"]'),
('e351a895-8850-4760-88ce-0716f8cf6893','偈頌一百零二首  其八四','釋紹曇','宋','宋诗','song-poetry','','[]','觸翻茶瓢，眉毛掛劍。',36,'全唐诗/poet.song.226000.json','["觸翻茶瓢，眉毛掛劍。", "殺活不分，邪正難辨。", "古今同轍不同途，妙悟玄機轆轆轉。"]'),
('5d9bdbe7-5ca3-4961-8f6e-a98faeebf23a','偈頌一百零二首  其八五','釋紹曇','宋','宋诗','song-poetry','','[]','燕語雕梁，綠陰覆牆。',22,'全唐诗/poet.song.226000.json','["燕語雕梁，綠陰覆牆。", "繰車聲軋軋，風遞繭絲香。"]'),
('73269b78-fe83-40d0-aa31-1710f1abac7d','偈頌一百零二首  其八六','釋紹曇','宋','宋诗','song-poetry','','[]','不擬寒山落韻詩，未傳盧老潑禪衣。',32,'全唐诗/poet.song.226000.json','["不擬寒山落韻詩，未傳盧老潑禪衣。", "脚頭活取通霄路，來透庭前剗草機。"]'),
('56ebcbb4-2a20-4bd6-92f4-03a4422a1d46','偈頌一百零二首  其八七','釋紹曇','宋','宋诗','song-poetry','','[]','枕石安眠，山雲四屯。',50,'全唐诗/poet.song.226000.json','["枕石安眠，山雲四屯。", "救不得也，浣盆浣盆。", "更說甚德山臨際，棒如雨點，喝似雷奔。", "草迷人去路，月掛客愁村。"]'),
('0191071d-3b09-456b-9a6d-79afe08cd1d9','偈頌一百零二首  其八八','釋紹曇','宋','宋诗','song-poetry','','[]','茆屋賦新詩，內院尋知識。',60,'全唐诗/poet.song.226000.json','["茆屋賦新詩，內院尋知識。", "身從勝境中來，句自活法中得。", "非身非句，絕毫絕釐，慈氏少陵安得知。", "法華不敢輕饒舌，只恐山禽語带徼。"]'),
('6c59cdad-a002-459d-9726-d467db36ff63','偈頌一百零二首  其八九','釋紹曇','宋','宋诗','song-poetry','','[]','鴆鳥毛，蠱毒水。',94,'全唐诗/poet.song.226000.json','["鴆鳥毛，蠱毒水。", "毒不傷人，何妨服餌。", "只有這些兒，含毒噴人，深入骨髓。", "三世諸佛畏之如兔見蒼鷹，歷代祖師遠之如龍怖金翅。", "唯有活衲僧，嗜之如鼎味，粉骨碎身猶未已。", "貪他底，著他底。", "佛也如何救得你。"]'),
('409ddcfa-ae2d-4fe2-a45c-a0e9fdfc0366','偈頌一百零二首  其九○','釋紹曇','宋','宋诗','song-poetry','','[]','打頭不遇作家，謾說俱輪先度。',42,'全唐诗/poet.song.226000.json','["打頭不遇作家，謾說俱輪先度。", "饒伊諸漏頓超，到底終成染污。", "不染污，活眼點開，光吞寰宇。"]'),
('31232533-7dc9-48ca-9db3-bfd4be72db34','偈頌一百零二首  其九一','釋紹曇','宋','宋诗','song-poetry','','[]','六用門頭，力戰爭奪，鎗殺賊陣雲橫。',89,'全唐诗/poet.song.226000.json','["六用門頭，力戰爭奪，鎗殺賊陣雲橫。", "群魔竄入藕絲孔，竟挽天河洗甲兵。", "凌烟閣就，汗血功成。", "高枕圓蒲塵夢破，隔窗幽鳥話昇平。", "灼然如是，千聖同盟。", "諸禪德，若也脚跟浮逼逼，畫堂立變鐵圍城。"]'),
('aac7247f-7b65-4fe8-be39-76a459b061e2','偈頌一百零二首  其九二','釋紹曇','宋','宋诗','song-poetry','','[]','久雨不晴，高低水平。',56,'全唐诗/poet.song.226000.json','["久雨不晴，高低水平。", "浸爛釋迦鼻孔，淹鱉迦葉眼睛。", "拄杖子，天造草昧，宜建侯而不寧。", "豁開正眼明如日，掃蕩重昏天宇清。"]'),
('50a17bdf-7e48-4e85-9827-06bc3a341349','偈頌一百零二首  其九三','釋紹曇','宋','宋诗','song-poetry','','[]','住院恰周年，日夜荒忙殺。',76,'全唐诗/poet.song.226000.json','["住院恰周年，日夜荒忙殺。", "園荒手自鉏，屋老身驚壓。", "費盡心神，百醜千拙。", "翻思三条椽下，噇飯噇眠。", "凡聖情空，心行處滅，赤條條地生涯別。", "生涯別，羊頭車子推明月。"]'),
('98338f46-d539-4efd-a53e-55d03ea7f4d1','偈頌一百零二首  其九四','釋紹曇','宋','宋诗','song-poetry','','[]','南宕湖邊，天台山上。',63,'全唐诗/poet.song.226000.json','["南宕湖邊，天台山上。", "踏斷石橋，絕人來往，難透無過者。", "一關望崖，多少空惆悵。", "握不成拳，伸不成掌。", "活語翻成死款招，謾說藕絲牽玉象。"]'),
('752d5130-b76d-4607-a5be-e25b4d21f345','偈頌一百零二首  其九五','釋紹曇','宋','宋诗','song-poetry','','[]','諸莊旱澇不爲憂，只恐難調水牯牛。',58,'全唐诗/poet.song.226000.json','["諸莊旱澇不爲憂，只恐難調水牯牛。", "拽脫鼻繩憨睡穩，數聲羌笛野田秋。", "絕無形影，誰放誰收。", "通身白了通身黑，游戲風煙百草頭。"]'),
('9605e545-28d4-4964-bc22-4ffd9576a79c','偈頌一百零二首  其九六','釋紹曇','宋','宋诗','song-poetry','','[]','三伏炎蒸，汗流如雨。',34,'全唐诗/poet.song.226000.json','["三伏炎蒸，汗流如雨。", "老倒白雲，說迷說悟。", "一莖草上建瓊樓，熟睡饒譫語。"]'),
('97e1b850-f11b-4845-b94f-c4186d0401a3','偈頌一百零二首  其九七','釋紹曇','宋','宋诗','song-poetry','','[]','覿體全彰，曾無覆藏。',90,'全唐诗/poet.song.226000.json','["覿體全彰，曾無覆藏。", "蟬聲集古寺，鳥影度寒塘。", "眼裏無筋，偷觀即瞎，耳中有竅，絕聽何傷。", "堪笑勤川孟八郎，不知諸佛出身處，錯摶量。", "薰風自南來，殿閣生微凉。", "引得傍人鬭熱荒，鵲石何曾解放光。"]'),
('65b28936-88b9-4c32-bbda-ca99d3fba8b6','偈頌一百零二首  其九八','釋紹曇','宋','宋诗','song-poetry','','[]','不守蠟人冰，不憐鵝護雪。',51,'全唐诗/poet.song.226000.json','["不守蠟人冰，不憐鵝護雪。", "互用六根門，大地一團鐵。", "百雜碎了也，妙盡依亡。", "肱枕綠蘿形影絕，獻花百鳥自空忙。"]'),
('7e21b585-43f2-4353-9ec3-b5433d303664','偈頌一百零二首  其九九','釋紹曇','宋','宋诗','song-poetry','','[]','墅里山前，一棚傀儡。',72,'全唐诗/poet.song.226000.json','["墅里山前，一棚傀儡。", "箇東箇西，或進或退。", "打東山皷樂，斷送及時。", "著楊岐戲衫，編排合製。", "雖由行主線牽抽，妙舞三臺誰不會。", "誰不會，喝彩一聲，鴉飛鵲喙。"]'),
('369742d4-fb8c-412f-a306-ba40af76ee1a','偈頌一百零二首  其一○○','釋紹曇','宋','宋诗','song-poetry','','[]','司南車，轆轆轉。',38,'全唐诗/poet.song.226000.json','["司南車，轆轆轉。", "務與冥行指迷，肯被傍人指點。", "三脚馿却步不前，老楊歧惡殽難掩。"]'),
('6562de14-8397-4745-b0bb-a81b9f25f67a','偈頌一百零二首  其一○一','釋紹曇','宋','宋诗','song-poetry','','[]','四十餘年，白雲高卧。',90,'全唐诗/poet.song.226000.json','["四十餘年，白雲高卧。", "無端刺腦膠盆，日夜烹煎家火。", "莊田淹沒，與死爲鄰，屋舍傾頹，安身難保。", "山僧冷地思量，不覺呵呵大笑。", "定業難逃，何妨笑破。", "頼有東村王老知，繞笆籬唱哩哩囉，何似大石調。"]'),
('3ce2b826-c22f-4f3d-85b1-8223bfefd521','偈頌一百零二首  其一○二','釋紹曇','宋','宋诗','song-poetry','','[]','明月可中庭，雁影沉寒水。',54,'全唐诗/poet.song.226000.json','["明月可中庭，雁影沉寒水。", "烹金爐冷歲華深，九鼎遺言猶在耳。", "深深撥著，宿火通紅。", "不假一槌成大器，刈禾鐮子疾如風。"]'),
('fc576275-4fd5-418f-89d0-ffa71ad41156','偈頌一百零二首  其一○三','釋紹曇','宋','宋诗','song-poetry','','[]','秋晚台星照命宮，不亨通事亦亨通。',32,'全唐诗/poet.song.226000.json','["秋晚台星照命宮，不亨通事亦亨通。", "持還趙國連城璧，換我蘿窗一枕風。"]'),
('c88b3864-da63-41ee-9f48-5864b4ec0661','偈頌一百零四首  其一','釋紹曇','宋','宋诗','song-poetry','','[]','殿成不必拆，佛生何用打。',31,'全唐诗/poet.song.226000.json','["殿成不必拆，佛生何用打。", "燒炷兜樓香，共說家私話。", "以力假人者霸。"]'),
('cbaa8bb1-7c0b-4a89-bbb6-8f5f2c093157','偈頌一百零四首  其二','釋紹曇','宋','宋诗','song-poetry','','[]','鴆鳥毛，烏喙藥。',30,'全唐诗/poet.song.226000.json','["鴆鳥毛，烏喙藥。", "毒無醫，休動著。", "輕動著，盡大地人，皮膚脫落。"]'),
('6eb3ab0f-55b8-402b-b265-c34b2e16b685','偈頌一百零四首  其三','釋紹曇','宋','宋诗','song-poetry','','[]','大覺無心，九峰饒舌。',36,'全唐诗/poet.song.226000.json','["大覺無心，九峰饒舌。", "較短量長，家私漏洩。", "引惹平人入禍門，金剛腦後抽生鐵。"]'),
('6453c29b-d7d3-43b5-8002-1b75c338f663','偈頌一百零四首  其四','釋紹曇','宋','宋诗','song-poetry','','[]','丈夫膝下有黄金，爭肯與他人作禮。',26,'全唐诗/poet.song.226000.json','["丈夫膝下有黄金，爭肯與他人作禮。", "須彌燈王，脚頭脚底。"]'),
('daefd481-8478-4d8c-a2eb-31c338a1dedc','偈頌一百零四首  其五','釋紹曇','宋','宋诗','song-poetry','','[]','妙攝化權，使不辱命。',64,'全唐诗/poet.song.226000.json','["妙攝化權，使不辱命。", "鶴唳東臯，雲歸乳嶺。", "拄杖子，黑粼皴，困卧壁根，聲前喚醒。", "舞蹈清風兩腋生，安閑又入蘿窗定。", "賓主歷然，頭正尾正。"]'),
('d66a3a8a-ecdb-4db7-9e3f-2aa2ea2908ef','偈頌一百零四首  其六','釋紹曇','宋','宋诗','song-poetry','','[]','南山燦燦，白石爛爛。',89,'全唐诗/poet.song.226000.json','["南山燦燦，白石爛爛。", "覿當面機，瞎人天眼。", "拄杖子，聞如是語，從定而起，向香積世界，乳竇峰前。", "轉法輪，摶香飯。", "聽之雙耳聾，嗅之舌頭爛。", "何似楊岐栗棘蓬，秦時𨍏轢鑽。", "啞，仁義盡從貧處斷。"]'),
('9214dcff-f901-4021-8298-76d4b8f96604','偈頌一百零四首  其七','釋紹曇','宋','宋诗','song-poetry','','[]','雕梁燕語，喬木鶑吟。',56,'全唐诗/poet.song.226000.json','["雕梁燕語，喬木鶑吟。", "秋田水足，麥嶺雲深。", "聲色純真渾聲色，無端花擘祖師心。", "耳無輪，眼無筋。", "優游子聖外，閬蕩拾花針。"]'),
('4d5b642d-d5e3-4c86-9a6a-71a7ae768cca','偈頌一百零四首  其八','釋紹曇','宋','宋诗','song-poetry','','[]','宿雨初晴，嵐光翠滴。',38,'全唐诗/poet.song.226000.json','["宿雨初晴，嵐光翠滴。", "瀑瀉懸崖，雲籠怪石。", "無位真人，面門出入。", "浄地上不許狼籍。"]'),
('8938764a-6bde-4439-b01e-5ce4441315d4','偈頌一百零四首  其九','釋紹曇','宋','宋诗','song-poetry','','[]','乳竇翠峰，何分彼此。',36,'全唐诗/poet.song.226000.json','["乳竇翠峰，何分彼此。", "遂府糖霜，口甜心苦。", "滅却雲門一字宗，斷崖飛瀑冤難訴。"]'),
('4fb35a3b-a4bc-426d-9541-932d4cba1212','偈頌一百零四首  其一○','釋紹曇','宋','宋诗','song-poetry','','[]','醭醭紅塵，炎炎火聚。',69,'全唐诗/poet.song.226000.json','["醭醭紅塵，炎炎火聚。", "著脚無蹤，翻身有路。", "去時山色慘愁容，歸來幽鳥啼芳樹。", "不涉去來，如何吐露。", "碧眼黄頭總不知，問訊粼皴拄杖子，逢人不得錯舉。"]'),
('0df35d48-053f-413e-902c-45978345ac46','偈頌一百零四首  其一一','釋紹曇','宋','宋诗','song-poetry','','[]','八月秋，何處熱，盡大地，一團鐵。',74,'全唐诗/poet.song.226000.json','["八月秋，何處熱，盡大地，一團鐵。", "衲僧家向南北東西，草鞋跟踏得裂，拄杖頭挑得折。", "驀劄相逢，德山棒，臨濟喝，百怪千妖，如何計結。", "噁，邪法難扶，莫說莫說。"]'),
('1df801bc-0668-49cb-a0c3-a9eb498f81d4','偈頌一百零四首  其一二','釋紹曇','宋','宋诗','song-poetry','','[]','秋氣肅金，秋暘鏖戰。',56,'全唐诗/poet.song.226000.json','["秋氣肅金，秋暘鏖戰。", "林間秋葉片片凋零，砌下秋蟲聲聲凄怨。", "滿眼聽不聞，滿耳覷不見。", "聽得聞，覷得見，聲前句後新羅箭。"]'),
('4ba3dddf-d052-48d7-af41-b15ea92965a9','偈頌一百零四首  其一三','釋紹曇','宋','宋诗','song-poetry','','[]','積癈未蘇，連遭荒旱。',75,'全唐诗/poet.song.226000.json','["積癈未蘇，連遭荒旱。", "鐵作心腸，也須寸斷。", "山僧自小不喜煎熬，幸遇中秋，何妨賞翫。", "皓月流輝，覺天雲散。", "倒跨楊岐三脚馿，深村荒草閑行看。", "光境俱忘，瞎乾坤眼。"]'),
('d4d825f3-8fcf-40f2-aa28-b00e6012dc51','偈頌一百零四首  其一四','釋紹曇','宋','宋诗','song-poetry','','[]','水牯牛，偏捩拗。',87,'全唐诗/poet.song.226000.json','["水牯牛，偏捩拗。", "酷暑雲林，恣情𨁝跳。", "山前祖父田園，忍見離離荒草。", "秋風正要及時耕，脫落鞭繩無鼻竅。", "去住自如，收放在我。", "牧笛聲聲送暮霞，故家深入千峰杳。", "嗚咿嗚咿，莫教忘却來時道。"]'),
('5a99cfef-0a5b-4ef7-beec-4ab4a4fcd292','偈頌一百零四首  其一五','釋紹曇','宋','宋诗','song-poetry','','[]','東籬菊染黄，秋浦茱凝翠。',60,'全唐诗/poet.song.226000.json','["東籬菊染黄，秋浦茱凝翠。", "古佛放光明，助發實相義。", "淵明有眼無筋，錯認白衣人至。", "金風剪剪，玉露團團。", "故人知此意，笑拍玉闌干。"]'),
('2d9b2275-a1ef-4dba-b151-e5906863087a','偈頌一百零四首  其一六','釋紹曇','宋','宋诗','song-poetry','','[]','隰州佛放光，遠射千峰頂。',50,'全唐诗/poet.song.226000.json','["隰州佛放光，遠射千峰頂。", "錦鏡冷交輝，瀑花寒鬭影。", "非虛非實，非色非空。", "舉世無人描邈得，只憑這箇爲流通。"]'),
('9cad358a-17a8-4df5-950b-00cc21d295c4','偈頌一百零四首  其一七','釋紹曇','宋','宋诗','song-poetry','','[]','花禁冷葉紅，草滴虛嵐翠。',24,'全唐诗/poet.song.226000.json','["花禁冷葉紅，草滴虛嵐翠。", "清浄盧舍那，全身荆棘裏。"]'),
('5d28df9a-057d-4b57-917e-6b572d94cfa7','偈頌一百零四首  其一八','釋紹曇','宋','宋诗','song-poetry','','[]','翳眼藥，文武火。',78,'全唐诗/poet.song.226000.json','["翳眼藥，文武火。", "用得親，煨得過。", "翠巖落盡眉毛眼愈明，乳竇爛却皮膚骨將槁。", "家醜分明說向誰，握手松根忘汝我。", "冷地思量，誾誾而笑。", "曾陷迷魂八陣圖，夢中驚入夔門道。"]'),
('42fab717-87c8-4baa-be04-0d2559bb6996','偈頌一百零四首  其一九','釋紹曇','宋','宋诗','song-poetry','','[]','大衆問訊，侍者燒香。',52,'全唐诗/poet.song.226000.json','["大衆問訊，侍者燒香。", "曲录棚上，說黑道黄。", "七世冤憎同劫會，泥犁拔舌自擔當。", "麟鳳出時山總秀，芝闌生處草俱芳。"]'),
('fa00264f-49e4-4d0e-b47e-383a20b9baef','偈頌一百零四首  其二○','釋紹曇','宋','宋诗','song-poetry','','[]','小春纔過，冬至相催。',70,'全唐诗/poet.song.226000.json','["小春纔過，冬至相催。", "光陰駒過隙，鬚鬢雪成堆。", "松根石上，槁木寒灰。", "凍膝擁深霜樹葉，禪心清點野橋梅。", "喚起來打，更莫遲回。", "蟄龍須奮躍，何待禹門雷。"]'),
('eb27a182-345c-41f8-8c27-3a16658c97c0','偈頌一百零四首  其二一','釋紹曇','宋','宋诗','song-poetry','','[]','乾非上，坤非下。',56,'全唐诗/poet.song.226000.json','["乾非上，坤非下。", "一畫先天，包含八卦。", "推窮爻象，凶吉不分，說盡繫辭，疑難未解。", "吉凶分，疑難解。", "阿魏無真，水銀無假。"]'),
('f66fba3c-7d9a-438c-a1a4-b038f02b6eea','偈頌一百零四首  其二二','釋紹曇','宋','宋诗','song-poetry','','[]','統御金輪四十年，拱垂衣化育黎元。',58,'全唐诗/poet.song.226000.json','["統御金輪四十年，拱垂衣化育黎元。", "萬機休罷昇遐去，四海無思不斷魂。", "林間衲子，感戴深恩。", "合掌迎歸兜率院，當來成佛補慈尊。"]'),
('e7180007-1268-4298-b73e-4d16bfc9f12d','偈頌一百零四首  其二三','釋紹曇','宋','宋诗','song-poetry','','[]','三度拂蒿枝，秦時𨍏轢鑽。',73,'全唐诗/poet.song.226000.json','["三度拂蒿枝，秦時𨍏轢鑽。", "拶得火星飛，結得弓弦斷。", "用盡自己心，瞎却他人眼。", "千里玄樞錯踏翻，神駒十影無羈絆。", "業風吹上乳竇峰前，點一杯茶向伊道，且緩緩。"]'),
('dedbcda4-f669-432d-a58b-83e5c96cd013','偈頌一百零四首  其二四','釋紹曇','宋','宋诗','song-poetry','','[]','天巧剪瑶花，六出繽紛落。',57,'全唐诗/poet.song.226000.json','["天巧剪瑶花，六出繽紛落。", "二祖立腰酸，楊岐嗟項縮。", "爭似火爐頭柮榾高燒，紙衾包却暖烘烘。", "憨睡著，不墮凝寒一色邊，錯錯。"]'),
('287b615f-c18b-46b0-80f3-b3e68e4c0e8f','偈頌一百零四首  其二五','釋紹曇','宋','宋诗','song-poetry','','[]','復見天地心，舉世皆知有。',80,'全唐诗/poet.song.226000.json','["復見天地心，舉世皆知有。", "山意衝寒欲放梅，岸容待臘將舒柳。", "惟有拄杖子，黑粼皴，元依舊。", "受霜凍不枯，遇陽和不秀。", "壁角落頭，塊然拙守。", "終日談玄口不開，噴嚏也成獅子吼。"]'),
('a4066f05-c9db-4396-b9b6-cc65fde55a85','偈頌一百零四首  其二六','釋紹曇','宋','宋诗','song-poetry','','[]','大慈苕菷生，倒拈風颯颯。',109,'全唐诗/poet.song.226000.json','["大慈苕菷生，倒拈風颯颯。", "掃盡大地塵，趙州驚吐舌。", "驀劄相逢玉乳峰，殷勤爲掃寒巖雪。", "拄杖子，愛客情深，把火助熱。", "卓破苔錢畫斷雲，放出寒梅南枝北枝，一花兩花三四花。", "疏影橫溪，暗香浮月，無端盡把春容泄。", "清不徹惱碎心，廣平似鐵。"]'),
('d67e39c1-c6cb-4cf0-9490-2825a0b71bc5','偈頌一百零四首  其二七','釋紹曇','宋','宋诗','song-poetry','','[]','道至無難，惟嫌揀擇。',80,'全唐诗/poet.song.226000.json','["道至無難，惟嫌揀擇。", "混俗通真，騎聲蓋色。", "近在口皮邊，遠過河沙國。", "慈明揭示，借鬼畫桃符。", "雪竇標題，去猊懸白澤。", "一見便見，迅雷陶壁奮飛梭。", "擬議尋思，逆浪禹門遭點額。"]'),
('2340d138-2765-4dde-86da-15247cc87f8e','偈頌一百零四首  其二八','釋紹曇','宋','宋诗','song-poetry','','[]','道無可成，法無可說。',90,'全唐诗/poet.song.226000.json','["道無可成，法無可說。", "黄面瞿曇，重重敗缺。", "家醜豈容外泄，剛被兒孫告訐。", "圖形畫影與人看，乳竇門風添暖熱。", "彷彷彿彿，一似閬州城南錦屏山，子細看來，却是鹿苑啣花，竺峰積雪。", "添得時人眼中屑。"]'),
('30840ec4-088f-4e0b-bd90-d4a311e28489','偈頌一百零四首  其二九','釋紹曇','宋','宋诗','song-poetry','','[]','柳條弓，蒿枝箭，射中虛空成兩片。',46,'全唐诗/poet.song.226000.json','["柳條弓，蒿枝箭，射中虛空成兩片。", "狸奴白牯，雷厲風行。", "碧眼黄頭，星飛電卷，擬搆珠林嚙鏃機。", "險。"]'),
('d5ffc0cb-8ca7-496c-97ba-fc07fa5a821d','偈頌一百零四首  其三○','釋紹曇','宋','宋诗','song-poetry','','[]','咸淳更號，立見昇平。',76,'全唐诗/poet.song.226000.json','["咸淳更號，立見昇平。", "兩朝聖化，四海歡聲。", "乳竇家貧開宴，用度非輕。", "錦雲山瀑帽，珠雪瀑懸纓。", "步步寒花翠結，關關幽鳥琴清。", "排當不知因底事，大衆萬福，慶賀元正。"]'),
('a374611e-2853-4a7b-871c-37c7c20e96a3','偈頌一百零四首  其三一','釋紹曇','宋','宋诗','song-poetry','','[]','寂寞萬峰頭，佳節成虛度。',70,'全唐诗/poet.song.226000.json','["寂寞萬峰頭，佳節成虛度。", "貧無一盞燈，好有多般事。", "洞山薑索價太穹，無縫塔入門辨主。", "厠籌子動地放光，利市官招財滿庫。", "不作佛法商量，亦非世諦流布。"]'),
('205ac925-a8da-49c6-812a-bbb87825a2de','偈頌一百零四首  其三二','釋紹曇','宋','宋诗','song-poetry','','[]','半夜客船鍾，漁火愁眠省。',50,'全唐诗/poet.song.226000.json','["半夜客船鍾，漁火愁眠省。", "不見老寒山，淚濕吳雲冷。", "幽鳥啼霜月影斜，野橋楓葉翻紅錦。", "擊碎重關，枯山未泯。"]'),
('1fbc9988-5077-430a-ba67-2d56b0067db2','偈頌一百零四首  其三三','釋紹曇','宋','宋诗','song-poetry','','[]','春山青，春水綠，鳥弄笙簧，梅飄香玉。',60,'全唐诗/poet.song.226000.json','["春山青，春水綠，鳥弄笙簧，梅飄香玉。", "具足清白梵行之相，聲色純真豈容攢簇。", "聽不足，觀不足，一會靈山儼未分，斷絃須是鸞膠續。"]'),
('2b889060-519c-4606-beaf-229079913b8d','偈頌一百零四首  其三四','釋紹曇','宋','宋诗','song-poetry','','[]','坐斷白雲，萬機寢息。',52,'全唐诗/poet.song.226000.json','["坐斷白雲，萬機寢息。", "黄葉止啼，總不消得。", "閑倚危闌看瀑花，縱乾坤眼清無極。", "清無極，自謂太平僧，豈知堯舜力。"]'),
('7b6c9432-d9a7-4567-a017-f504002c1bed','偈頌一百零四首  其三五','釋紹曇','宋','宋诗','song-poetry','','[]','達磨眼睛，天台骨髓。',40,'全唐诗/poet.song.226000.json','["達磨眼睛，天台骨髓。", "鈎鎖連環，提掇不起。", "提得起，湖頭春水綠成紋，竹外清風來未已。"]'),
('8909abe8-3cf4-4782-b42c-e29ea888526c','偈頌一百零四首  其三六','釋紹曇','宋','宋诗','song-poetry','','[]','天高地厚，水闊山遥。',76,'全唐诗/poet.song.226000.json','["天高地厚，水闊山遥。", "古今常理，何用忉忉。", "衲僧家，脚跟下一段光明，十日並照，明察秋毫。", "不揀侯門射策，何須華頂降魔。", "孤迥迥，冷蕭蕭，無端翻黑月，魑魅哭連宵。"]'),
('9c593a3a-d18b-4abb-8c26-6c06ad553ea6','偈頌一百零四首  其三七','釋紹曇','宋','宋诗','song-poetry','','[]','二月十五，瞿曇滅度。',87,'全唐诗/poet.song.226000.json','["二月十五，瞿曇滅度。", "足示雙趺，胸摩卍字。", "山愁慘莫雲，花淚啼紅雨。", "去年一次，今年一次，明年一次。", "輒莫明年更明年百千年，年年一次。", "狼籍涅槃心，此恨憑誰訴。", "頼有粼皴拄杖子，牢記取。"]'),
('ebf7648c-4248-474f-98bd-e1f8e18528cf','偈頌一百零四首  其三八','釋紹曇','宋','宋诗','song-poetry','','[]','天地不仁，以萬物爲芻狗。',87,'全唐诗/poet.song.226000.json','["天地不仁，以萬物爲芻狗。", "聖人不仁，以百姓爲芻狗。", "拄杖子不仁，以三世諸佛歷代祖師四聖六凡爲芻狗。", "化育春陽煦嫗前，摧殘霜雪憑陵後。", "截鶴續鳬，折衡剖斗。", "力盡神疲困壁根，笑破他人口。"]'),
('0603405d-4e7e-4368-9180-34f94cfa6c44','偈頌一百零四首  其三九','釋紹曇','宋','宋诗','song-poetry','','[]','春日晴，春雨足，玉龍怒噴懸崖瀑。',66,'全唐诗/poet.song.226000.json','["春日晴，春雨足，玉龍怒噴懸崖瀑。", "花簇簇，錦簇簇，滿山桃李嫌粗俗。", "休捏目，直饒伊向聲色堆頭。", "密透重塵，坐卧經行，了無拘束。", "砒霜未是毒。"]'),
('c0f20a18-dfc8-481d-a66e-5ea6a3ca70d9','偈頌一百零四首  其四○','釋紹曇','宋','宋诗','song-poetry','','[]','關雎頌德，樛木垂陰。',38,'全唐诗/poet.song.226000.json','["關雎頌德，樛木垂陰。", "八荒開壽域，萬國奉君心。", "亙古今爲諸佛母，曇花時現覺園春。"]'),
('2af66d83-a49f-4fe6-a4f3-f38a89e8b930','偈頌一百零四首  其四一','釋紹曇','宋','宋诗','song-poetry','','[]','黄河清，聖人生。',34,'全唐诗/poet.song.226000.json','["黄河清，聖人生。", "體天行健，濬哲文明。", "率土更新堯舜化，八荒無地著歡聲。"]'),
('aad4e83b-b247-4a79-a284-17b7ed47cf7d','偈頌一百零四首  其四二','釋紹曇','宋','宋诗','song-poetry','','[]','錦鏡濃粧十樣花，練拖寒瀑掛蒼崖。',58,'全唐诗/poet.song.226000.json','["錦鏡濃粧十樣花，練拖寒瀑掛蒼崖。", "無賓主句全機露，見得分明眼著砂。", "依亡妙盡，猶隔天涯。", "奪取黄梅無底鉢，且教盧老去擔柴。"]'),
('159ed5c4-ddb2-4709-9586-8a0c1005ea55','偈頌一百零四首  其四三','釋紹曇','宋','宋诗','song-poetry','','[]','父豩頑，子惡毒。',56,'全唐诗/poet.song.226000.json','["父豩頑，子惡毒。", "熱血相噴，嗔拳相𡎺。", "如風吹水自成紋，醫得耳聾成瞎禿。", "冷地思量，笑不成哭。", "乳峰將底報深冤，捩鼻木。"]'),
('e22dd36d-c99c-4244-9dc8-77b9d40929af','偈頌一百零四首  其四四','釋紹曇','宋','宋诗','song-poetry','','[]','活馬騮，百十箇。',98,'全唐诗/poet.song.226000.json','["活馬騮，百十箇。", "乳竇峰前，追風跳竈。", "楊岐三脚馿，盡力跂步不前；江西千里駒，奮鬣追蹤不到。", "更饒伊象頭檀特，九十六種，見鞭影而行，蹶蹄不少。", "未奏沙場汗血功，便思嚼嚙天閑草。", "好則甚好，明覺老人笑須絕倒。"]'),
('4a287cd7-1560-476d-bad8-33e95ccf749f','偈頌一百零四首  其四五','釋紹曇','宋','宋诗','song-poetry','','[]','綠暗紅稀，人家翠微。',88,'全唐诗/poet.song.226000.json','["綠暗紅稀，人家翠微。", "杜鵑啼月，紫燕銜泥。", "莫春者，浴乎沂，風乎舞雩，詠而歸。", "本是儒家閑戲劇，剛言漏泄祖師機。", "是不是，非不非，老倒乳峰那得知。", "松根憨睡足，閑把瘦藤戲，侍者無事相隨。"]'),
('73252e98-ee95-4cdc-bdfa-c38286e53969','偈頌一百零四首  其四六','釋紹曇','宋','宋诗','song-poetry','','[]','萬本青松，後人標榜。',73,'全唐诗/poet.song.226000.json','["萬本青松，後人標榜。", "臨濟兒孫，當機不讓。", "千古清凉樹蔭人，法門梁棟真堪賞。", "初莫學黄梅道者，貪傳破鉢盂，連累周家女。", "無地著渾身空惆悵，叢林難免無根謗。"]'),
('20cb516e-9d58-4144-a3f6-8168da7a2a1a','偈頌一百零四首  其四七','釋紹曇','宋','宋诗','song-poetry','','[]','仙苑蟠桃不老春，三千年實薦芳新。',58,'全唐诗/poet.song.226000.json','["仙苑蟠桃不老春，三千年實薦芳新。", "錫開王母瑶池宴，滿簇金盤壽聖人。", "雖云絕品，未足爲珍。", "幸有菩提真妙果，年年同獻佛生辰。"]'),
('eba9a9d1-955f-451b-947e-124f13f8b0b4','偈頌一百零四首  其四八','釋紹曇','宋','宋诗','song-poetry','','[]','無憂樹下風如箭，九龍吐出水含毒。',86,'全唐诗/poet.song.226000.json','["無憂樹下風如箭，九龍吐出水含毒。", "涓滴沾身痛入心。", "霎時吹面刀剜肉。", "不知悉達爲何因，纔出母胎罹此酷。", "後代兒孫忍見渠，一年一度香湯浴。", "我今灌沐諸如來，浄智莊嚴功德聚，只恐不是玉。"]'),
('4dce7ed5-8d87-429b-9add-fe17166224f9','偈頌一百零四首  其四九','釋紹曇','宋','宋诗','song-poetry','','[]','聞道金輪出母胎，盡河沙界掃氛埃。',58,'全唐诗/poet.song.226000.json','["聞道金輪出母胎，盡河沙界掃氛埃。", "想應新整乾坤手，多带堯風舜日來。", "普天率土，壽域宏開。", "林下野人何祝獻，一莖草上玉樓臺。"]'),
('9db8890d-a5c0-448a-8838-1f47247e9567','偈頌一百零四首  其五○','釋紹曇','宋','宋诗','song-poetry','','[]','百二十日夏，今朝始發頭。',48,'全唐诗/poet.song.226000.json','["百二十日夏，今朝始發頭。", "飯抄雲子白，羹煮菜香浮。", "未問寒山子，先看水牯牛。", "山前千頃地，信脚踏翻休。"]'),
('42c78b6a-b921-4158-a540-120ba468cb95','偈頌一百零四首  其五一','釋紹曇','宋','宋诗','song-poetry','','[]','一口吸西江，赤土塗牛奶。',75,'全唐诗/poet.song.226000.json','["一口吸西江，赤土塗牛奶。", "蕩盡聖凡情，猶欠這一解。", "丹霞馬祖，眼見如盲，靈照龐婆，口說如啞。", "驀劄相逢露一機，驚翻巖瀑蒼龍掛。", "雖然斫額望鄉關，前頭大有路在。"]'),
('3304502d-5a5e-4662-b34a-adf6c2ef1077','偈頌一百零四首  其五二','釋紹曇','宋','宋诗','song-poetry','','[]','玉版阿師，錦綳稚子。',54,'全唐诗/poet.song.226000.json','["玉版阿師，錦綳稚子。", "穎脫叢林，頭角呈露。", "參透油煎石磉盤，飽經鰲煉翻身去。", "塞斷咽喉，更須吞吐。", "毗耶未識香來處。"]'),
('ad6367d5-84d8-407e-976d-a0267f60663e','偈頌一百零四首  其五三','釋紹曇','宋','宋诗','song-poetry','','[]','籜包角黍，茶點菖蒲。',48,'全唐诗/poet.song.226000.json','["籜包角黍，茶點菖蒲。", "香浮毛孔，清透肌膚。", "肱枕藜床心醉月，驅邪何用掛神符。", "汨羅人去遠，還有獨醒無。"]'),
('b84555ef-e1ee-45d0-8a12-0f04e79ede31','偈頌一百零四首  其五四','釋紹曇','宋','宋诗','song-poetry','','[]','雲收麥壟，水足秋田。',48,'全唐诗/poet.song.226000.json','["雲收麥壟，水足秋田。", "繭繰白雪，鶑弄朱絃。", "無象太平還有象，蕢桴土皷樂堯年。", "誰知聲色裏，心印是渠傳。"]'),
('f1332d5f-1b15-4f46-92df-82099cadd665','偈頌一百零四首  其五五','釋紹曇','宋','宋诗','song-poetry','','[]','活衲僧，生鐵鑄。',84,'全唐诗/poet.song.226000.json','["活衲僧，生鐵鑄。", "吐出鐵心肝，掛起鐵面具。", "蚊子上鐵牛，無你啗啄處。", "素紈摇月，碧帳含烟。", "或放或收皆在我，長伸兩脚放憨眠。", "灼然如是，天地相懸。", "開眼不知天大曉，閻家催索水漿錢。"]'),
('e7a7b0f3-ec92-4cd2-bb77-94e3904b8468','偈頌一百零四首  其五六','釋紹曇','宋','宋诗','song-poetry','','[]','一湖橫陳，七峰環遶。',69,'全唐诗/poet.song.226000.json','["一湖橫陳，七峰環遶。", "妙轉玄樞，死生關破。", "去何有偈，流水渡百灘，來本無言，疾風號萬竅。", "更問如何與若何，珍重便行。", "髑髏前失照，斷猿哭月千林曉。"]'),
('288198f4-dbff-4f33-addc-5e4e9f688949','偈頌一百零四首  其五七','釋紹曇','宋','宋诗','song-poetry','','[]','薄福住山，百無所取。',32,'全唐诗/poet.song.226000.json','["薄福住山，百無所取。", "何以表勤，惟誠爲主。", "祈晴便得晴，祈雨便得雨。"]'),
('a7bb3548-869b-4768-ae8d-18285e158c27','偈頌一百零四首  其五八','釋紹曇','宋','宋诗','song-poetry','','[]','乳竇相從幾弟兄，忘形骸外又忘情。',58,'全唐诗/poet.song.226000.json','["乳竇相從幾弟兄，忘形骸外又忘情。", "炊香好甑和籮飯，鼠糞無端污却羹。", "隣僧扣齒，訴不平聲。", "折筯何妨挑剔去，壁根不到礙人行。"]'),
('2d83c3c0-66e2-41c8-9aaf-7f91b2275f33','偈頌一百零四首  其五九','釋紹曇','宋','宋诗','song-poetry','','[]','虛空包不包，大地壞不壞。',40,'全唐诗/poet.song.226000.json','["虛空包不包，大地壞不壞。", "行脚不遇人，出語無頼聊。", "謾言密室不通風，濕紙如何裹大蟲。"]'),
('001b1c87-1e7f-4f2c-a273-0273164c9c95','偈頌一百零四首  其六○','釋紹曇','宋','宋诗','song-poetry','','[]','巴南巴西，水流巴字。',80,'全唐诗/poet.song.226000.json','["巴南巴西，水流巴字。", "古篆分明，心畫顯著。", "游泳江湖四十年，與世同波無彼此。", "朅來千丈岩前路，截流機透險崖句，辨龍蛇眼明今古。", "何侶老趙州，略彴橋頭，滴水丈波。", "喫茶去。"]'),
('98c5feba-db5e-4e9a-a5c9-0e0f78961a2d','偈頌一百零四首  其六一','釋紹曇','宋','宋诗','song-poetry','','[]','社燕催歸，賓鴻欲返。',22,'全唐诗/poet.song.226000.json','["社燕催歸，賓鴻欲返。", "雪點白蘋洲，錦鋪紅蓼岸。"]'),
('0c979675-3906-486a-8c3c-27de276aef73','偈頌一百零四首  其六二','釋紹曇','宋','宋诗','song-poetry','','[]','靈山話月，曹溪指月。',64,'全唐诗/poet.song.226000.json','["靈山話月，曹溪指月。", "玉乳峰前，相呼看月。", "縱饒光透十虛，未免成第二月。", "諸人要見真月麽，非暗非明，非圓非缺。", "無物堪比倫，教我如何說。"]'),
('c4e7e92e-c741-4538-982b-70bc613ad219','偈頌一百零四首  其六三','釋紹曇','宋','宋诗','song-poetry','','[]','目前機，真實相。',78,'全唐诗/poet.song.226000.json','["目前機，真實相。", "張都料輪材底輪材，李作頭𡎺磉底𡎺磉。", "動靜奚分兩處看，太平基業初無象。", "迥出常情，與誰共賞。", "佳客歡呼自往來，瑞巖拍掌仙巖唱。", "潦倒龐公，精神迭宕。"]'),
('c4d8596d-5b55-4796-b0b9-2c664763574d','偈頌一百零四首  其六四','釋紹曇','宋','宋诗','song-poetry','','[]','共住孤峰頂，霜牙咬菜根。',48,'全唐诗/poet.song.226000.json','["共住孤峰頂，霜牙咬菜根。", "一身塵不染，千古道長存。", "石竹閑眠鹿，巖松冷掛猿。", "我行荒草裏，汝又入荒村。"]'),
('503bed80-d999-4119-a0c6-7d270f127db6','偈頌一百零四首  其六五','釋紹曇','宋','宋诗','song-poetry','','[]','一二千碩穀，四五百籮粟。',71,'全唐诗/poet.song.226000.json','["一二千碩穀，四五百籮粟。", "䆉稏熟天風，高低布雲麓。", "辛勤收拾歸來，碓擣明璣，鉢盛香玉。", "無位真人手捫腹，口唱無生曲。", "花簇簇，聽不足，欵乃一聲山水綠。"]'),
('4b333f8d-c436-4628-a3d8-77729c772f80','偈頌一百零四首  其六六','釋紹曇','宋','宋诗','song-poetry','','[]','乳竇家私，寸無可取。',94,'全唐诗/poet.song.226000.json','["乳竇家私，寸無可取。", "分明徹骨貧，剛道薰天富。", "綱宗委地，力要匡扶。", "大厦傾頹，直須撐拄。", "不學老楊岐，破屋雪真珠，縮項暗嗟吁。", "不學大愚芝，脫粟淡黄虀，不喫從君去。", "千聖頭邊露一機，靈蹤不在猨啼處。"]'),
('eebc7dd0-f7a3-4042-adfa-b8e66d687bb5','偈頌一百零四首  其六七','釋紹曇','宋','宋诗','song-poetry','','[]','合水和泥，打成一片。',72,'全唐诗/poet.song.226000.json','["合水和泥，打成一片。", "脫却胚腪，重加煅煉。", "滲漏全無蓋覆人，平地昇高乘快便。", "若非衆手出力扶持，心印蒙塵，光難發現。", "美則美矣，只如古人道，明堂瓦插簷。"]'),
('6482cdf0-49fd-4ee2-95a0-2b38eb316fab','偈頌一百零四首  其六八','釋紹曇','宋','宋诗','song-poetry','','[]','趁晴蓋却屋，捉空種了麥。',48,'全唐诗/poet.song.226000.json','["趁晴蓋却屋，捉空種了麥。", "安身立命既無憂，只須體究庭前柏。", "堅守歲寒，青無變色。", "喚作西來直指宗，瞎。"]'),
('50916543-7531-4747-9e95-a2291dedf28a','偈頌一百零四首  其六九','釋紹曇','宋','宋诗','song-poetry','','[]','月下扣朱門，不會推敲句。',71,'全唐诗/poet.song.226000.json','["月下扣朱門，不會推敲句。", "滿面是埃塵，低頭陪笑語。", "不重己靈，諸聖不慕。", "拍盲入草尋人去，歸來羞對白雲，倦倚寒巖枯樹。", "笑倒粼皴拄杖子，逢人但恁麽舉。"]'),
('2f56d5fb-a2a9-4e8d-980e-caa8bc7b609e','偈頌一百零四首  其七○','釋紹曇','宋','宋诗','song-poetry','','[]','鳳輦昇遐恰一周，思君心切淚交流。',32,'全唐诗/poet.song.226000.json','["鳳輦昇遐恰一周，思君心切淚交流。", "攀龍無路空摧哽，凝望蒼梧幾許愁。"]'),
('e61fea0d-d37f-4d7b-a36a-c3eddd714463','偈頌一百零四首  其七一','釋紹曇','宋','宋诗','song-poetry','','[]','統御金輪四十春，篤行舜德與堯仁。',32,'全唐诗/poet.song.226000.json','["統御金輪四十春，篤行舜德與堯仁。", "莫言過去無蹤蹤，盧舍時時現本身。"]'),
('06ce20cd-aa91-4b2b-ac37-83fd4cf077f4','偈頌一百零四首  其七二','釋紹曇','宋','宋诗','song-poetry','','[]','吳江風急浪翻空，聲擊楓林半夜鐘。',58,'全唐诗/poet.song.226000.json','["吳江風急浪翻空，聲擊楓林半夜鐘。", "驚起客船塵夢破，踏翻大地去無蹤。", "寒山撫掌，龐老槌胸。", "少室門庭空寂寂，凝寒古路綠苔封。"]'),
('1c254cc9-e8a4-432a-a286-3e6e1a6f94af','偈頌一百零四首  其七三','釋紹曇','宋','宋诗','song-poetry','','[]','史筆書雲，綉閨添線。',84,'全唐诗/poet.song.226000.json','["史筆書雲，綉閨添線。", "愛日舒長，豐年取驗。", "衲僧不被四時遷，妙應圓機轆轆轉。", "喝散嶺上白雲，掣斷脚跟紅線，陰極陽生總不知。", "曝背晴簷，手摘寒梅。", "一點兩點三四點，拈花微笑今重見。"]'),
('9c018bba-715f-43e6-a873-d7dbe2fc4d50','偈頌一百零四首  其七四','釋紹曇','宋','宋诗','song-poetry','','[]','如來禪，祖師意，落葉錦翻空，亂山雲積翠。',54,'全唐诗/poet.song.226000.json','["如來禪，祖師意，落葉錦翻空，亂山雲積翠。", "見得分明隔萬層，道得完全失千里。", "非不非，是不是。", "達磨大師，無當門齒。"]'),
('b36acabb-d896-43fa-9d34-cfd1499dd96c','偈頌一百零四首  其七五','釋紹曇','宋','宋诗','song-poetry','','[]','鐵團欒，無縫罅。',67,'全唐诗/poet.song.226000.json','["鐵團欒，無縫罅。", "上下三指，彼此七馬。", "德山臨濟，眼見如盲，雲門趙州，口說如啞。", "拄杖子，忍俊不禁，等閑捉敗。", "休休，盡法恐無民，且放天寒赦。"]'),
('daaf9d2b-54d8-43db-a51e-1e6afb81ea0b','偈頌一百零四首  其七六','釋紹曇','宋','宋诗','song-poetry','','[]','庾嶺春歸，溪梅早知。',70,'全唐诗/poet.song.226000.json','["庾嶺春歸，溪梅早知。", "雪破寒英，一點半點，月橫疏影，三枝兩枝。", "未放高樓吹笛，且聽茆舍吟詩。", "十分瀟灑，一段清奇。", "將謂黄梅消息絕，暗香猶有好風吹。"]'),
('e3405bb0-a61c-42de-9bf3-1f4794e36449','偈頌一百零四首  其七七','釋紹曇','宋','宋诗','song-poetry','','[]','靈江月，中巖月。',47,'全唐诗/poet.song.226000.json','["靈江月，中巖月。", "交影松蘿，斷猿啼切。", "聲色純真見一邊，騎聲蓋色天然別。", "別別，明覺掀眉，長庚吐舌。"]'),
('6e2ff0fb-5d6f-40c7-b6ed-cfd544f3962e','偈頌一百零四首  其七八','釋紹曇','宋','宋诗','song-poetry','','[]','迅瀑千尋，懸崖萬仞。',65,'全唐诗/poet.song.226000.json','["迅瀑千尋，懸崖萬仞。", "說法聲高，驗人機峻。", "要扶法眼門風，花衲元非古錦。", "堪笑高麗四九僧，面門搭了冬瓜印。", "乳竇謗沉無香，是可忍孰不可忍。"]'),
('78abb658-6763-4630-9199-fc7533c5fa02','偈頌一百零四首  其七九','釋紹曇','宋','宋诗','song-poetry','','[]','圖畫天開，春風剪裁。',36,'全唐诗/poet.song.226000.json','["圖畫天開，春風剪裁。", "爛銀庭院，白玉樓臺。", "將謂乳峰貧徹骨，敵君王富自何來。"]'),
('d680d2a9-6086-4582-95b0-52fc5256885a','偈頌一百零四首  其八○','釋紹曇','宋','宋诗','song-poetry','','[]','松頂雪簪花，山頭雲裹帽。',50,'全唐诗/poet.song.226000.json','["松頂雪簪花，山頭雲裹帽。", "呼喚賀元正，粲發溪聲笑。", "一不成單，二無兩箇。", "漏洩元元化母機，春風未必能包裹。"]'),
('ac4a2e74-9ad0-484f-a189-bcbe31998aa1','偈頌一百零四首  其八一','釋紹曇','宋','宋诗','song-poetry','','[]','昨夜唧蟟吞跛鱉，天明屙出一團鐵。',72,'全唐诗/poet.song.226000.json','["昨夜唧蟟吞跛鱉，天明屙出一團鐵。", "平地翻身觸險崖，擘破崑崙成八橛。", "捻土爲香供養伊，細問因由不肯說。", "不肯說，太饒舌。", "莫管他人屋上霜，自家掃取門前雪。"]'),
('414978bc-3ea1-4da9-9d24-cc4995914a1c','偈頌一百零四首  其八二','釋紹曇','宋','宋诗','song-poetry','','[]','道教灰飛，佛燈花燦。',65,'全唐诗/poet.song.226000.json','["道教灰飛，佛燈花燦。", "大地歡悰，笙歌賞玩。", "拄杖子，按下雲頭，得失是非，渾然不管。", "一點光明耀十虛，古今閲幾平人眼。", "因甚如此，司空見慣。"]'),
('95a7240a-dcb3-4786-9269-a3ff6715b484','偈頌一百零四首  其八三','釋紹曇','宋','宋诗','song-poetry','','[]','未有清規，人能弘道。',48,'全唐诗/poet.song.226000.json','["未有清規，人能弘道。", "纔涉典章，翻成機巧。", "華屋春風錦綉圍，草廬不見人高卧。", "啞，刻糞爲香，是誰之過。"]'),
('a07f946f-3423-402c-8926-67b2a3f0c673','偈頌一百零四首  其八四','釋紹曇','宋','宋诗','song-poetry','','[]','飄蓬四十餘年，夢遶晶然山路。',56,'全唐诗/poet.song.226000.json','["飄蓬四十餘年，夢遶晶然山路。", "才見廣安軍人，便憶破庵師祖。", "摵破碎沙盆，打動蝦蟆皷。", "驚落蛟龍虎兕威，知音不在頻頻舉。"]'),
('29a4932f-7a38-4b33-ba19-664e2d1935e4','偈頌一百零四首  其八五','釋紹曇','宋','宋诗','song-poetry','','[]','光明幢，如來藏。',57,'全唐诗/poet.song.226000.json','["光明幢，如來藏。", "八面玲瓏，十方通暢。", "拭佛祖大病之瘡疣，見鬼神幽愁之情狀。", "擡你爺，擡你娘，擡上方丈，洞山寧免無根謗。"]'),
('2e2d0c9c-35b9-4ef2-99a0-1c2ae4b8d525','偈頌一百零四首  其八六','釋紹曇','宋','宋诗','song-poetry','','[]','瞿曇醜惡，臨死猶多。',50,'全唐诗/poet.song.226000.json','["瞿曇醜惡，臨死猶多。", "足下輪輻顯露，胸前卍字揩磨。", "抱橋澡洗，寄帽投河。", "舉世無人援手得，竟隨殘夢入無何。"]'),
('53f860aa-2e2f-4c30-a058-bc27b7399ce9','偈頌一百零四首  其八七','釋紹曇','宋','宋诗','song-poetry','','[]','庭院春深，和風翠陰。',36,'全唐诗/poet.song.226000.json','["庭院春深，和風翠陰。", "桃花簇錦，柳線摇金。", "無眼靈雲徒說悟，一生埋沒祖師心。"]'),
('4e07297a-eaf5-404b-9235-5be9ad18112f','偈頌一百零四首  其八八','釋紹曇','宋','宋诗','song-poetry','','[]','焚香書寫佛名經，窗外幽禽報喜聲。',32,'全唐诗/poet.song.226000.json','["焚香書寫佛名經，窗外幽禽報喜聲。", "次補數中添一位，大唐國裏聖人生。"]'),
('128b7196-089e-460b-837c-56a42a087c5b','偈頌一百零四首  其八九','釋紹曇','宋','宋诗','song-poetry','','[]','鑿透耳聾，板夾背傴。',46,'全唐诗/poet.song.226000.json','["鑿透耳聾，板夾背傴。", "只要醫行，不管人苦。", "拄杖子，不別時宜，强行直路。", "大地羊腸遶棘林。", "何處去。"]'),
('a8294949-6f5b-42b0-9f91-2b24a8f2f9f0','偈頌一百零四首  其九○','釋紹曇','宋','宋诗','song-poetry','','[]','落頼門風，大家撐拄。',93,'全唐诗/poet.song.226000.json','["落頼門風，大家撐拄。", "量田底量田，種樹底種樹。", "带雨扶犁綠野耕，和雲荷钁千峰去。", "有甚心情，管得南泉貓兒，趙州狗子，勘證平田婆，連累周家女。", "棘林中有通天路，飽飯狂歌，閒行幾步，脚頭山色無重數。"]'),
('ecf39d40-c7a8-42ea-821e-00c4dfae6b8e','偈頌一百零四首  其九一','釋紹曇','宋','宋诗','song-poetry','','[]','金輪王宅，惡業無多。',36,'全唐诗/poet.song.226000.json','["金輪王宅，惡業無多。", "不知何事，生此妖魔。", "打與狗噇頑不殺，好將惡水劈頭澆。"]'),
('f9c9edea-0263-40b1-bf56-1273aa74d050','偈頌一百零四首  其九二','釋紹曇','宋','宋诗','song-poetry','','[]','布關雎化襲宮闈，萬國人趨奉母儀。',32,'全唐诗/poet.song.226000.json','["布關雎化襲宮闈，萬國人趨奉母儀。", "壽結蟠桃千載實，年年天仗宴瑶池。"]'),
('37994e09-b8a0-4989-8b41-b1663921ced2','偈頌一百零四首  其九三','釋紹曇','宋','宋诗','song-poetry','','[]','九曲黄河徹底清，六龍乾會聖人生。',32,'全唐诗/poet.song.226000.json','["九曲黄河徹底清，六龍乾會聖人生。", "周行七步稱尊處，山嶽齊呼萬歲聲。"]'),
('8ecd7237-52d8-458d-9cf1-56480a531cd6','偈頌一百零四首  其九四','釋紹曇','宋','宋诗','song-poetry','','[]','共住不知名，千聖亦不識，無端平地生荆棘。',69,'全唐诗/poet.song.226000.json','["共住不知名，千聖亦不識，無端平地生荆棘。", "兄呼弟應，與世同波，笑獨醒人死汨羅。", "恁麽也好，不恁麽也好。", "手拍闌干唱竹枝，哩哩囉，天涯望遠無人到。"]'),
('c44cdc1e-b3a4-4f35-97ee-70602ecd651f','偈頌一百零四首  其九五','釋紹曇','宋','宋诗','song-poetry','','[]','撮藥場中驗作家，一枝手髂兩條蛇。',32,'全唐诗/poet.song.226000.json','["撮藥場中驗作家，一枝手髂兩條蛇。", "劉寄奴草雖靈驗，已是遭它毒口來。"]'),
('a4558ffa-2f52-46af-9f85-9ae69a625eb9','偈頌一百零四首  其九六','釋紹曇','宋','宋诗','song-poetry','','[]','九曲明珠久藴藏，走盤時見發寒光。',32,'全唐诗/poet.song.226000.json','["九曲明珠久藴藏，走盤時見發寒光。", "當陽拈出還收拾，瞎眼波斯自著忙。"]'),
('76789ade-062f-4628-9b00-404c7116c109','偈頌一百零四首  其九七','釋紹曇','宋','宋诗','song-poetry','','[]','鑑在機先，妙在轉處。',63,'全唐诗/poet.song.226000.json','["鑑在機先，妙在轉處。", "碧眼胡兒，全無肯路，行一步是一步。", "信脚錯踏翻，大地無寸土。", "業風吹上乳竇山，來點一盃茶，徐徐向伊道，提鞋去。"]'),
('956e980f-9631-4f7f-97df-41026151b196','偈頌一百零四首  其九八','釋紹曇','宋','宋诗','song-poetry','','[]','蒿籬關猛虎，筆管養蒼龍。',68,'全唐诗/poet.song.226000.json','["蒿籬關猛虎，筆管養蒼龍。", "穩帖帖藏牙伏爪，黑漫漫怪雨顛風。", "臨濟小廝兒驚心欲折，豐干老凍膿睡思方濃。", "山濛濛，水溶溶。", "乾坤無碧落，收放絕行蹤。"]'),
('21d63a27-2ae2-4b6f-a26c-fa3f9f015edb','偈頌一百零四首  其九九','釋紹曇','宋','宋诗','song-poetry','','[]','幕掛春烟，簟鋪秋水。',87,'全唐诗/poet.song.226000.json','["幕掛春烟，簟鋪秋水。", "高枕橫眠，鼻雷聒耳。", "爍石流金總不知，何須殿閣薰風至。", "又誰管九十日種粟燒畬，說甚麽十三番悟明自己。", "灼然是箇無煩惱，閻家倒退三千里。", "其或未然，莫道甕中常有米。"]'),
('e00d39cf-8348-4cea-a195-e1e376eb93e0','偈頌一百零四首  其一○○','釋紹曇','宋','宋诗','song-poetry','','[]','三伏炎蒸，汗流如雨。',26,'全唐诗/poet.song.226000.json','["三伏炎蒸，汗流如雨。", "一莖草上建瓊樓，徹骨貧窮敵國富。"]'),
('56b28ef8-f80d-4e0b-8270-6d3243f012f8','偈頌一百零四首  其一○一','釋紹曇','宋','宋诗','song-poetry','','[]','三界炎炎如火聚，攪擾勞生困蒸煮。',86,'全唐诗/poet.song.226000.json','["三界炎炎如火聚，攪擾勞生困蒸煮。", "邪見稠林蔽祖庭，孰爲臨濟陰凉樹。", "拄杖子，回避無門，全身荷負。", "特立獨行，危分險布。", "掃除枝葉不留蹤，普覆大地人，徹骨清凉去。", "雖然如是，趙婆酤醋。"]'),
('dcf6d5ab-529e-463a-8be1-638754032f81','偈頌一百零四首  其一○二','釋紹曇','宋','宋诗','song-poetry','','[]','寺踞千峰，十方同聚。',119,'全唐诗/poet.song.226000.json','["寺踞千峰，十方同聚。", "家賊難防，令人驚怖。", "正法明王，怒髮衝冠。", "作如是言休驚怖，儂家自有降魔杵。", "粉碎髑髏，裂開腸肚。", "熱鐵洋銅滿滿盛，鼻繩牽入泥犁去。", "佛子將謂出家行菩提路，誰知反不如狼虎，累及七代先靈，生身父母。", "號天血泪啼紅雨，啞，怨恨憑誰訴。"]'),
('98b394ee-e24a-48a3-810e-715737ef2d6c','偈頌一百零四首  其一○三','釋紹曇','宋','宋诗','song-poetry','','[]','有一物，全機用。',81,'全唐诗/poet.song.226000.json','["有一物，全機用。", "塵勞之儔，如來之種。", "輕若鴻毛輕，重若丘山重。", "乳峰信手拈來，點破勞生塵夢。", "剛被秋蟲落葉知，清聲戛玉寒，翠色黄金弄。", "雖然不直分文，擲地金聲，令人驚悚。"]'),
('7e9afe51-ee72-4168-8e67-e67e36a23d07','偈頌一百零四首  其一○四','釋紹曇','宋','宋诗','song-poetry','','[]','百戲場中賽錦標，蜜脾古馬舞兒多。',32,'全唐诗/poet.song.226000.json','["百戲場中賽錦標，蜜脾古馬舞兒多。", "頭籌暗被奪將去，行主喃喃强說呵。"]'),
('1bb6b067-69e3-4f91-97f4-b13cc17a0085','偈頌一百零四首  其一○五','釋紹曇','宋','宋诗','song-poetry','','[]','地上翻瓢，眉間掛劍。',56,'全唐诗/poet.song.226000.json','["地上翻瓢，眉間掛劍。", "古道雖微，惡聲難掩。", "窮則通，通則變。", "倒跨楊岐三脚馿，踏破山前祖父田園，一片兩片，四五六七片。"]'),
('9460132d-c22c-462f-8065-a5602cdc7b0f','偈頌一百零四首  其一○六','釋紹曇','宋','宋诗','song-poetry','','[]','千丈懸崖弄險巇，草鞋修整已多時。',32,'全唐诗/poet.song.226000.json','["千丈懸崖弄險巇，草鞋修整已多時。", "秋風償盡皮毛債，散步閑雲快活戲。"]'),
('746dbdd0-d7c1-4945-8eea-73374c35f52c','偈頌一百一十七首  其一','釋紹曇','宋','宋诗','song-poetry','','[]','池開古鏡奩，山聳青螺髻。',40,'全唐诗/poet.song.226000.json','["池開古鏡奩，山聳青螺髻。", "急著眼來看，不得作境會。", "覿體全彰解脫門，一踏牢關百雜碎。"]'),
('27363d3d-8d85-4e5f-af04-0f043ab0eaee','偈頌一百一十七首  其二','釋紹曇','宋','宋诗','song-poetry','','[]','你面黄，我面黑。',34,'全唐诗/poet.song.226000.json','["你面黄，我面黑。", "是馬是馿，各隨業力。", "驀劄相牽入草窠，鼻頭香臭不爭多。"]'),
('ba0ea339-b934-4e26-a73d-58ee6aaa9da3','偈頌一百一十七首  其三','釋紹曇','宋','宋诗','song-poetry','','[]','十二瑞峰前，一火白拈賊。',42,'全唐诗/poet.song.226000.json','["十二瑞峰前，一火白拈賊。", "佛面夜叉心，是何等相識。", "燒香供養，使自知非，剪月初無陷虎機。"]'),
('cb5dfdd6-6545-455f-8506-cbae2479b37a','偈頌一百一十七首  其四','釋紹曇','宋','宋诗','song-poetry','','[]','瘦藤枝，烏律卒。',34,'全唐诗/poet.song.226000.json','["瘦藤枝，烏律卒。", "入草尋人，揣空出骨。", "不是心不是佛不是物，貶向無生國。"]'),
('8359d111-3f29-4a45-9d88-a6c5a54689f3','偈頌一百一十七首  其五','釋紹曇','宋','宋诗','song-poetry','','[]','入微塵，含法界。',26,'全唐诗/poet.song.226000.json','["入微塵，含法界。", "頂𩕳機，看脚下。", "須彌燈王，冰消瓦解。"]'),
('d6301dc7-9abf-40f9-907a-1f3d443c7d64','偈頌一百一十七首  其六','釋紹曇','宋','宋诗','song-poetry','','[]','杓柄短長，鍋兒大小，家醜無端花擘了。',38,'全唐诗/poet.song.226000.json','["杓柄短長，鍋兒大小，家醜無端花擘了。", "狼籍不小，慚惶不少。", "藏主師兄，平跋則个。"]'),
('f25a4670-cb29-4f53-9af9-b1c8befc42c4','偈頌一百一十七首  其七','釋紹曇','宋','宋诗','song-poetry','','[]','逼人上樹拔却梯，推人入井覆却桶。',42,'全唐诗/poet.song.226000.json','["逼人上樹拔却梯，推人入井覆却桶。", "江湖用此惡心腸，誰云契義金蘭重。", "怪語顛言，開眼說夢。"]'),
('44109bc7-f371-4d54-bd75-1ac00b22b583','偈頌一百一十七首  其八','釋紹曇','宋','宋诗','song-poetry','','[]','蛇頭揩癢，虎口拔牙。',20,'全唐诗/poet.song.226000.json','["蛇頭揩癢，虎口拔牙。", "拚得性命，始是作家。"]'),
('0c75deca-e46b-4adb-809c-826af7cd8205','偈頌一百一十七首  其九','釋紹曇','宋','宋诗','song-poetry','','[]','國有世臣，伊周是則。',62,'全唐诗/poet.song.226000.json','["國有世臣，伊周是則。", "神政冰清，忠謨鯁直。", "存方寸地子孫耕，黍稷非馨深種德。", "美則美矣，這爭如何。", "巨闢十三華藏界，藏身無迹海騰波。"]'),
('bef640cd-1f76-4bcd-ad7a-80d285df5b95','偈頌一百一十七首  其一○','釋紹曇','宋','宋诗','song-poetry','','[]','萬疊青山，一溪寒水。',80,'全唐诗/poet.song.226000.json','["萬疊青山，一溪寒水。", "花禁冷葉紅，草滴虛嵐翠，無位真人祇者是。", "不離當處當湛然，左右逢原無二體。", "覷之瞎雙眸，即之雲萬里。", "祇如堅持漢節，賤賣生姜，妙悟水因，重光佛日。"]'),
('f9be3a5d-6655-48a0-a3ce-5e750feeb2ee','偈頌一百一十七首  其一一','釋紹曇','宋','宋诗','song-poetry','','[]','再世唐堯，更生虞舜。',36,'全唐诗/poet.song.226000.json','["再世唐堯，更生虞舜。", "統御金輪，永膺天命。", "林泉何以報生成，一縷檀烟萬佛名。"]'),
('3ae3f1cc-715a-4dc9-ae2e-7c4361155c4d','偈頌一百一十七首  其一二','釋紹曇','宋','宋诗','song-poetry','','[]','浄飯王宮積惡多，從天降謫個妖魔。',52,'全唐诗/poet.song.226000.json','["浄飯王宮積惡多，從天降謫個妖魔。", "指天指地胡揮揎，無柰通身穢汙何。", "瑞岩無柄杓，惡水劈頭澆，特石須頑也合消。"]'),
('b93b9f04-11a0-4bf1-8860-1971e91c097a','偈頌一百一十七首  其一三','釋紹曇','宋','宋诗','song-poetry','','[]','跛脚阿師，弄蹄馿子。',82,'全唐诗/poet.song.226000.json','["跛脚阿師，弄蹄馿子。", "一字關徒費分疏，栗棘蓬恣情吞吐。", "凌滅祖師禪，函蓋乾坤句。", "孤危不立自孤危，萬仞雪崖丰骨露。", "十二峰前，斫額望汝。", "洞山佛無光，無你捫摸處，無你栖泊處。"]'),
('811892fc-a66e-4393-bdd2-c17e63ab7b90','偈頌一百一十七首  其一四','釋紹曇','宋','宋诗','song-poetry','','[]','苦澀菖蒲茶，膠粘青蒻粽。',101,'全唐诗/poet.song.226000.json','["苦澀菖蒲茶，膠粘青蒻粽。", "嗅著鼻頭辛，咬得牙關腫。", "佛病祖病蠲除，妖星怪星驚悚。", "善才採藥，颺在壁根。", "天師書符，抗藏衣籠。", "和盤掇出宴佳賓，山鳥山花欣然。", "錦綉鋪陳，笙簧品弄。", "囉囉招，囉囉送，莫怪空疏，伏惟珍重。"]'),
('274fab8c-ce7c-4424-b220-53f517b6b025','偈頌一百一十七首  其一五','釋紹曇','宋','宋诗','song-poetry','','[]','半晴半雨，釀成梅溽。',62,'全唐诗/poet.song.226000.json','["半晴半雨，釀成梅溽。", "無位真人，口生白醭。", "玄談發淵默之雷，妙應答傳聲之谷。", "花簇簇，錦簇簇，聽不足，玩不足。", "啞，六六依前三十六。"]'),
('edcbf4e4-808b-4ea4-bc36-70f7bdcde32e','偈頌一百一十七首  其一六','釋紹曇','宋','宋诗','song-poetry','','[]','一二三四五六七，數目分明誰委悉。',48,'全唐诗/poet.song.226000.json','["一二三四五六七，數目分明誰委悉。", "李淳風與袁天綱，推盡先天算不出。", "算得出，昨日五月盡，今朝六月一。"]'),
('45cc25c1-436b-4964-9794-19a49ceb8d9a','偈頌一百一十七首  其一七','釋紹曇','宋','宋诗','song-poetry','','[]','諸莊收歛，幾樣心腸。',62,'全唐诗/poet.song.226000.json','["諸莊收歛，幾樣心腸。", "憂風憂雨，憂旱憂荒。", "刈禾鐮雖云快利，要用處不犯鋒鋩。", "策勳汗血，別甑炊香。", "飯裏有沙如咬著，方知禾熟不臨場。"]'),
('c9f01cd8-7223-416a-929b-8379215981ee','偈頌一百一十七首  其一八','釋紹曇','宋','宋诗','song-poetry','','[]','天地不仁，人心招感。',101,'全唐诗/poet.song.226000.json','["天地不仁，人心招感。", "田稼如雲，一風消散。", "農家血泪流，肝腸斷。", "惟有林間衲子，有亦不知，無亦不管。", "圓蒲擁雪衾，綴鉢盛香飯。", "放憨一飽萬緣空，冷笑傍人忙似鑽。", "灼然如是，萬兩黄金也合消，其或未然，切莫怪閻家打算。"]'),
('72c769a7-bc40-4afe-b8f6-d540fb0e2fd1','偈頌一百一十七首  其一九','釋紹曇','宋','宋诗','song-poetry','','[]','善護菩提樹有年，金枝玉葉蔭兒孫。',32,'全唐诗/poet.song.226000.json','["善護菩提樹有年，金枝玉葉蔭兒孫。", "大功難紀人間世，千佛名書補處尊。"]'),
('1c920917-87a7-4c82-8d5e-703e8a94b57a','偈頌一百一十七首  其二○','釋紹曇','宋','宋诗','song-poetry','','[]','衲僧家，無本據。',86,'全唐诗/poet.song.226000.json','["衲僧家，無本據。", "暑退凉生，任情去住。", "折拄杖，挑撥紅塵堆裏人，破草鞋，踏斷枯木巖前路。", "無佛處，急赴過，有佛處，不得住。", "捏聚大千無寸土，業風吹上十二峰。", "來，徐徐向伊道，提鞋去。"]'),
('a0b1c279-2d51-4bdc-b7eb-7bfa97af8d5c','偈頌一百一十七首  其二一','釋紹曇','宋','宋诗','song-poetry','','[]','截流機，分涇渭。',70,'全唐诗/poet.song.226000.json','["截流機，分涇渭。", "清濁淺深，窮源倒底。", "三脚馿子弄蹄行，踏過何曾沾著水。", "芝峰家醜外揚，也是碓坊洿米。", "低聲低聲，牆壁有耳。", "座滿江南客，何須唱鷓鴣。"]'),
('c735d2b9-d04a-4909-afe8-f4a5fcefb913','偈頌一百一十七首  其二二','釋紹曇','宋','宋诗','song-poetry','','[]','寒空書雁，破壁吟螿。',73,'全唐诗/poet.song.226000.json','["寒空書雁，破壁吟螿。", "井梧翻葉，巖桂飄香。", "無位真人，橫拖倒拽，無地埋藏。", "舉世生盲人不識，分拏摸象恣猖狂。", "徒勞香至子，歷魏與遊梁。", "啞，鵲石何曾解放光。"]'),
('42217d6e-e5de-400b-93f7-80f8f39b9c2b','偈頌一百一十七首  其二三','釋紹曇','宋','宋诗','song-poetry','','[]','劄得脚跟牢，不怕風濤險。',52,'全唐诗/poet.song.226000.json','["劄得脚跟牢，不怕風濤險。", "大田多稼如雲，只要及時收歛。", "歸來香積國經行，喜見飛簷翔唇吻。", "議賞元勳，高低有分。"]'),
('d2e115a6-f746-4418-aa6b-16d07261e1b9','偈頌一百一十七首  其二四','釋紹曇','宋','宋诗','song-poetry','','[]','鳳宿龍巢，宸車苔輾。',91,'全唐诗/poet.song.226000.json','["鳳宿龍巢，宸車苔輾。", "前不搆村，後不迭店。", "疑殺天下人，自疑猶未免。", "瞥轉一機，星馳電捲。", "飛來峰刮地風寒，冷泉水滔天浪衮。", "死句翻成活句傳，大冶精金經百鍊。", "啞，退耕師兄，能事云周，一死何憾。"]'),
('579bf9de-ef07-4d4c-9586-66fafe01182b','偈頌一百一十七首  其二五','釋紹曇','宋','宋诗','song-poetry','','[]','拄杖子，黑粼皴。',58,'全唐诗/poet.song.226000.json','["拄杖子，黑粼皴。", "韜藏頭角，枯槁身心。", "剛被業風飄皷，忙忙入草尋人。", "奔馳鳥道，簸弄馿唇。", "湖海聽聞齊掩耳，只宜藏拙古巖陰。"]'),
('9f6d6cd9-773e-43ae-ba0b-2a425c05a507','偈頌一百一十七首  其二六','釋紹曇','宋','宋诗','song-poetry','','[]','萬疊青山，一溪流水。',62,'全唐诗/poet.song.226000.json','["萬疊青山，一溪流水。", "幽鳥綿蠻，烟蘿鎖翠。", "瑞巖活計無多，徒掛傍人唇齒。", "徹骨貧窮，熏天富貴。", "一陣西風丹桂香。", "二三子，吾無隠乎爾。"]'),
('297b1215-1c14-4311-a3dc-d5064493551f','偈頌一百一十七首  其二七','釋紹曇','宋','宋诗','song-poetry','','[]','滄溟深，未必深。',110,'全唐诗/poet.song.226000.json','["滄溟深，未必深。", "須彌險，未必險。", "衲僧家險崖機不可挨，深密心不可察。", "拄杖子忍俊不禁，試與探測看。", "深無半寸，平如鏡面。", "浩大雷聲，全無雨點。", "只好深雲龜六藏，佛眼迷蹤尋不見。", "尋得見，瑞巖點一杯茶，徐徐向伊道，日暮窮途，家鄉尚遠。"]'),
('8b0f1f3a-2d1d-44a5-9f14-298f8b2a0caa','偈頌一百一十七首  其二八','釋紹曇','宋','宋诗','song-poetry','','[]','沒絃琴，有遺音。',69,'全唐诗/poet.song.226000.json','["沒絃琴，有遺音。", "調高流水，聲振緇林。", "碧眼黄頭爭品弄，無端花擘祖師心。", "瑞巖素非妙手，效顰彈一曲看。", "叮當叮當，絕聽子期迷節奏，和雲高掛古松陰。"]'),
('fe179ecb-56d4-424e-8b76-29e95554d457','偈頌一百一十七首  其二九','釋紹曇','宋','宋诗','song-poetry','','[]','荆棘林，大火聚。',52,'全唐诗/poet.song.226000.json','["荆棘林，大火聚。", "峭壁深阬，無栖泊處。", "直饒伊瞥轉一機，轉得身，通得步。", "瑞巖未敢輕相許，何故鳳栖不在梧桐樹。"]'),
('69bc3129-1537-4ead-8e59-7f8a7305f101','偈頌一百一十七首  其三○','釋紹曇','宋','宋诗','song-poetry','','[]','書載五雲，綉添一線。',48,'全唐诗/poet.song.226000.json','["書載五雲，綉添一線。", "剝盡羣陰，天心復見。", "惟有龜毛拂，今古無遷變。", "松根石上笑談空，切忌隨他語脈轉。"]'),
('f090a957-1a64-413a-b9f4-fc744b259034','偈頌一百一十七首  其三一','釋紹曇','宋','宋诗','song-poetry','','[]','大智洞明，十方虛徹。',59,'全唐诗/poet.song.226000.json','["大智洞明，十方虛徹。", "玄樞妙轉，千聖迷蹤。", "直饒透箐眼明，截流機峻。", "須知更有向上一路在，這裡見得徹去，方知東山五祖老凍膿。"]'),
('60f30e96-5f09-42bd-87b5-aae5b3a2a779','偈頌一百一十七首  其三二','釋紹曇','宋','宋诗','song-poetry','','[]','太阿久瘞豐城劍，纔遇張華便發光。',32,'全唐诗/poet.song.226000.json','["太阿久瘞豐城劍，纔遇張華便發光。", "積世冤讎都掃却，蟄龍銀匣襲珍藏。"]'),
('6e55ea14-18ef-42c4-9098-ad47e6165a0e','偈頌一百一十七首  其三三','釋紹曇','宋','宋诗','song-poetry','','[]','扭碎東山鼻孔，牽斷佛眼耳輪。',54,'全唐诗/poet.song.226000.json','["扭碎東山鼻孔，牽斷佛眼耳輪。", "一等施呈毒手，腕頭力重千鈞。", "飫饕法味，飽聽圓音。", "漢室威儀重復見，紫芝香散碧巖春。"]'),
('837d56d7-6d47-4b1b-80d8-01903e618118','偈頌一百一十七首  其三四','釋紹曇','宋','宋诗','song-poetry','','[]','忠清千古燦奎文，蓋世功名富貴生。',32,'全唐诗/poet.song.226000.json','["忠清千古燦奎文，蓋世功名富貴生。", "旌佩擁雲何處去，毗盧樓閣款經行。"]'),
('21299507-38ce-43a0-adbf-5ae4e4d46603','偈頌一百一十七首  其三五','釋紹曇','宋','宋诗','song-poetry','','[]','簸弄乾坤，靈蛇在掌。',74,'全唐诗/poet.song.226000.json','["簸弄乾坤，靈蛇在掌。", "露刃含霜，阿誰近傍。", "殲厥渠魁未得時，蟄龍護匣牢收抗。", "還他道地，劍州與太阿無兩樣。", "携來剪月亭前，共聚五湖禪流，拭目縱觀，連聲稱賞。"]'),
('5597a0e4-a179-4a13-b7d4-08e7bb62d15c','偈頌一百一十七首  其三六','釋紹曇','宋','宋诗','song-poetry','','[]','半夜逾城，六年栖雪。',62,'全唐诗/poet.song.226000.json','["半夜逾城，六年栖雪。", "餓得腸枯，凍得骨折。", "那更見明星，兩眼添重屑。", "後代兒孫苦證羊，一年一度爭饒舌。", "正法眼藏，宜乎向這瞎馿邊滅。"]'),
('9dbf2a85-aa1b-40cc-8767-e3a522d4790c','偈頌一百一十七首  其三七','釋紹曇','宋','宋诗','song-poetry','','[]','正月一，是新年。',67,'全唐诗/poet.song.226000.json','["正月一，是新年。", "家家慶賀，處處喧闐。", "惟有拄杖子，不隨時變。", "松根穩坐，石上安眠。", "驀地放憨歌一曲，囉囉哩囉囉哩囉。", "木人聽不足，瘦立綠蘿烟。"]'),
('52031015-127f-4a1f-a813-456777f8d3a3','偈頌一百一十七首  其三八','釋紹曇','宋','宋诗','song-poetry','','[]','一點心燈，寒光燦爛。',83,'全唐诗/poet.song.226000.json','["一點心燈，寒光燦爛。", "今古長明，幾人著眼。", "諸方老凍膿，燒畬種粟，三呼三應，妙悟水因，眉間挂劍。", "雖然列焰分輝，當暗中有明，當明中有暗。", "而今拈出普請看，出格元宵，何妨賞翫。"]'),
('bb443b22-c8c2-46da-bce4-498594c49037','偈頌一百一十七首  其三九','釋紹曇','宋','宋诗','song-poetry','','[]','獨坐大雄峰，臨機多弄險。',58,'全唐诗/poet.song.226000.json','["獨坐大雄峰，臨機多弄險。", "遭虎口殺活不分，脫狐身真假難辨。", "那堪創立清規，平地深深坑壍。", "結成不共戴天讎，燒炷楓香解釋休。"]'),
('c389aa72-83d4-4c5f-9cad-e66b0b2483c2','偈頌一百一十七首  其四○','釋紹曇','宋','宋诗','song-poetry','','[]','人從雪峰來，接得乳峰信。',115,'全唐诗/poet.song.226000.json','["人從雪峰來，接得乳峰信。", "報道古磵寒泉，湧出千丈飛雪。", "推倒妙高臺，掀翻烏石嶺。", "松山土主冷地翻身，隠潭龍王夢中驚醒。", "郎忙抖擻精神，念一道離怖畏真言，南無三滿多，沒馱喃，唵部齡，唵齒齡。", "吽吽，急急如律令。", "三世諸佛立地聽，梵語華言難改正。"]'),
('f8adae20-e8c9-4d44-9e75-27efd5883a7a','偈頌一百一十七首  其四一','釋紹曇','宋','宋诗','song-poetry','','[]','家在蓬萊，霓裾粲霞。',76,'全唐诗/poet.song.226000.json','["家在蓬萊，霓裾粲霞。", "步虛聲有節，觀徼念無差。", "護劍蒼虬鳴寶匣，聽琴瘦鶴倚庭花。", "丹成九轉，符掃群邪。", "不負東林蓮社約，乘軺來訪竺僊家。", "虎溪分未得，款喫趙州茶。"]'),
('0a16175b-33b9-471d-a46e-a4d523822f5a','偈頌一百一十七首  其四二','釋紹曇','宋','宋诗','song-poetry','','[]','祖父田園，積年荒廢。',54,'全唐诗/poet.song.226000.json','["祖父田園，積年荒廢。", "農不務耕，漁專討利。", "徹底掀翻自有人，去盡殘蘆并敗葦。", "鴈過長空，影沉寒水，字字聲聲說大義。"]'),
('611b0578-5c33-4d29-b7d7-9d5387ddfe35','偈頌一百一十七首  其四三','釋紹曇','宋','宋诗','song-poetry','','[]','九十日春今欲過，人生能見幾韶光。',68,'全唐诗/poet.song.226000.json','["九十日春今欲過，人生能見幾韶光。", "秦源方被桃花誤，隋岸還看柳絮狂。", "拄杖子，知不遷義，緘封不密，滿口嚼冰霜。", "千言萬語無人會，又逐流鶑過短牆。"]'),
('17ecdd88-3d74-4625-90ef-dda9ca89161e','偈頌一百一十七首  其四四','釋紹曇','宋','宋诗','song-poetry','','[]','長鬚翁，久不見。',74,'全唐诗/poet.song.226000.json','["長鬚翁，久不見。", "壁角深藏，心灰百煉。", "將期休影息陰，豈謂明明弄險。", "點出夜叉心，擘開菩薩面。", "醜惡既乖張，佛手難遮掩。", "贏得春山哭杜鵑，鮮血染花枝，聲聲怨。"]'),
('e5f3201f-fa7f-460a-a1e9-ea53bc0edd4a','偈頌一百一十七首  其四五','釋紹曇','宋','宋诗','song-poetry','','[]','秋暘肆酷，秋暑炎蒸。',63,'全唐诗/poet.song.226000.json','["秋暘肆酷，秋暑炎蒸。", "不容鵝護雪，難保蠟人冰。", "一夏噇眠虛過了，秋風拈弄刈禾鐮。", "權有用，無黨無偏。", "幾箇祖師頭割了，立教凶歲變豐年。"]'),
('04293269-8ef8-4884-b637-6156343afb29','偈頌一百一十七首  其四六','釋紹曇','宋','宋诗','song-poetry','','[]','秋陽肆酷，劃地奔雷。',112,'全唐诗/poet.song.226000.json','["秋陽肆酷，劃地奔雷。", "洗滌袢襟，喜而不寐。", "懿德山王贈之以偈：大旱逢甘雨，他鄉遇故知。", "攧崖泉漱玉，嘗稻雪翻匙。", "咿嗚咿，誰知艱棘際，復見太平時。", "拄杖子，暗中聞得，手之舞之，足之蹈之。", "暑退凉生前路活，化龍一躍出天池，贏得龐公笑展眉。"]'),
('1212693f-e342-49ca-9af1-2087055cd9b8','偈頌一百一十七首  其四七','釋紹曇','宋','宋诗','song-poetry','','[]','僧鉢一粒飯，農家一滴血。',56,'全唐诗/poet.song.226000.json','["僧鉢一粒飯，農家一滴血。", "戰爭收拾歸，知費幾牙頰。", "明璣杵白，別甑炊香。", "伴客地爐燒榾柮，無賓主話商量。", "切忌增金以黄。"]'),
('4d192274-659b-4909-9704-15618a1c5b30','偈頌一百一十七首  其四八','釋紹曇','宋','宋诗','song-poetry','','[]','雨後谿聲寒弄玉，風前木葉碎飄金。',58,'全唐诗/poet.song.226000.json','["雨後谿聲寒弄玉，風前木葉碎飄金。", "見聞互用非聲色，花劈威音古佛心。", "見成家樂，管宴佳賓。", "莫謂瑞巖岑寂甚，一回拈出一回新。"]'),
('a945a0b3-d66f-475e-9ace-949c1f226511','偈頌一百一十七首  其四九','釋紹曇','宋','宋诗','song-poetry','','[]','打破劍門關，未死先辭世。',59,'全唐诗/poet.song.226000.json','["打破劍門關，未死先辭世。", "書偈自塗糊，白把驪珠碎。", "口款細供通，自首原其罪。", "木人歌舞石人悲。", "聲遏行雲，鴈序分，影落千峰外。"]'),
('7cf8123b-b46a-43cb-ae9d-3a88e3989fdc','偈頌一百一十七首  其五○','釋紹曇','宋','宋诗','song-poetry','','[]','兜率天宮初說夢，修多羅藏又談空。',58,'全唐诗/poet.song.226000.json','["兜率天宮初說夢，修多羅藏又談空。", "一人人飽純陀味，不與尋常至節同。", "娟娟蘿月，瑟瑟松風。", "四壁生涯貧徹骨，敵君王富樂無窮。"]'),
('b2449f29-4f61-43ba-93a2-2626646414c0','偈頌一百一十七首  其五一','釋紹曇','宋','宋诗','song-poetry','','[]','萬金包裹爛泥團，不惜當場撮弄看。',32,'全唐诗/poet.song.226000.json','["萬金包裹爛泥團，不惜當場撮弄看。", "敗闕遭人窺覷了，末梢依舊被渠瞞。"]'),
('8b357ac8-4782-4033-b3cf-ca4ae01b0654','偈頌一百一十七首  其五二','釋紹曇','宋','宋诗','song-poetry','','[]','一點心燈，靈明炳煥。',56,'全唐诗/poet.song.226000.json','["一點心燈，靈明炳煥。", "去古來今，清光無間。", "不同萬斛金蓮，惑亂癡人賞翫。", "今朝上元節，拈出普請看。", "擬議尋思，空華翳眼。"]'),
('1e105246-0f07-42dc-8d3d-781006c5f389','偈頌一百一十七首  其五三','釋紹曇','宋','宋诗','song-poetry','','[]','廝撲場中作斷交，拳來趯去不相饒。',32,'全唐诗/poet.song.226000.json','["廝撲場中作斷交，拳來趯去不相饒。", "誰知用盡平生力，却傍被人奪錦標。"]'),
('93b711ce-ea3a-4c15-aa3f-b6c09c5c50e3','偈頌一百一十七首  其五四','釋紹曇','宋','宋诗','song-poetry','','[]','上林春色正繁華，公子聯鑣去賞花。',32,'全唐诗/poet.song.226000.json','["上林春色正繁華，公子聯鑣去賞花。", "貪弄玉盃泥樣醉，笙歌叢裡簇歸家。"]'),
('c0ecc12a-06e7-4bee-9619-ca155797f44f','偈頌一百一十七首  其五五','釋紹曇','宋','宋诗','song-poetry','','[]','遠望蓬萊去學仙，途中忽遇李先生。',32,'全唐诗/poet.song.226000.json','["遠望蓬萊去學仙，途中忽遇李先生。", "還丹一粒吞還吐，回首空山獨自行。"]'),
('2b656570-e742-4517-826e-72409585efc5','偈頌一百一十七首  其五六','釋紹曇','宋','宋诗','song-poetry','','[]','大悲正眼露堂堂，百步當摇閃電光。',32,'全唐诗/poet.song.226000.json','["大悲正眼露堂堂，百步當摇閃電光。", "被掣風顛醫瞎子，暗中拖拽下禪床。"]'),
('af8829fa-6d11-4189-b21a-866d39a2051c','偈頌一百一十七首  其五七','釋紹曇','宋','宋诗','song-poetry','','[]','嶺上雲磨松偃蹇，巖前瀑漱石琮琤。',58,'全唐诗/poet.song.226000.json','["嶺上雲磨松偃蹇，巖前瀑漱石琮琤。", "瞿曇面目全彰露，誰道今朝始誕生。", "跛雲門棒，休放拍盲。", "一杓香湯三拜著，聽渠千古惡名行。"]'),
('76954482-9b73-4a11-a826-64b4a9fd85ef','偈頌一百一十七首  其五八','釋紹曇','宋','宋诗','song-poetry','','[]','一春連雨，民心憂懼。',70,'全唐诗/poet.song.226000.json','["一春連雨，民心憂懼。", "妻子號饑，米無糴處。", "珍重活衲僧福德聚，衲被蒙頭無思無慮。", "九旬禁足，鈍鳥栖蘆。", "三月安居，蟄蟲坏戶。", "翻轉鐵面皮，嫌佛不肯做。"]'),
('abb7c364-a828-4db3-aacc-fd34863dbd95','偈頌一百一十七首  其五九','釋紹曇','宋','宋诗','song-poetry','','[]','前宵剪月亭邊，曲奏高山流水。',83,'全唐诗/poet.song.226000.json','["前宵剪月亭邊，曲奏高山流水。", "雖云獅子筋絃，品弄必資妙指，不落宮商人聳耳。", "嘉州大像增百倍精神，荆溪老龍添十分活意。", "正音將謂絕無聞，誰料鄭聲亂雅中，有此清彈爾。", "慚愧慚愧。"]'),
('a5fa2648-43b6-4b9d-950b-fc9c7bd07802','偈頌一百一十七首  其六○','釋紹曇','宋','宋诗','song-poetry','','[]','雷轟薦福碑，天秘無文印。',66,'全唐诗/poet.song.226000.json','["雷轟薦福碑，天秘無文印。", "字義既難明，心傳誰得正。", "東湖瀉恨浪滔天，驚𢞕瑞巖殘夢醒。", "猛拍闌干，叫天不應。", "哭不成兮笑不成，野花泪濕千峰影。"]'),
('cc52dc12-2cdb-4618-b262-5e8582776ea8','偈頌一百一十七首  其六一','釋紹曇','宋','宋诗','song-poetry','','[]','三月休征，修文偃武。',73,'全唐诗/poet.song.226000.json','["三月休征，修文偃武。", "治格太平，生靈鼓舞。", "無端塞馬嘶風，又欲揚塵簸土。", "密運機籌，肅行師旅。", "塞北安南一戰收，生死冤魔都掃去。", "重賞元勳，凱歌聲撼芝峰路。"]'),
('623826c7-68b3-4c8e-9cb1-3704f40c5c87','偈頌一百一十七首  其六二','釋紹曇','宋','宋诗','song-poetry','','[]','九月授衣天，芝峰無可授。',24,'全唐诗/poet.song.226000.json','["九月授衣天，芝峰無可授。", "破衲擁寒雲，對客慵開口。"]'),
('31fe6a3b-d5de-405a-a661-d5de9a9f9093','偈頌一百一十七首  其六三','釋紹曇','宋','宋诗','song-poetry','','[]','成癖襟懷爲愛山，不逢佳處不開顔。',32,'全唐诗/poet.song.226000.json','["成癖襟懷爲愛山，不逢佳處不開顔。", "錦屏劍閣重相見，疑在岷峨翠靄間。"]'),
('8b9ddf42-47e6-47df-9ed5-3e61f2c79071','偈頌一百一十七首  其六四','釋紹曇','宋','宋诗','song-poetry','','[]','一二三四五，六七八九十。',83,'全唐诗/poet.song.226000.json','["一二三四五，六七八九十。", "梵語華言譯不成，玉几重新添註解。", "字義炳然，無人領解。", "頼有同風知，點頭道奇怪。", "彷彷彿彿，一似東山瓦鼓歌。", "腔調宛同，聲無高下。", "彭八剌拶，未在未在。"]'),
('4b952b05-d274-4023-a00e-9b43849e630e','偈頌一百一十七首  其六五','釋紹曇','宋','宋诗','song-poetry','','[]','書雲開管宴，法輪食輪轉。',54,'全唐诗/poet.song.226000.json','["書雲開管宴，法輪食輪轉。", "覷之雙眼盲，味之唾三嚥。", "雲門胡餠，謾自誇張，楊岐栗蓬，急須收卷。", "露柱燈籠，春風滿面。"]'),
('81811fcf-fca8-4241-9827-d70332ced02a','偈頌一百一十七首  其六六','釋紹曇','宋','宋诗','song-poetry','','[]','道德五千言，深明玄妙句。',84,'全唐诗/poet.song.226000.json','["道德五千言，深明玄妙句。", "雲門一字關，截斷橫陳路。", "十二峰前，危分險布。", "喚醒惺惺石上瞌睡主人公，握手評論，掀眉笑語。", "驚放寒梅一兩花，漏洩先春，奔馳驛使。", "啞，尋香逐臭人無數。"]'),
('e7d994d2-5441-4833-8f5a-ddf593158f90','偈頌一百一十七首  其六七','釋紹曇','宋','宋诗','song-poetry','','[]','向上機，頂門眼。',44,'全唐诗/poet.song.226000.json','["向上機，頂門眼。", "察秋毫處暗昏昏，透險崖中平坦坦。", "三世諸佛，正視無門，白牯狸奴，活埋何限。"]'),
('c30f0270-cefe-4c30-86d0-0a304d7dd643','偈頌一百一十七首  其六八','釋紹曇','宋','宋诗','song-poetry','','[]','親隨彌勒下長汀，一字王書奉化名。',32,'全唐诗/poet.song.226000.json','["親隨彌勒下長汀，一字王書奉化名。", "輔國功成歸內院，子孫恩被錦衣榮。"]'),
('f9a58616-1f3e-4728-b20c-fdd4e7ab86b3','偈頌一百一十七首  其六九','釋紹曇','宋','宋诗','song-poetry','','[]','無辨古今眼，有辨古今舌。',44,'全唐诗/poet.song.226000.json','["無辨古今眼，有辨古今舌。", "說得十分真，何如見得徹。", "見得徹，耿耿心燈奪夜寒。", "年年宴賞元宵節。"]'),
('79e25b22-f1af-4240-960b-b9dc65231b9f','偈頌一百一十七首  其七○','釋紹曇','宋','宋诗','song-poetry','','[]','茅舍春深，韶華可人。',53,'全唐诗/poet.song.226000.json','["茅舍春深，韶華可人。", "山花裛翠，烟草如茵。", "況有尋幽客至，錦囊探句，藜杖挑琴。", "握手松根同一笑，高風曾不護東林。"]'),
('6d70f518-38c9-4187-a05f-db6c2a99c068','偈頌一百一十七首  其七一','釋紹曇','宋','宋诗','song-poetry','','[]','廣漢馬駒子，十方羅漢僧。',82,'全唐诗/poet.song.226000.json','["廣漢馬駒子，十方羅漢僧。", "不喫金鷄粟，專銜血戰冤。", "古龍淵吸乾到底，清凉樹靠倒無根。", "五處移場弄巇險，化機曾不涉春緣。", "休征藏密，地陷天崩。", "棠棣花殘鴈沉影，椎胸未免哭蒼天。"]'),
('a42f5788-b913-40cf-a1ca-2810bafa7b30','偈頌一百一十七首  其七二','釋紹曇','宋','宋诗','song-poetry','','[]','三月青春彈指過，九旬朱夏又從頭。',42,'全唐诗/poet.song.226000.json','["三月青春彈指過，九旬朱夏又從頭。", "茶抽雀舌郎忙摘，麥弄蝦鬚逐旋收。", "熾然說法，聲撼林丘。"]'),
('9cdb8434-2ac9-4c1c-b649-254543523115','偈頌一百一十七首  其七三','釋紹曇','宋','宋诗','song-poetry','','[]','結夏已半月了也，水牯牛作麽生。',53,'全唐诗/poet.song.226000.json','["結夏已半月了也，水牯牛作麽生。", "愛從荒草去，不向坦途行。", "閙中牽索，靜處加鞭。", "月白風清眠露地，聲聲牧笛響烟村。"]'),
('6dc48893-0294-422b-918c-91f1de226594','偈頌一百一十七首  其七四','釋紹曇','宋','宋诗','song-poetry','','[]','小供天中節，家貧樂有餘。',58,'全唐诗/poet.song.226000.json','["小供天中節，家貧樂有餘。", "蒻包粳米粽，茶點石菖蒲。", "不用童尋藥，何須鬼畫符。", "千妖俱掃迹。", "長夏得安居。", "衲僧門下，天地懸殊。"]'),
('cc7ce02b-c684-4d2c-bb89-3e5674127ddb','偈頌一百一十七首  其七五','釋紹曇','宋','宋诗','song-poetry','','[]','放下著，莫妄想。',44,'全唐诗/poet.song.226000.json','["放下著，莫妄想。", "無孔鐵鎚，半斤八兩。", "面門拋擲，土曠人稀。", "無業趙州元不會，鳳林徒自說吒之。"]'),
('f4b9173a-7d96-42bc-8045-7c8a97e33d94','偈頌一百一十七首  其七六','釋紹曇','宋','宋诗','song-poetry','','[]','六月苦炎熱，蠟人何似生。',65,'全唐诗/poet.song.226000.json','["六月苦炎熱，蠟人何似生。", "火雲烹得解，解後却完全。", "堪笑雲門老，杲掣風顛，通身臭汗。", "微凉生殿閣，打失鬼精魂。", "要會諸佛出身處，馿年馿年。"]'),
('dcbc44bf-10ab-4060-9924-c84eab5bdeb1','偈頌一百一十七首  其七七','釋紹曇','宋','宋诗','song-poetry','','[]','雨足龍閑，年豐民樂。',65,'全唐诗/poet.song.226000.json','["雨足龍閑，年豐民樂。", "袖出刈禾鐮，大地全收却。", "歸來十二峰前，別甑炊香，明璣滿鉢。", "餵飽活衲僧，曲肱酣睡著。", "佛法身心爛似泥，啞，醫無藥。"]'),
('b23004b0-5b72-462e-9982-8101e6cbeaf5','偈頌一百一十七首  其七八','釋紹曇','宋','宋诗','song-poetry','','[]','十二峰前傀儡棚，盡由行主線抽牽。',32,'全唐诗/poet.song.226000.json','["十二峰前傀儡棚，盡由行主線抽牽。", "編排科段無新舊，歌舞秋風樂管筵。"]'),
('907fe2da-7445-4927-9f59-f6292668fe15','偈頌一百一十七首  其七九','釋紹曇','宋','宋诗','song-poetry','','[]','人從福州來，接得江西信。',62,'全唐诗/poet.song.226000.json','["人從福州來，接得江西信。", "報道雪峰木毬，輥入育王鰻井。", "怒浪翻空，魚龍乞命。", "秋風吹落惺惺石上，驚觸主人翁酣睡醒。", "掀眉一笑千峰靜。"]'),
('deb2bd00-a876-4c59-98d4-10410d9a06b3','偈頌一百一十七首  其八○','釋紹曇','宋','宋诗','song-poetry','','[]','八月十五中秋節，人皆競賞天邊月。',66,'全唐诗/poet.song.226000.json','["八月十五中秋節，人皆競賞天邊月。", "心月孤圓自不知，不涉圓虧光影滅。", "馬師父子錯商量，拂袖便行猶未徹。", "諸人還見心月麽，急著眼看，重重金屑。"]'),
('5e9992a7-a220-44fb-9f84-116b9de77ed8','偈頌一百一十七首  其八一','釋紹曇','宋','宋诗','song-poetry','','[]','巖桂飄香，井梧凋葉。',64,'全唐诗/poet.song.226000.json','["巖桂飄香，井梧凋葉。", "活祖師機，重重漏洩。", "見得分明眼似眉，道得完全舌如結。", "諸人要知親切句麽，蒲團三月冷如冰，今朝穩坐，靜聽渠分說。"]'),
('f673f500-6906-4fbe-a0d4-1c8f1000c683','偈頌一百一十七首  其八二','釋紹曇','宋','宋诗','song-poetry','','[]','九月九，重陽節。',59,'全唐诗/poet.song.226000.json','["九月九，重陽節。", "不向東籬賞菊花，只點茱萸茶一啜。", "苦澀難嘗舌如㔢，更吞栗棘蓬肝腸裂。", "且道陶淵明，還曾知此味麽。", "莫說莫說。"]'),
('f2539f54-7876-48b5-a98d-c6358ad6f2ac','偈頌一百一十七首  其八三','釋紹曇','宋','宋诗','song-poetry','','[]','九月授衣天，山林無可授。',70,'全唐诗/poet.song.226000.json','["九月授衣天，山林無可授。", "破衲擁殘雲，癡坐蒲團透。", "長慶稜捲簾悟道，病眼見空花。", "香林遠紙襖大書，破袖爭出手。", "鳬短鶴長，馿前馬後，不知笑破他人口。"]'),
('7cab649f-a082-4fbf-bed9-856eaf536afb','偈頌一百一十七首  其八四','釋紹曇','宋','宋诗','song-poetry','','[]','綉閤新添一綫長，金針鬭巧製鴛鴦。',32,'全唐诗/poet.song.226000.json','["綉閤新添一綫長，金針鬭巧製鴛鴦。", "不知這箇長多少，莫把龜毛亂較量。"]'),
('3185a969-80b2-4b7a-995c-852e301abd9c','偈頌一百一十七首  其八五','釋紹曇','宋','宋诗','song-poetry','','[]','要見心珠發耿光，只消一念破慳囊。',32,'全唐诗/poet.song.226000.json','["要見心珠發耿光，只消一念破慳囊。", "昆蟲草木承恩力，世世叢林建法幢。"]'),
('4e5c4082-606e-42c5-b37e-534183f3e678','偈頌一百一十七首  其八六','釋紹曇','宋','宋诗','song-poetry','','[]','十方義聚，和氣如春。',48,'全唐诗/poet.song.226000.json','["十方義聚，和氣如春。", "非魔非佛，無主無賓。", "食法二輪能妙轉，不虛剪月過書雲。", "聞韶不知味，門戶喜重新。"]'),
('fa674408-8ff4-44fb-b532-aa6cb9f29b2e','偈頌一百一十七首  其八七','釋紹曇','宋','宋诗','song-poetry','','[]','當年不合棄金輪，忍凍吞饑度六春。',62,'全唐诗/poet.song.226000.json','["當年不合棄金輪，忍凍吞饑度六春。", "又被毛頭星換眼，至今苦屈未能伸。", "瑞巖不孝，尚有慈心。", "燒塊木頭修薄供，且圖溫飽過，切忌賺他人。"]'),
('1cf2d160-4b8e-4d42-85da-cf13c5f2e497','偈頌一百一十七首  其八八','釋紹曇','宋','宋诗','song-poetry','','[]','兆應豐年，單明一色。',36,'全唐诗/poet.song.226000.json','["兆應豐年，單明一色。", "玉作樓臺，銀連巷陌。", "新晴人喜賀元正，不識春山頭併白。"]'),
('04ac60c5-8668-4bcf-a066-181b2656c970','偈頌一百一十七首  其八九','釋紹曇','宋','宋诗','song-poetry','','[]','茶迎過客無新舊，秤定須彌有重輕。',32,'全唐诗/poet.song.226000.json','["茶迎過客無新舊，秤定須彌有重輕。", "活弄手頭雖得妙，何如聞爆桶箍聲。"]'),
('5a89b466-d9d9-438e-b1b8-2e388ceb0ec5','偈頌一百一十七首  其九○','釋紹曇','宋','宋诗','song-poetry','','[]','今朝二月十五，黄面瞿曇滅度。',48,'全唐诗/poet.song.226000.json','["今朝二月十五，黄面瞿曇滅度。", "諸方撾皷聲冤，盡是閑言長語。", "一點涅槃心，無人知落處。", "山花泪滴如紅雨。"]'),
('94faa413-1b4a-433e-8bde-c3d62c87a31f','偈頌一百一十七首  其九一','釋紹曇','宋','宋诗','song-poetry','','[]','久雨新晴，物情顯煥。',53,'全唐诗/poet.song.226000.json','["久雨新晴，物情顯煥。", "蝶弄海棠陰，鶑啼楊柳岸。", "聲色純真，不得一半。", "堪笑靈雲活眼睛，却被桃花換。", "啞，瞎漢瞎漢。"]'),
('b0ab8f73-88ea-4f17-bcbe-59e2275b6dae','偈頌一百一十七首  其九二','釋紹曇','宋','宋诗','song-poetry','','[]','楊岐栗棘蓬，趙州殿裏底。',28,'全唐诗/poet.song.226000.json','["楊岐栗棘蓬，趙州殿裏底。", "一句當機裂萬差，盡大地人扶不起。"]'),
('630f6340-aebb-4d5d-b293-f037ed584203','偈頌一百一十七首  其九三','釋紹曇','宋','宋诗','song-poetry','','[]','四十年同參，廿餘年相別。',56,'全唐诗/poet.song.226000.json','["四十年同參，廿餘年相別。", "不唱菩薩蠻，何暇說佛法。", "驀劄相逢十二峰，我患生盲你患聾。", "是聖是凡都莫問，且分苔石憩松風。"]'),
('6d0d5c57-831e-4db0-ac63-34d71f5f565e','偈頌一百一十七首  其九四','釋紹曇','宋','宋诗','song-poetry','','[]','客路奔馳歲月深，朝游東魯暮西秦。',32,'全唐诗/poet.song.226000.json','["客路奔馳歲月深，朝游東魯暮西秦。", "子規苦勸人歸去，血濺巖花幾見春。"]'),
('f6558329-23e1-427b-86e1-8facc74cbe1b','偈頌一百一十七首  其九五','釋紹曇','宋','宋诗','song-poetry','','[]','示大家身，爲帝王母。',36,'全唐诗/poet.song.226000.json','["示大家身，爲帝王母。", "與佛同生，福兼寰宇。", "萬國歡悰慶誕彌，蟠桃何止宴瑶池。"]'),
('7f910cb6-944a-4eea-af16-557243c1976b','偈頌一百一十七首  其九六','釋紹曇','宋','宋诗','song-poetry','','[]','九曲河清産聖人，行堯舜道覺斯民。',32,'全唐诗/poet.song.226000.json','["九曲河清産聖人，行堯舜道覺斯民。", "萬邦翹仰垂衣化，皷舞春風賀太平。"]'),
('ab42a204-69d1-4b04-8c51-aa61d4fc0de4','偈頌一百一十七首  其九七','釋紹曇','宋','宋诗','song-poetry','','[]','九旬禁足，困魚止濼。',36,'全唐诗/poet.song.226000.json','["九旬禁足，困魚止濼。", "三月安居，鈍鳥栖蘆。", "圓覺伽藍俱掃迹，釋迦彌勒是他奴。"]'),
('eddf18a4-3605-42f9-ae62-6058491707c7','偈頌一百一十七首  其九八','釋紹曇','宋','宋诗','song-poetry','','[]','筀筍剪龍鬚，山茶烹雀舌。',50,'全唐诗/poet.song.226000.json','["筀筍剪龍鬚，山茶烹雀舌。", "款客話家私，各打鄉談說。", "閩蜀同風，浙音迥別。", "老倒芝峰耳重聽，子規聲訴三更月。"]'),
('998bfb7d-ae4a-4806-86f2-b6119e2f4f85','偈頌一百一十七首  其九九','釋紹曇','宋','宋诗','song-poetry','','[]','傾倒投子油瓶，拗折龍孫頭角。',63,'全唐诗/poet.song.226000.json','["傾倒投子油瓶，拗折龍孫頭角。", "大鑪鞴裏烹煎，香透千巖萬壑。", "殷勤奉供昔年高卧白雲僧，與無舌人從頭咬嚼。", "咬得著，鼓舞昇平，唱村田樂。"]'),
('35461ca4-c48f-41f8-8d7d-6cae1a967df0','偈頌一百一十七首  其一○○','釋紹曇','宋','宋诗','song-poetry','','[]','跨弄蹄馿，住疎壁院，千古遺風今再見。',52,'全唐诗/poet.song.226000.json','["跨弄蹄馿，住疎壁院，千古遺風今再見。", "吞吐何須栗棘蓬，煅煉已成丹九轉。", "傾出瓶壺，寒光閃電，扶危妙在通權變。"]'),
('0bdf3797-2002-4a74-a7cc-53e922580f22','偈頌一百一十七首  其一○一','釋紹曇','宋','宋诗','song-poetry','','[]','九旬禁足已嫌多，那更重加一月遥。',32,'全唐诗/poet.song.226000.json','["九旬禁足已嫌多，那更重加一月遥。", "不解六根門互用，蠟人鐵做也應消。"]'),
('65220523-6b74-4d23-b4e9-6231ef8b898f','偈頌一百一十七首  其一○二','釋紹曇','宋','宋诗','song-poetry','','[]','八月秋，何處熱。',34,'全唐诗/poet.song.226000.json','["八月秋，何處熱。", "塞鴈來賓，井梧凋葉。", "衲僧拄杖知時節，千里萬里一條鐵。"]'),
('35691cef-a933-481d-af31-bcc34e377e40','偈頌一百一十七首  其一○三','釋紹曇','宋','宋诗','song-poetry','','[]','監本祖庭花，東西爭擢秀。',42,'全唐诗/poet.song.226000.json','["監本祖庭花，東西爭擢秀。", "一等放清香，不分新與舊。", "枝枝葉葉，陡頓精神，粧點芝園劫外春。"]'),
('ff1a413a-460d-46a7-a99c-b20db720f8fa','偈頌一百一十七首  其一○四','釋紹曇','宋','宋诗','song-poetry','','[]','秋菊鋪黄，茱萸裛翠。',46,'全唐诗/poet.song.226000.json','["秋菊鋪黄，茱萸裛翠。", "彭澤淵明，清吟濁醉。", "一年一度賞東籬，蹉過重陽總不知。", "因甚如此，逐物意移。"]'),
('9f857c5d-2eaf-4da7-94c3-693f7d39348c','偈頌一百一十七首  其一○五','釋紹曇','宋','宋诗','song-poetry','','[]','䆉稏黄雲，精神玉粒。',54,'全唐诗/poet.song.226000.json','["䆉稏黄雲，精神玉粒。", "熟知稼穡人，著意勤收拾，已收拾，舂石墜腰，炊香滿室。", "客來唱曲賀豐年，撫髀清歡，莫嫌貧極。"]'),
('a5f2df82-088b-4b57-8461-0c019a6ce55b','偈頌一百一十七首  其一○六','釋紹曇','宋','宋诗','song-poetry','','[]','楊岐馿弄蹄，天衣雁沉影。',82,'全唐诗/poet.song.226000.json','["楊岐馿弄蹄，天衣雁沉影。", "兩個老無知，語不分邪正。", "何似火爐頭話，無主無賓。", "是非審定，不違法印。", "我王庫內豈有是刀哉，古今多少人以橘皮爲火，紛然錯認。", "啞，死灰煨殺誰深省。"]'),
('63256aaf-1f85-4e94-ab75-aaf87e93af97','偈頌一百一十七首  其一○七','釋紹曇','宋','宋诗','song-poetry','','[]','航海而來，面壁而坐。',54,'全唐诗/poet.song.226000.json','["航海而來，面壁而坐。", "未明直指單傳，先被梁王勘破。", "當門齒露風，隻履歸何早。", "熊耳峰前，纍纍荒草，至今惹得行人笑。"]'),
('4895349d-6bcc-4ec1-a50f-840e2cda94ca','偈頌一百一十七首  其一○八','釋紹曇','宋','宋诗','song-poetry','','[]','昨宵送舊，今日迎新。',52,'全唐诗/poet.song.226000.json','["昨宵送舊，今日迎新。", "迎新送舊，費盡精神。", "新舊兩頭忘記了，始知今日是元正。", "不用借婆衫子拜，今年人是去年人。"]'),
('e5cdd553-5226-459d-8122-1c55bee4e318','偈頌一百一十七首  其一○九','釋紹曇','宋','宋诗','song-poetry','','[]','貧苦芝峰，賞元宵節。',91,'全唐诗/poet.song.226000.json','["貧苦芝峰，賞元宵節。", "宴樂佳賓，將何鋪設。", "明挑海底燈，細剪亭前月。", "打拍東山瓦皷歌，掤八剌札，樂有餘，清不徹。", "趣味森嚴，恰似趙州，曾到未到，喫盃盃茶，洞山生姜不改辣。", "啞，不是知心向誰說。"]'),
('05013fd1-15c1-49a9-8adf-4bf1530e5423','偈頌一百一十七首  其一一○','釋紹曇','宋','宋诗','song-poetry','','[]','二月十五，瞿曇滅度。',72,'全唐诗/poet.song.226000.json','["二月十五，瞿曇滅度。", "山鳥悲春，山花泣雨。", "盡大地人，有屈無伸處。", "獨有瑞巖拄杖子，鐵作心腸渾不顧。", "唱太平歌，歡聲滿路。", "因甚如此，殲厥渠魁，澄清寰宇。"]'),
('8061e281-a0e6-4dd6-bcbb-d8a5a00ca2f9','偈頌一百一十七首  其一一一','釋紹曇','宋','宋诗','song-poetry','','[]','浴乎沂，舞雩歸。',46,'全唐诗/poet.song.226000.json','["浴乎沂，舞雩歸。", "道存目擊，樂以忘機。", "嗟歎奔馳途路客，拋家失業有誰知。", "杜鵑啼出血，勸得幾人歸。"]'),
('7318f6cf-013b-4c73-9356-f20e14b59078','偈頌一百一十七首  其一一二','釋紹曇','宋','宋诗','song-poetry','','[]','薄福值荒年，日餐三頓粥。',77,'全唐诗/poet.song.226000.json','["薄福值荒年，日餐三頓粥。", "兩眼挂青山，真味填枵腹。", "貧有餘，樂不足。", "誰管古人見延壽不見延壽，山前麥熟與未熟。", "無事巖泉洗耳聽，幽禽巧奏陽春曲。", "好大哥，快活快活。"]'),
('c4d21886-a307-4ead-bf90-a0e9c6f73c90','偈頌一百一十七首  其一一三','釋紹曇','宋','宋诗','song-poetry','','[]','五髻峰頭，怨憎會苦。',84,'全唐诗/poet.song.226000.json','["五髻峰頭，怨憎會苦。", "熱血相噴，重重染污。", "箇樣老妖魔，慚愧今朝死。", "粗茶一甌，粗香一炷，供養阿儂。", "願百劫千生，驀劄相逢，好眼看承，好心攀顧。", "切莫重行巇險路，背後恐遭人指註。"]'),
('6e619e73-2707-4a51-a347-7d739661242b','偈頌一百一十七首  其一一四','釋紹曇','宋','宋诗','song-poetry','','[]','大地全荒總不憂，奪饑人食縛耕牛。',32,'全唐诗/poet.song.226000.json','["大地全荒總不憂，奪饑人食縛耕牛。", "衲僧舉止合如是，百煉精金肯博鍮。"]'),
('26ee5964-e740-4e76-b9bc-b99d1c5313e1','偈頌一百一十七首  其一一五','釋紹曇','宋','宋诗','song-poetry','','[]','撈摝群迷，示生五濁。',38,'全唐诗/poet.song.226000.json','["撈摝群迷，示生五濁。", "臭穢通身，如何洗却。", "百滾洋銅澆一杓，徹骨清凉，快活快活。"]'),
('31f210dc-5324-43bb-a2b1-65a378d5d4cf','偈頌一百一十七首  其一一六','釋紹曇','宋','宋诗','song-poetry','','[]','六年償債芝峰寺，費盡衣盂用盡心。',32,'全唐诗/poet.song.226000.json','["六年償債芝峰寺，費盡衣盂用盡心。", "今日杖藜行活路，笑看花木媚清陰。"]'),
('ef0a1b75-719a-43a6-8062-76eda3566ac7','偈頌十九首  其一','釋紹曇','宋','宋诗','song-poetry','','[]','草舍開張小小筵，炊無米飯爨無烟。',32,'全唐诗/poet.song.226000.json','["草舍開張小小筵，炊無米飯爨無烟。", "通身飽暖憨憨睡，夢到滄洲白鳥邊。"]'),
('2ff3b303-0270-4c69-94b5-a2d91df1b719','偈頌十九首  其二','釋紹曇','宋','宋诗','song-poetry','','[]','宮花壓鬢墜烏雲，傾國風流宛勝秦。',32,'全唐诗/poet.song.226000.json','["宮花壓鬢墜烏雲，傾國風流宛勝秦。", "玉笛插藏人不見，夜深吹起鳳樓春。"]'),
('bf8c8c0a-7f0d-44ee-9e99-f5c4c72f6de5','偈頌十九首  其三','釋紹曇','宋','宋诗','song-poetry','','[]','萬里無寸草，出門便是草。',24,'全唐诗/poet.song.226000.json','["萬里無寸草，出門便是草。", "支筇寂寞中，望斷無人到。"]'),
('d8932187-fc4f-4e5f-b80f-dbb65be0f57d','偈頌十九首  其四','釋紹曇','宋','宋诗','song-poetry','','[]','槽廠安身不記年，一心希慕嶺南能。',32,'全唐诗/poet.song.226000.json','["槽廠安身不記年，一心希慕嶺南能。", "肩頭颺下潑柴擔，要汝來傳佛祖燈。"]'),
