('41d75eff-5151-4c4f-b333-2d0c6060c7b8','王鞔鼓','釋紹曇','宋','宋诗','song-poetry','','[]','鼓兩片皮謾自己，一回拈出一回新。',32,'全唐诗/poet.song.226000.json','["鼓兩片皮謾自己，一回拈出一回新。", "揭天聲響疑塗毒，自有臨風側耳人。"]'),
('cd78dee0-0a38-490d-b9af-1221e0e04487','矮道者','釋紹曇','宋','宋诗','song-poetry','','[]','身如椰子口宏開，看盡諸方鬼戲來。',32,'全唐诗/poet.song.226000.json','["身如椰子口宏開，看盡諸方鬼戲來。", "放一頭低人不識，疎山師叔是同胎。"]'),
('c81d531b-4bd8-4f54-9619-3fca2415e887','鄰峰艮上人  其一','釋紹曇','宋','宋诗','song-poetry','','[]','四十餘年別故鄉，夢魂時復到藏王。',32,'全唐诗/poet.song.226000.json','["四十餘年別故鄉，夢魂時復到藏王。", "春風九曲溪頭寺，桃花翻霞柳弄黄。"]'),
('83bd868d-bbda-453a-821e-f8b74bfaebaf','鄰峰艮上人  其二','釋紹曇','宋','宋诗','song-poetry','','[]','短筇扶瘦扣烟蘿，款問東山瓦皷歌。',32,'全唐诗/poet.song.226000.json','["短筇扶瘦扣烟蘿，款問東山瓦皷歌。", "老倦不能謳唱得，隔窗幽鳥語尤多。"]'),
('5b7f024f-6ac6-4f84-9e52-d3185ea9fb2b','璉監寺  其一','釋紹曇','宋','宋诗','song-poetry','','[]','烹金爐裏脫胚腪，妙斲初無斧鑿痕。',32,'全唐诗/poet.song.226000.json','["烹金爐裏脫胚腪，妙斲初無斧鑿痕。", "汝質自成瑚璉器，我儂甘作破沙盆。"]'),
('5f5e01e1-0c02-4dd9-b892-47c50745c1c9','璉監寺  其二','釋紹曇','宋','宋诗','song-poetry','','[]','曾把楊岐破屋撐，閑騎馿子弄蹄行。',32,'全唐诗/poet.song.226000.json','["曾把楊岐破屋撐，閑騎馿子弄蹄行。", "犯寒踏月慈溪上，冷笑梅兄太瘦生。"]'),
('9316a5df-2948-4d86-87ca-5034b74cac11','日本澄上人','釋紹曇','宋','宋诗','song-poetry','','[]','掃盡機緣萬法空，澄潭不許卧蒼龍。',32,'全唐诗/poet.song.226000.json','["掃盡機緣萬法空，澄潭不許卧蒼龍。", "翻身踏斷來時路，家在海山雲外峰。"]'),
('7905482d-cd25-42f5-bf14-584342532902','日本然上人  其一','釋紹曇','宋','宋诗','song-poetry','','[]','橫擔楖𣗖走諸方，佛祖玄關路轉長。',32,'全唐诗/poet.song.226000.json','["橫擔楖𣗖走諸方，佛祖玄關路轉長。", "放下身心歸故隠，金烏依舊出扶桑。"]'),
('87a831f8-5697-4569-85fd-70e207e2042b','日本然上人  其二','釋紹曇','宋','宋诗','song-poetry','','[]','奔趨客路困塵泥，蟻夢方酣蝶夢飛。',32,'全唐诗/poet.song.226000.json','["奔趨客路困塵泥，蟻夢方酣蝶夢飛。", "頼有啼鵑知此意，一聲聲勸不如歸。"]'),
('a310c952-afe1-41e5-9b86-e27541a739ab','化城山主化田','釋紹曇','宋','宋诗','song-poetry','','[]','古柳堤邊展化機，要人一飽便忘饑。',32,'全唐诗/poet.song.226000.json','["古柳堤邊展化機，要人一飽便忘饑。", "誰將奪食驅耕手，拚却良田種蒺藜。"]'),
('9ef6a97a-edf8-4d59-9270-2cf5de695caf','人我擔','釋紹曇','宋','宋诗','song-poetry','','[]','骨露皮穿未肯休，冥機蠻觸戰蝸牛。',32,'全唐诗/poet.song.226000.json','["骨露皮穿未肯休，冥機蠻觸戰蝸牛。", "一肩人我都擔了，遍界從教是髑髏。"]'),
('fb94b851-1eee-40a1-aadf-65c44c6d59d5','慧禪人','釋紹曇','宋','宋诗','song-poetry','','[]','翠織岷峨錦綉春，堪嗟撲撲蔽胡塵。',32,'全唐诗/poet.song.226000.json','["翠織岷峨錦綉春，堪嗟撲撲蔽胡塵。", "金鷄銜粟餘殃在，誰繼神駒踏殺人。"]'),
('28c73bc9-52e6-4d1e-abcf-a8efef4fbe40','從禪人','釋紹曇','宋','宋诗','song-poetry','','[]','臨濟陰凉樹已枯，片無霜葉擁禪趺。',32,'全唐诗/poet.song.226000.json','["臨濟陰凉樹已枯，片無霜葉擁禪趺。", "兒孫不解澆培得，翫作山門境致圖。"]'),
('56a379ee-46e3-4ea2-a69c-5364cc821bd4','寧藏主省師兄求語','釋紹曇','宋','宋诗','song-poetry','','[]','橘州文學石橋書，妙畫雄才舉世無。',112,'全唐诗/poet.song.226000.json','["橘州文學石橋書，妙畫雄才舉世無。", "宗說俱通心眼活，奇哉老蚌出雙珠。", "百年凜有遺風烈，行處同途不同轍。", "癡翁真得虎頭癡，月峰清照峨嵋月。", "分飛雁影各東西，幾對秋風歎離別。", "去去吳天浄如洗，淡墨聯書形字義。", "且教人道渠和儂，好對難兄與難弟。"]'),
('b39e4872-c445-48c1-89d0-b4e1a3947ff9','緣侍者之浙右','釋紹曇','宋','宋诗','song-poetry','','[]','一本潼川花瑞菜，全蜀知名誰不愛。',128,'全唐诗/poet.song.226000.json','["一本潼川花瑞菜，全蜀知名誰不愛。", "夜雨叢凝色染藍，春風花噀香如麝。", "不知何處得靈根，栽遍牛頭山後前。", "古佛低頭看不厭，聲聞鼻孔被渠穿。", "上人携種游江浙，味與首陽薇不別。", "伏虎巖前清客嘗，老饕嚼斷娘生舌。", "餘香分餉老芝峰，彷彿家園小摘同。", "此去零星休賣弄，珍藏大作蘇陀供。"]'),
('96513af3-b73b-4546-88b9-6553a0eac5f6','觀知客歸葬親求語','釋紹曇','宋','宋诗','song-poetry','','[]','道人觀方知彼去，入門要驗賓中主。',96,'全唐诗/poet.song.226000.json','["道人觀方知彼去，入門要驗賓中主。", "喫一杯茶即轉身，誰能掉舌論今古。", "危機俊逸旱雷轟，蒼鷹折翅獵狗烹。", "老明覺舉手加額，韓大伯敢攙先行。", "秋深撥草天台路，靈骨要尋親父母。", "破钁頭邊掘窖埋，斷猿哭月風號樹。"]'),
('b5f7434b-3716-4086-a00e-9b1be7f7d017','律宗玉維那三人禮石佛求語','釋紹曇','宋','宋诗','song-poetry','','[]','老倒南山犯真律，三生鑿破寒巖石。',96,'全唐诗/poet.song.226000.json','["老倒南山犯真律，三生鑿破寒巖石。", "不立名中强立名，弗狼籍處成狼籍。", "兒孫膝下有黄金，撥草瞻風遠訪尋。", "三拜起來發一嘆，方知老子錯留心。", "天真自性佛不管，頑石頭邊討甚椀。", "費盡鉗鎚多破綻，烏藤緊捉從頭看。"]'),
('e0da7f6a-0af0-4930-a3b1-046ae49ae5a4','妙恩侍者求語','釋紹曇','宋','宋诗','song-poetry','','[]','一奩春錦鬭鮮明，較古菱花越樣清。',32,'全唐诗/poet.song.226000.json','["一奩春錦鬭鮮明，較古菱花越樣清。", "照影不應呼小玉，至今湖海客關情。"]'),
('4cc15e99-ef71-4aa9-a5f9-78d12359f9f7','又省師','釋紹曇','宋','宋诗','song-poetry','','[]','逴得諸方惡毒些，歸尋刻骨舊冤家。',32,'全唐诗/poet.song.226000.json','["逴得諸方惡毒些，歸尋刻骨舊冤家。", "深深掘窖都埋了，翻鐵面皮誰識爺。"]'),
('562f9523-1a4d-453d-b579-ff8ba1ca5808','鄱陽恭上人求語','釋紹曇','宋','宋诗','song-poetry','','[]','鄱陽風鼓浪千尋，徹底探窮不顧身。',32,'全唐诗/poet.song.226000.json','["鄱陽風鼓浪千尋，徹底探窮不顧身。", "塔主連聲呼莫莫，截流機峻恐驚人。"]'),
('4ed00f97-4516-494e-a697-6a640fe02352','靈叟小師悟垓侍者求語','釋紹曇','宋','宋诗','song-poetry','','[]','碧落一碑無贋本，非草非真非隸篆。',128,'全唐诗/poet.song.226000.json','["碧落一碑無贋本，非草非真非隸篆。", "鏡樣渝江徹底清，字義炳然人少見。", "靈叟珍藏歲月深，南來吳越人爭尋。", "瘞鶴銘辭匪同調，寒山詩句非知音。", "紛紛問字誰親切，勾不成勾丿不丿。", "爭得盧公賽子雲，一肩擔荷柴衝折。", "臨行密付阿誰邊，妙處休云子不傳。", "索性掃除元字脚，義天雲浄月孤玄。"]'),
('dff0daf0-ad16-4477-ab2f-58f244a10afb','簡州性上人求語','釋紹曇','宋','宋诗','song-poetry','','[]','春山杜鵑啼，苦勸人歸去。',120,'全唐诗/poet.song.226000.json','["春山杜鵑啼，苦勸人歸去。", "聲碎竹林風，血染花梢雨。", "我老無家可得歸，蘿窗睡飽雲黏衣。", "山童推枕破殘夢，報道有僧開竹扉。", "何方聖者來尋討，解包颺下青龍鈔。", "便欲庭前縱火焚，浄地豈容狼藉了。", "問渠何日離飛來，兩月奔馳未到家。", "好勸急歸休歇去，春風落盡武林花。"]'),
('1ca9cc9f-5b47-49e3-9088-f5d392b1ca89','周上人求語','釋紹曇','宋','宋诗','song-poetry','','[]','憶昔周當仁，手握金剛杵。',120,'全唐诗/poet.song.226000.json','["憶昔周當仁，手握金剛杵。", "憤氣向南方，誓滅諸魔子。", "老婆驀劄點三心，走入龍潭恨轉深。", "掃蕩家私無一窖，胡揮白棒到平人。", "牧閒冷坐思高躅，斷絃爭得鸞膠續。", "扣門聽得簡州人，倒屐相迎幾折足。", "略寒溫外問來端，叉手丁寧覓指南。", "未舉紙燈明說了，隔窗春鳥語綿蠻。"]'),
('4e070a78-dfdf-4e03-84db-fd28264750fe','西水浄土庵奉寄具足孤松老師','釋紹曇','宋','宋诗','song-poetry','','[]','聞道虛空曾解講，信疑往決西山亮。',128,'全唐诗/poet.song.226000.json','["聞道虛空曾解講，信疑往決西山亮。", "烟雨溟濛蘚石溫，六藏影跡難尋訪。", "小徑披榛扣竹扉，道人一見笑掀眉。", "布衲橫肩瘦如削，口持密語沒停時。", "雲簷掃榻延居夏，白蓮香散東林社。", "澗水松風說苦空，不資中有生清泰。", "殷勤寄問老孤松，具足門中有正宗。", "灼然嫌佛不肯做，鳳栖不在梧桐樹。"]'),
('346438f0-785d-4c34-ac1c-e8322587289b','爲叔向題坐禪蝦蟆','釋紹曇','宋','宋诗','song-poetry','','[]','一從識得性分明，懶作春池鼓吹聲。',32,'全唐诗/poet.song.226000.json','["一從識得性分明，懶作春池鼓吹聲。", "閑把六根門鎖斷，白蓮香散水風清。"]'),
('027f19b9-0314-4ccd-852d-28a40757d5bd','題直夫牛圖','釋紹曇','宋','宋诗','song-poetry','','[]','三三五五戲平蕪，踏裂春風百草枯。',32,'全唐诗/poet.song.226000.json','["三三五五戲平蕪，踏裂春風百草枯。", "莫寫溈山僧某甲，恐人誤作祖師圖。"]'),
('7425e03e-9fea-461a-953a-96eee713d823','題老融猿','釋紹曇','宋','宋诗','song-poetry','','[]','危坐禪枝冷，機含毒果深。',24,'全唐诗/poet.song.226000.json','["危坐禪枝冷，機含毒果深。", "直饒捫摸著，未必死偷心。"]'),
('cfdec78e-f90b-49f4-98e2-193370ccd6f4','題圓澤圖','釋紹曇','宋','宋诗','song-poetry','','[]','月下騎寒犢，三生事細論。',24,'全唐诗/poet.song.226000.json','["月下騎寒犢，三生事細論。", "已遭人點檢，休弄鬼精魂。"]'),
('7e4d9fd7-8a58-4888-9053-771ca669ebce','題拗韁牛','釋紹曇','宋','宋诗','song-poetry','','[]','隴樹冥冥日向西，苦貪芳草不知歸。',32,'全唐诗/poet.song.226000.json','["隴樹冥冥日向西，苦貪芳草不知歸。", "牧童盡力拽得轉，在在暝烟深翠微。"]'),
('5b661856-eae4-4ece-8b14-31b1ba1577ae','坦老求題真歇宏智竹庵同遊雁山酬唱真蹟軸後','釋紹曇','宋','宋诗','song-poetry','','[]','天生三箇老冤魔，狹路相逢沒柰何。',32,'全唐诗/poet.song.226000.json','["天生三箇老冤魔，狹路相逢沒柰何。", "□把肚腸摟抉看，曲於四十九盤多。"]'),
('4d7ca79a-6a85-4787-9722-7dff0577c098','題放山堂','釋紹曇','宋','宋诗','song-poetry','','[]','一擊牢關八字開，石頭機路滑如苔。',32,'全唐诗/poet.song.226000.json','["一擊牢關八字開，石頭機路滑如苔。", "危分險布知多少，排闥從渠輥入來。"]'),
('31cbdb2e-feea-4ac5-9046-d6b1d1d32686','杜甫騎馿遊春圖','釋紹曇','宋','宋诗','song-poetry','','[]','客路如天遠，吟身太瘦生。',24,'全唐诗/poet.song.226000.json','["客路如天遠，吟身太瘦生。", "無家歸未得，策蹇傍春行。"]'),
('d8107492-0b7c-4f78-aacf-46532bd3272f','李白醉騎馿圖','釋紹曇','宋','宋诗','song-poetry','','[]','酒渴思鯨飲，金鸞早退朝。',24,'全唐诗/poet.song.226000.json','["酒渴思鯨飲，金鸞早退朝。", "醉身扶不起，壓折老馿腰。"]'),
('c50c97d9-1194-43c4-8431-f4dde02a9965','題秋堂四蘭  其一','釋紹曇','宋','宋诗','song-poetry','','[]','指玉彈曉，喙檀噀春。',20,'全唐诗/poet.song.226000.json','["指玉彈曉，喙檀噀春。", "倏爾生妬，陰飈不仁。"]'),
('b71a4951-394a-49b5-8c4c-b50a659d4197','題秋堂四蘭  其二','釋紹曇','宋','宋诗','song-poetry','','[]','湘英整佩，楚衣告紉。',20,'全唐诗/poet.song.226000.json','["湘英整佩，楚衣告紉。", "羲黄薦馥，采采疑真。"]'),
('737aaf6d-00f6-42d1-8ae5-cc2eb1319f1c','題秋堂四蘭  其三','釋紹曇','宋','宋诗','song-poetry','','[]','紛披佩玉，仆委苔痕。',20,'全唐诗/poet.song.226000.json','["紛披佩玉，仆委苔痕。", "簷花寫恨，難拈楚魂。"]'),
('d8adc170-de73-4468-9d34-141272fe12a7','題秋堂四蘭  其四','釋紹曇','宋','宋诗','song-poetry','','[]','幽石封白，深林掩芳。',20,'全唐诗/poet.song.226000.json','["幽石封白，深林掩芳。", "隠德不耀，何矜色香。"]'),
('0eff6d07-8da6-46b2-a646-970b528a2e33','題蘭蕙  其一','釋紹曇','宋','宋诗','song-poetry','','[]','色淡而清，節香而貞。',44,'全唐诗/poet.song.226000.json','["色淡而清，節香而貞。", "隠德不耀，咀華含英。", "君子同其芳潔，寫真不墮丹青。", "宜乎孕瀟湘幽楚之靈。"]'),
('147d0980-ad68-4a2f-8ccb-ae7683e59eea','題蘭蕙  其二','釋紹曇','宋','宋诗','song-poetry','','[]','一莖四花，挺然拔萃。',48,'全唐诗/poet.song.226000.json','["一莖四花，挺然拔萃。", "其臭如蘭，其標如芷。", "檀喙簇烟而不繁，勁節疾風而不倚。", "是以昂山有山林軒昂之志。"]'),
('a8ad7cdb-d59c-4b7b-9b75-e5603e2abac1','題四蘭  其一','釋紹曇','宋','宋诗','song-poetry','','[]','深藏巖谷裡，初不要人知。',24,'全唐诗/poet.song.226000.json','["深藏巖谷裡，初不要人知。", "苦是香難掩，春風得意吹。"]'),
('13d0cc59-abc9-438e-8b69-7104415e3c4b','題四蘭  其二','釋紹曇','宋','宋诗','song-poetry','','[]','喜晴彈玉指，林下見幽人。',24,'全唐诗/poet.song.226000.json','["喜晴彈玉指，林下見幽人。", "楚楚湘靈樣，肌膚不染塵。"]'),
('23f87a8d-b2ec-4b2d-9cc8-17f59b907e8c','題四蘭  其三','釋紹曇','宋','宋诗','song-poetry','','[]','珮玉半零亂，繄誰吊楚英。',24,'全唐诗/poet.song.226000.json','["珮玉半零亂，繄誰吊楚英。", "醉香魂未返，愁聽打蓬聲。"]'),
('b535a76d-0393-4bd3-a53b-2cfb8bf63d83','題四蘭  其四','釋紹曇','宋','宋诗','song-poetry','','[]','一再荒林雪，全身掩薜蘿。',24,'全唐诗/poet.song.226000.json','["一再荒林雪，全身掩薜蘿。", "直饒埋沒得，爭柰鼻頭何。"]'),
('77651b2e-41e4-4c77-afa4-99620b83f0b5','題秋堂四蘭  其一','釋紹曇','宋','宋诗','song-poetry','','[]','靈均侈山林之樂，薄籠綃袴，幽放檀心。',31,'全唐诗/poet.song.226000.json','["靈均侈山林之樂，薄籠綃袴，幽放檀心。", "嬌舞春風身醉香，力難扶也。"]'),
('19c5d08f-77e4-4b4a-87e7-f585eae6e582','題秋堂四蘭  其二','釋紹曇','宋','宋诗','song-poetry','','[]','久居深林幽寂中，雖隠德不耀。',50,'全唐诗/poet.song.226000.json','["久居深林幽寂中，雖隠德不耀。", "遇春陽姁嫗，笑彈玉指，十倍精神。", "所慮楚俗尚芳，紉而爲佩，使不克終其天矣。"]'),
('79d6d6f2-689e-4f55-905e-c896a9aab6b1','題秋堂四蘭  其三','釋紹曇','宋','宋诗','song-poetry','','[]','娥英吊舜於九疑，泣泪如雨。',44,'全唐诗/poet.song.226000.json','["娥英吊舜於九疑，泣泪如雨。", "珮玉零亂，半委塵泥。", "愚恐離騷九歌，曲盡其哀，香魂冷而卒難拈也。"]'),
('8c6ef76e-0ea4-49e0-ac11-41bcd44736b4','題秋堂四蘭  其四','釋紹曇','宋','宋诗','song-poetry','','[]','大雪申威，萬木摧拉，獨能擢芳於凝沍中，雖百折不委。',41,'全唐诗/poet.song.226000.json','["大雪申威，萬木摧拉，獨能擢芳於凝沍中，雖百折不委。", "非素有所養，寧不爲外侮憑凌者歟。"]'),
('4df5626c-9c6b-4c37-a3d9-6503a5993eb1','爲丘桂巖司門題和靖雪後看梅圖','釋紹曇','宋','宋诗','song-poetry','','[]','破曉湖山入畫時，短篷摇雪傍疏籬。',32,'全唐诗/poet.song.226000.json','["破曉湖山入畫時，短篷摇雪傍疏籬。", "一心只在梅花上，凍損吟身也不知。"]'),
