('acdcce60-f045-4e6f-a30e-e282aea19876','賀友山新建東皋接待','釋紹曇','宋','宋诗','song-poetry','','[]','分袂南湖十數春，近聞華搆策奇勳。',64,'全唐诗/poet.song.226000.json','["分袂南湖十數春，近聞華搆策奇勳。", "鉢從金粟摶香飯，僧自東皋接水雲。", "柔玉新拳春塢蕨，嬾黄新縷曉溪芹。", "定應容我分陳榻，曝背晴簷醉夕曛。"]'),
('5dc8812a-f833-4860-80d5-5dd64ba76e68','禮雲門千歲塔','釋紹曇','宋','宋诗','song-poetry','','[]','越山清絕無塵翳，不到胡僧取次埋。',32,'全唐诗/poet.song.226000.json','["越山清絕無塵翳，不到胡僧取次埋。", "輒莫更加千歲壽，也須和骨洗將來。"]'),
('c84760f4-7718-4f3a-b5f5-bd07cd970f44','梅窗','釋紹曇','宋','宋诗','song-poetry','','[]','溢目湖山看不足，引清吟有此雲房。',64,'全唐诗/poet.song.226000.json','["溢目湖山看不足，引清吟有此雲房。", "簷牙掛月橫疎影，隙眼通風度暗香。", "夜掩只疑和靖宅，曉開爭看壽陽粧。", "蘭兄礬弟休相憐，斗室難爲納衆芳。"]'),
('5ead0f21-4159-4967-94e8-76f869b228ba','隠秀','釋紹曇','宋','宋诗','song-poetry','','[]','觸戰蠻征總不知，樂羲皇世遯嘉肥。',64,'全唐诗/poet.song.226000.json','["觸戰蠻征總不知，樂羲皇世遯嘉肥。", "馨香靜掩芝蘭室，文采深藏錦綉機。", "伴野僧眠嵩少石，汲蒙泉煮首陽薇。", "簞瓢飫味□貧趣，爭得紅塵染著衣。"]'),
('90475c79-9b4a-4199-886e-227ebbe07834','竹雲','釋紹曇','宋','宋诗','song-poetry','','[]','春錦千綳玉萬竿，嵐光翠裛渭川寒。',32,'全唐诗/poet.song.226000.json','["春錦千綳玉萬竿，嵐光翠裛渭川寒。", "油然已作從龍勢，只恐仙陂化蟄難。"]'),
('5766da94-73cb-4d92-acd0-063b888993de','王庵和劉府教','釋紹曇','宋','宋诗','song-poetry','','[]','鹿眠芳草印春庭，月掛蘿窗曉半扃。',32,'全唐诗/poet.song.226000.json','["鹿眠芳草印春庭，月掛蘿窗曉半扃。", "白髮老僧偏愛客，忍寒同看換鵝經。"]'),
('27447624-d484-45c7-94c3-b5222b286879','游九峰','釋紹曇','宋','宋诗','song-poetry','','[]','攀石捫蘿入杳冥，凌虛潜覺膽魂驚。',96,'全唐诗/poet.song.227000.json','["攀石捫蘿入杳冥，凌虛潜覺膽魂驚。", "陰崖擷瀑瑶花碎，枯葉翻霜錦樹榮。", "汲水僧歸龍洞去，采薇人踏虎蹤行。", "風流二老遺音在，度曲松濤萬壑清。", "雙磵奔流戰玉龍，浮屠雲鎖翠千重。", "只將一疏傳天下，大覺馿年識九峰。"]'),
('67794cb5-6da6-4080-8da0-92fd0ce3245d','清凉禮先師遺像','釋紹曇','宋','宋诗','song-poetry','','[]','白雲迷谷雪鋪階，老倒清凉眼著沙。',32,'全唐诗/poet.song.227000.json','["白雲迷谷雪鋪階，老倒清凉眼著沙。", "若問普通年遠事，三千里外摘楊花。"]'),
('3b5e6a9d-4668-4380-b87b-a82e3b363f0d','興化寺','釋紹曇','宋','宋诗','song-poetry','','[]','門照雙池鏡樣明，東西廊喝寂無聲。',32,'全唐诗/poet.song.227000.json','["門照雙池鏡樣明，東西廊喝寂無聲。", "紫羅帳裏機玄密，雖有珍珠撒未成。"]'),
('4064ce57-634c-4b26-bd43-2325251c25f2','焙經','釋紹曇','宋','宋诗','song-poetry','','[]','老胡監本誑人天，開口無非吐黑烟。',32,'全唐诗/poet.song.227000.json','["老胡監本誑人天，開口無非吐黑烟。", "五熱炙身甘自受，要翻元款待馿年。"]'),
('48951159-b475-4740-9f6d-ec35cb8e859b','爲惟翁題非畫圖','釋紹曇','宋','宋诗','song-poetry','','[]','誤入蓬壺影裏游，諭盟白鳥下滄洲。',64,'全唐诗/poet.song.227000.json','["誤入蓬壺影裏游，諭盟白鳥下滄洲。", "吞波島嶼鰲身黑，映日樓臺蜃氣浮。", "門逆潮開喧海市，網沿堤晒簇漁舟。", "晦明晴雨時時別，難把王維腕力收。"]'),
('1594ddf1-1e2c-4a73-ad98-20924d7425be','登金峨峰頂','釋紹曇','宋','宋诗','song-poetry','','[]','撥開空翠上危顛，路遶羊腸石齒尖。',64,'全唐诗/poet.song.227000.json','["撥開空翠上危顛，路遶羊腸石齒尖。", "到頂方知天下小，攀高似取世人嫌。", "碧連蓬島雲千疊，冷照東溟鏡一奩。", "歸去松窗伴禪老，此山佳致話無厭。"]'),
('e840c39f-c49b-463c-a6ed-60b508edd82d','爲聖俞頌橘巖','釋紹曇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭秋晚半青黄，須待霜林熟自香。',32,'全唐诗/poet.song.227000.json','["洞庭秋晚半青黄，須待霜林熟自香。", "不向懸崖親撒手，認皮作火錯承當。"]'),
('c035bc85-efb1-47c7-904e-dd1d642b9b5c','聞竺寺迎號服因成口號  其一','釋紹曇','宋','宋诗','song-poetry','','[]','絲管紛紛鼓亂撾，兩山迎接賜衣來。',32,'全唐诗/poet.song.227000.json','["絲管紛紛鼓亂撾，兩山迎接賜衣來。", "白雲恐污山翁耳，重鎖柴門不放開。"]'),
('af36e91b-c6c2-44b7-a1f0-db9b1b57d526','聞竺寺迎號服因成口號  其二','釋紹曇','宋','宋诗','song-poetry','','[]','祖庭秋晚日增悲，見得芙蓉便展眉。',32,'全唐诗/poet.song.227000.json','["祖庭秋晚日增悲，見得芙蓉便展眉。", "不與狂花爭瑣細，淄川緣有拒霜枝。"]'),
('6c0d8d96-c697-4741-a4c8-d36449ce85a6','六言山居  其一','釋紹曇','宋','宋诗','song-poetry','','[]','野菜花飛胡蝶，古藤枝挂清猿。',28,'全唐诗/poet.song.227000.json','["野菜花飛胡蝶，古藤枝挂清猿。", "閑倚柴門看倦，枕肱高卧雲根。"]'),
('3f8a2dbc-0404-4363-8d2a-5a09d53e32ec','六言山居  其二','釋紹曇','宋','宋诗','song-poetry','','[]','積雪封無過路，亂雲堆滿空庭。',28,'全唐诗/poet.song.227000.json','["積雪封無過路，亂雲堆滿空庭。", "我也誰能掃得，掩關且讀殘經。"]'),
('016695a3-18aa-42fe-893c-d72d717b7388','六言山居  其三','釋紹曇','宋','宋诗','song-poetry','','[]','盤石新封翠蘚，破龕重繞青蘿。',28,'全唐诗/poet.song.227000.json','["盤石新封翠蘚，破龕重繞青蘿。", "喚起驚回殘夢，月篩林影婆娑。"]'),
('026d7240-4ae4-4e94-966b-1fa864aed457','六言山居  其四','釋紹曇','宋','宋诗','song-poetry','','[]','粉芋頭煨軟火，嬾黄菁煮沙瓶。',28,'全唐诗/poet.song.227000.json','["粉芋頭煨軟火，嬾黄菁煮沙瓶。", "飯後烏藤用事，小奚忙啟巖扃。"]'),
('ab2d84f4-2d91-45ea-a9a9-05b2508a3d1f','六言山居  其五','釋紹曇','宋','宋诗','song-poetry','','[]','石磵霜凝松粉，竹籬雪點梅膚。',28,'全唐诗/poet.song.227000.json','["石磵霜凝松粉，竹籬雪點梅膚。", "春到山家日遠，愧貧管領全無。"]'),
('5949a2c3-67a7-4af9-b350-d6d3ef98affe','六言山居  其六','釋紹曇','宋','宋诗','song-poetry','','[]','曉逕旋除榛翳，午厨要款隣僧。',28,'全唐诗/poet.song.227000.json','["曉逕旋除榛翳，午厨要款隣僧。", "童子掃雲歸晚，忍饑趁□嬌藤。"]'),
('3a1ebea3-8c7d-4562-a6e9-c777367e582d','六言山居  其七','釋紹曇','宋','宋诗','song-poetry','','[]','香霧曉垂簾幕，幽禽春弄笙簧。',28,'全唐诗/poet.song.227000.json','["香霧曉垂簾幕，幽禽春弄笙簧。", "誰料貧無一物，邇來富敵君王。"]'),
('194651aa-1ee3-469a-bec8-1600b3bfb6cb','六言山居  其八','釋紹曇','宋','宋诗','song-poetry','','[]','兩耳爐焚柏子，一拳不養菖蒲。',28,'全唐诗/poet.song.227000.json','["兩耳爐焚柏子，一拳不養菖蒲。", "客至莫談塵事，略寒溫外跏趺。"]'),
('dc70b308-8c45-436b-9de6-54fa99155091','六言山居  其九','釋紹曇','宋','宋诗','song-poetry','','[]','得失心無半點，聖凡機裂千差。',28,'全唐诗/poet.song.227000.json','["得失心無半點，聖凡機裂千差。", "終日山禽聚集，且無箇去銜花。"]'),
('d83cf81a-204b-49de-be2d-737bdad442f4','六言山居  其一○','釋紹曇','宋','宋诗','song-poetry','','[]','香醉人尋梅塢，馬嘶聲度雲坳。',28,'全唐诗/poet.song.227000.json','["香醉人尋梅塢，馬嘶聲度雲坳。", "急把柴門深掩，從教小外推敲。"]'),
('1a561c10-8c5a-46fa-b27e-406b0cb4e0ba','悼芳洲懺首  其一','釋紹曇','宋','宋诗','song-poetry','','[]','不忍螢窗賺一生，翻身義虎頂頭行。',32,'全唐诗/poet.song.227000.json','["不忍螢窗賺一生，翻身義虎頂頭行。", "金篦刮盡空花膜，喜得天台教眼明。"]'),
('79801b13-e747-47d4-8e3e-c6d9c4c6b146','悼芳洲懺首  其二','釋紹曇','宋','宋诗','song-poetry','','[]','烟渚春融岸碧綃，采蘭人競唱離騷。',32,'全唐诗/poet.song.227000.json','["烟渚春融岸碧綃，采蘭人競唱離騷。", "曲終翻作無生調，聽著愁魂似雪消。"]'),
('7dce8481-a115-4ce4-989c-b24ff975fbaf','送剡源講師住華亭延慶','釋紹曇','宋','宋诗','song-poetry','','[]','三周講得墜天花，法眼無瑕却有瑕。',32,'全唐诗/poet.song.227000.json','["三周講得墜天花，法眼無瑕却有瑕。", "切莫朱涇訪船子，一橈摵碎潑生涯。"]'),
('5d833f0d-e491-43de-a2f3-d5cb6505da1b','依愚谷韻悼無己  其一','釋紹曇','宋','宋诗','song-poetry','','[]','中金蠶毒好埋冤，家醜難將歲月論。',32,'全唐诗/poet.song.227000.json','["中金蠶毒好埋冤，家醜難將歲月論。", "冷地思量喫虧處，咬牙不覺把齦吞。"]'),
('3dd7d1a1-fe19-431f-aa20-dbc035566cdf','依愚谷韻悼無己  其二','釋紹曇','宋','宋诗','song-poetry','','[]','雪真珠布滿階庭，急把楊岐破屋撐。',32,'全唐诗/poet.song.227000.json','["雪真珠布滿階庭，急把楊岐破屋撐。", "死伎窮時機路活，倒騎馿子弄蹄行。"]'),
('0b7b54f0-90e8-40be-9465-3ccc00ad5b21','依愚谷韻悼無己  其三','釋紹曇','宋','宋诗','song-poetry','','[]','末後蘇州作斷□，手頭活弄死蛇條。',32,'全唐诗/poet.song.227000.json','["末後蘇州作斷□，手頭活弄死蛇條。", "暗遭一口通身爛，累合城人哭幾朝。"]'),
('52cd4e5a-b0c7-4942-8da9-e9055bd6b82c','定侍者奔乃師喪諸公以偈乃求題其後','釋紹曇','宋','宋诗','song-poetry','','[]','五逆從前恨阿爺，幾思吞併老尸骸。',32,'全唐诗/poet.song.227000.json','["五逆從前恨阿爺，幾思吞併老尸骸。", "無端更被人攛掇，憤憤扶鍬去活埋。"]'),
('d94087b1-aeb9-4727-bb90-b9905367b2f7','送徑山圓兄亂後歸鄉','釋紹曇','宋','宋诗','song-poetry','','[]','故國烟塵慘甲兵，勞生終日望昇平。',32,'全唐诗/poet.song.227000.json','["故國烟塵慘甲兵，勞生終日望昇平。", "軍持带得龍淵水，歸去何妨一洗清。"]'),
('9c3c8285-bf86-4321-b5b8-3fc110225826','挽顔伯涯制斡','釋紹曇','宋','宋诗','song-poetry','','[]','握手論盟二十年，瘦筇曾約上危巔。',64,'全唐诗/poet.song.227000.json','["握手論盟二十年，瘦筇曾約上危巔。", "雪崖未遂同觀瀑，玉沼何期促孕蓮。", "桐葉成陰愁引月，菊花無酒冷含烟。", "細看新補東林傳，十八賢中又一賢。"]'),
('6e795283-0ed8-4454-a392-f5f648fa495c','送節操翁住閻寺','釋紹曇','宋','宋诗','song-poetry','','[]','早年教海已馳名，破衲青燈究一經。',64,'全唐诗/poet.song.227000.json','["早年教海已馳名，破衲青燈究一經。", "不借虛空開口說，肯教頑石點頭聽。", "宸奎錫命旌梅塢，丹桂飄香供柏庭。", "指日白雲禪坐穩，獻花無地著山靈。"]'),
('1c625180-b7d6-459f-a54f-8b27916b175c','南楊判鎮以詩問安次韻','釋紹曇','宋','宋诗','song-poetry','','[]','拙養自林泉，鏖戰驚蠻觸。',48,'全唐诗/poet.song.227000.json','["拙養自林泉，鏖戰驚蠻觸。", "心灰百念寒，虐焰肯停蓄。", "猗歟子雲翁，惜我如龜玉。", "無復獻楚庭，終期毀于櫝。"]'),
('17fb1a0b-2337-4a93-9bbc-7b28cb4b2678','寄梅墟陳提幹','釋紹曇','宋','宋诗','song-poetry','','[]','齒履登臨乏款延，薰風報謁鬰藍天。',64,'全唐诗/poet.song.227000.json','["齒履登臨乏款延，薰風報謁鬰藍天。", "拂塵未下雲簷榻，采寶新歸海國船。", "乘興□□迷柳下，搜吟□夢到梅邊。", "何時握手東林社，重結三生未盡緣。"]'),
('fd7f516b-e48b-44bc-b151-00d0b2c68274','懷樗寮','釋紹曇','宋','宋诗','song-poetry','','[]','半生魚佩解黄金，泉石郊坰得趣深。',64,'全唐诗/poet.song.227000.json','["半生魚佩解黄金，泉石郊坰得趣深。", "幽興發時閑副墨，俗塵捐處靜觀心。", "聖賢爐冶鎔聲色，妙密工夫鏗古今。", "遐想蓮居馳夢遠，未應輕易到瑶林。"]'),
('bbf3ba21-9c18-41b0-9340-d8a39bfa2ebe','挽王知縣','釋紹曇','宋','宋诗','song-poetry','','[]','東晉風流繼令名，家傳真本換鵝經。',64,'全唐诗/poet.song.227000.json','["東晉風流繼令名，家傳真本換鵝經。", "廉勤自得官中趣，貧節親書座右銘。", "民感庥仁忘赴壑，子明詩禮爲趨庭。", "疾風誰料摧梁木，猿鶴悲鳴不忍聽。"]'),
('6eaa2a2e-d231-448d-aebd-3428db7432fd','聽叫居親求語','釋紹曇','宋','宋诗','song-poetry','','[]','幼把儒冠颺壁根，朅來巾侍乳峰僧。',64,'全唐诗/poet.song.227000.json','["幼把儒冠颺壁根，朅來巾侍乳峰僧。", "吟詩清苦規寒子，舂碓辛勤慕老能。", "錦鏡閑看花瑣碎，瀑崖戲擊玉稜層。", "惜分陰語宜鞭策，望汝來挑暗室燈。"]'),
('09f58882-d035-486c-a07c-c5cb082fb92f','仁座主自西山來求語','釋紹曇','宋','宋诗','song-poetry','','["\u8861\u5c71"]','燈窗苦讀覺身癯，暫握筇枝訪野夫。',64,'全唐诗/poet.song.227000.json','["燈窗苦讀覺身癯，暫握筇枝訪野夫。", "愛竹勁思持玉節，看梅閑共數銀鬚。", "西山月冷歸招隠，南嶽風清欲步趨。", "靈利莫教人指去，且教船子老江湖。"]'),
('c8275cb9-2572-4b3a-9c10-b3332d3c1010','賦梅','釋紹曇','宋','宋诗','song-poetry','','[]','雪邊春信到衡茅，誰遣梅兄慰寂寥。',64,'全唐诗/poet.song.227000.json','["雪邊春信到衡茅，誰遣梅兄慰寂寥。", "秀氣一枝抽嫩玉，寒英五葉剪生綃。", "月移疏影窗前挂，風遞清香竹外飄。", "幾許吟魂招不返，急催蘭弟讀離騷。"]'),
('bfab17d5-b4c3-40cc-a6c6-aa9cde9bde20','布袋贊','釋紹曇','宋','宋诗','song-poetry','','[]','握藤枝，馱布袋。',36,'全唐诗/poet.song.227000.json','["握藤枝，馱布袋。", "轉腦回頭，使些奉化。", "逢人謾說覓文錢，乞兒乞兒，敗缺了也。"]'),
('1fca0233-6a10-44b8-a917-ddc2ed17befe','達磨贊','釋紹曇','宋','宋诗','song-poetry','','[]','遠離竺國見梁王，五鬼臨身討苦噇。',32,'全唐诗/poet.song.227000.json','["遠離竺國見梁王，五鬼臨身討苦噇。", "面面相看言不識，秋風一葦急橫江。"]'),
('737517d5-1f4d-4539-9acc-421fd611b8c8','靈照女贊','釋紹曇','宋','宋诗','song-poetry','','[]','幾對丹霞鬭活機，惡心腸有老爺知。',32,'全唐诗/poet.song.227000.json','["幾對丹霞鬭活機，惡心腸有老爺知。", "笊籬舀得春風滿，不直分文賣與誰。"]'),
('108dcaeb-c09f-4459-8cc4-59fb791ae387','漁籃婦贊','釋紹曇','宋','宋诗','song-poetry','','[]','短裳褰起露珠珍，雲鬢慵梳惑亂人。',32,'全唐诗/poet.song.227000.json','["短裳褰起露珠珍，雲鬢慵梳惑亂人。", "弄得籃中魚再活，禹門未必解翻身。"]'),
('c17ddb92-7ed7-45ef-83fb-322738621418','大慧禪師贊','釋紹曇','宋','宋诗','song-poetry','','[]','薰風南來，凉生殿閣。',39,'全唐诗/poet.song.227000.json','["薰風南來，凉生殿閣。", "諸佛出身，開口即錯。", "錯錯，贏得衡梅十七年，馿前馬後無歸著。"]'),
('97833797-f48e-4ad2-b088-d7618a84c8a4','慈林講師頂相','釋紹曇','宋','宋诗','song-poetry','','[]','氣宇兮春溫，風標兮凜然。',146,'全唐诗/poet.song.227000.json','["氣宇兮春溫，風標兮凜然。", "律虎出林兮，裂破開遮持犯。", "經龍攪海兮，探窮頓漸偏圓。", "句法清新兮，吟徹山莊梅竹。", "胸襟妙藴兮，包羅丘壑風烟。", "友縉紳兮，非權門炙手。", "荷佛法兮，思重負赬肩。", "煨芋香兮，無心收涕。", "卧雲深兮，豈意朝天。", "邈真容兮，明鏡繪像。", "付箕裘兮，神珠藏淵。", "夫是之謂慈林克家之子，真鸞膠而續絃者也。"]'),
('02503aba-70a0-4eb5-88f0-83426f717626','達磨贊','釋紹曇','宋','宋诗','song-poetry','','[]','殫千金産學屠龍，袖隠吹毛不露鋒。',32,'全唐诗/poet.song.227000.json','["殫千金産學屠龍，袖隠吹毛不露鋒。", "洎見真龍元不識，郎忙航葦去無蹤。"]'),
('e21ab7cc-f80c-41e2-af19-2fedb06c60e3','布袋贊','釋紹曇','宋','宋诗','song-poetry','','[]','楖栗橫肩拖布袋，回頭轉腦小兒嬉。',32,'全唐诗/poet.song.227000.json','["楖栗橫肩拖布袋，回頭轉腦小兒嬉。", "休言兜率宮中事，已被渠儂捉敗伊。"]'),
('a90d4b66-72d2-46f2-a8a6-b4e7b6f80ec1','布袋贊','釋紹曇','宋','宋诗','song-poetry','','[]','內院不肯安店，長汀分甘落泊。',54,'全唐诗/poet.song.227000.json','["內院不肯安店，長汀分甘落泊。", "拄杖不解拈提，布袋徒然倚託。", "肚中計較百般，要睡何曾睡著。", "睡得著，鐵奉化人須軟脚。"]'),
('d563dbc0-3534-4223-b28c-5027af84286b','天台三隠贊','釋紹曇','宋','宋诗','song-poetry','','[]','門鈎弗解開扃，苕箒不能掃地。',44,'全唐诗/poet.song.227000.json','["門鈎弗解開扃，苕箒不能掃地。", "解說杜撰文書，背後有人切齒。", "將謂寒山聽信他，不知笑裏暗藏刀。"]'),
('4b754e40-85d5-4993-9c84-15f02c309d8b','大慈環峰和尚贊','釋紹曇','宋','宋诗','song-poetry','','[]','肚腸深，用白粘賊翳睛藥，定滄海舶指南針。',66,'全唐诗/poet.song.227000.json','["肚腸深，用白粘賊翳睛藥，定滄海舶指南針。", "出智門蓮花，換人鼻孔。", "握大慈苕箒，掃世烟塵。", "忘忌諱，絕疏親。", "病在膏肓加蠱毒，直教石佛汗通身。"]'),
('2d2bfd90-1a46-4802-800d-92875adbdb6a','觀音贊','釋紹曇','宋','宋诗','song-poetry','','[]','百八摩尼杏葉光，圓通門戶日開張。',32,'全唐诗/poet.song.227000.json','["百八摩尼杏葉光，圓通門戶日開張。", "度生莫恃蓮舟穩，惡浪狂風自著忙。"]'),
('46eadff2-22af-4083-8797-0e091585ed88','豐干贊','釋紹曇','宋','宋诗','song-poetry','','[]','加紗挂頭何規矩，眼要看經不識字。',52,'全唐诗/poet.song.227000.json','["加紗挂頭何規矩，眼要看經不識字。", "差般差樣掣風顛，硬作斑貓騎作虎。", "道是彌陀，有何本據。", "閭丘太守，似蘇州子。"]'),
('6fec1e35-c1ae-43a2-90c0-4dbdf9847b1a','達磨贊','釋紹曇','宋','宋诗','song-poetry','','[]','一葦橫江，九年面壁。',34,'全唐诗/poet.song.227000.json','["一葦橫江，九年面壁。", "直指單傳，人信不及。", "面對梁王言不識，泥團亂拋擲。"]'),
('82e422b4-bcb5-49a4-90df-afa48f0d74c6','布袋贊','釋紹曇','宋','宋诗','song-poetry','','[]','靠布袋坐，聽巖瀑笑。',34,'全唐诗/poet.song.227000.json','["靠布袋坐，聽巖瀑笑。", "手把輪珠，數個什麽。", "內院拋離歲月深，忘却來時道。"]'),
('7e25e254-aff5-451a-8396-6a9bf3852ad6','對月了殘經贊','釋紹曇','宋','宋诗','song-poetry','','[]','是甚經，欠翻譯。',30,'全唐诗/poet.song.227000.json','["是甚經，欠翻譯。", "用盡心，看不出。", "看得出，月掛松梢，煙籠蘚石。"]'),
('87882166-8045-4374-81b6-a4e891d10c5f','朝陽穿破衲贊','釋紹曇','宋','宋诗','song-poetry','','[]','死鐵針，無鼻竅。',30,'全唐诗/poet.song.227000.json','["死鐵針，無鼻竅。", "眼昏花，穿不過。", "穿得過，雲擁禪衣，風生木杪。"]'),
('be86d410-ba00-40ae-8029-08420ddb4679','達磨贊','釋紹曇','宋','宋诗','song-poetry','','[]','遠泛鯨波入大唐，廓然無聖觸梁王。',32,'全唐诗/poet.song.227000.json','["遠泛鯨波入大唐，廓然無聖觸梁王。", "九年冷坐精靈窟，怕見嵩山下雪霜。"]'),
('c0c8b28c-836d-4239-98d9-e1d4620cdbf8','石室和尚贊','釋紹曇','宋','宋诗','song-poetry','','[]','面孔得人憎，腦中秋月皎。',77,'全唐诗/poet.song.227000.json','["面孔得人憎，腦中秋月皎。", "做處沒瘢痕，用時成要妙。", "見明極透出夜明簾，依圓照爛煨文武火。", "幾處移場弄險機，電卷風旋人絕倒。", "夫是之謂石室道人，前身後身，一夢兩覺。"]'),
('eda901f4-4367-476b-876c-392b5db37ada','草衣文殊贊','釋紹曇','宋','宋诗','song-poetry','','[]','被髮袒肩，全身入草。',41,'全唐诗/poet.song.227000.json','["被髮袒肩，全身入草。", "是真文殊，何須恁麽。", "手裡底拈不出，覷不破。", "七佛之師，敗缺不少。"]'),
('9b32f115-dd3e-49ba-8e65-40b9358c27a8','觀音贊','釋紹曇','宋','宋诗','song-poetry','','[]','隨類分身萬百千，真圓通境落誰邊。',32,'全唐诗/poet.song.227000.json','["隨類分身萬百千，真圓通境落誰邊。", "小兒戲劇無人會，萬頃滄波一葉蓮。"]'),
('f249a315-b3a2-419c-93a2-f6ed1ed7fa40','達磨贊','釋紹曇','宋','宋诗','song-poetry','','[]','竺乾竊得屠龍伎，袖隠神鋒入南海。',32,'全唐诗/poet.song.227000.json','["竺乾竊得屠龍伎，袖隠神鋒入南海。", "暨見真龍元不識，九年面壁好羞慚。"]'),
('7e698fb3-08fb-4bc0-be62-5cf2aa8de0d6','小師寫真請贊','釋紹曇','宋','宋诗','song-poetry','','[]','眉似箒粗，面如漆墨。',62,'全唐诗/poet.song.227000.json','["眉似箒粗，面如漆墨。", "人道慈悲，誰知惡毒。", "蒿籬關猛虎，寬處有威。", "筆管養蒼龍，直中藏曲。", "喜臧倉沮，不遇魯侯。", "忍伯夷饑，不食周粟。"]'),
('3b5637b6-4158-44d2-8eea-214a38049fe1','布袋贊','釋紹曇','宋','宋诗','song-poetry','','[]','馱布袋，握藤枝。',40,'全唐诗/poet.song.227000.json','["馱布袋，握藤枝。", "一肚皮惡毒，好使你門知。", "轉腦回頭望阿誰，髯公知此意，冷笑賊風吹。"]'),
('38820663-c400-4ade-b296-b2e9fa82ad16','讚延慶謙山主壽像','釋紹曇','宋','宋诗','song-poetry','','[]','謙德有光，慈心攝物。',144,'全唐诗/poet.song.227000.json','["謙德有光，慈心攝物。", "等冤親不與較量，混塵俗初無間隔。", "熙熙然氣融冰谷之春，汪汪乎胸吞雲夢之澤。", "樂羲皇世，含飴弄孫。", "下陳蕃榻，倒屐迎客。", "眼睛頭燁燁光明幢，脚跟下塵塵清泰國。", "卜隣陋巷，慕孔聖人獲麟作傳之風規。", "摵碎明珠，有郁山主騎馿過橋之標格。", "誠所謂入廛垂手，我自調心。", "繼百世凜然，見古道之顔色。"]'),
('a6c8961c-8c62-48be-bc08-9f4376a67f0d','丹霞見龐居士靈照歛手而立圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','放下菜籃，深深歛袂。',36,'全唐诗/poet.song.227000.json','["放下菜籃，深深歛袂。", "瞞得丹霞，難瞞自己。", "惡機關被老爺知，赤土塗牛奶賞伊。"]'),
('4021c6ff-0569-498d-9259-bedab7bdcdc4','居士問馬祖不與萬法爲侶圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','萬法本空，與誰爲侶。',36,'全唐诗/poet.song.227000.json','["萬法本空，與誰爲侶。", "道得十成，難爲共語。", "饒伊一口吸西江，也是芭蕉深夜雨。"]'),
('1854da67-8c39-48d4-b9be-eeaeb5b94495','團欒說無上話圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','夙世冤憎，聚頭合腦。',36,'全唐诗/poet.song.227000.json','["夙世冤憎，聚頭合腦。", "面面相看，說箇甚麽。", "低聲切莫使人知，竹石無情須笑倒。"]'),
('dd10e8e9-83df-495a-a5f7-a47aa0609d83','居士看日靈照先化去圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','這豆娘兒，短頭折脚。',36,'全唐诗/poet.song.227000.json','["這豆娘兒，短頭折脚。", "弄鬼精魂，攙先一著。", "看日龐公監本獃，深深好與一坑埋。"]'),
('d22382d8-2e9a-40fd-8607-1bc7f4632b0d','龐婆報兒兒即倚鋤立化圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','小姝先行，老爺踵去。',36,'全唐诗/poet.song.227000.json','["小姝先行，老爺踵去。", "無意奔喪，急尋死路。", "哭煞孤孀這老娘，钁頭邊事難分付。"]'),
('d2207e21-36c7-4850-8199-a6be565907f5','李翱見藥山圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','天本藏雲，瓶元貯水。',36,'全唐诗/poet.song.227000.json','["天本藏雲，瓶元貯水。", "不會看經，那堪指示。", "寄語唐朝李相公，只須著眼聽松風。"]'),
('70a28bb5-d48e-4a10-a513-41132366daf3','裴相國參黄蘗圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','大小癡禪，對談甚底。',36,'全唐诗/poet.song.227000.json','["大小癡禪，對談甚底。", "背後人聽，不能奪耳。", "切莫求安古佛名，當頭便觸賢侯諱。"]'),
('fcf907cb-b4c2-4da4-8697-dea0de597737','呂洞賓見黄龍圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','鐺煮乾坤，粟藏世界。',36,'全唐诗/poet.song.227000.json','["鐺煮乾坤，粟藏世界。", "縱得長生，終成敗壞。", "不是黄龍蓋覆伊，太阿補履豈如錐。"]'),
('8017b93c-1cff-4694-9e8a-3c23839986d0','爲昌州月上人贊布袋','釋紹曇','宋','宋诗','song-poetry','','[]','拄杖不能倚靠，穩跨布袋打坐。',28,'全唐诗/poet.song.227000.json','["拄杖不能倚靠，穩跨布袋打坐。", "莫怪噴嚏不成，鼻孔元來無竅。"]'),
('bf6dc41b-00ee-4489-bfb1-e920eb1b1735','嚴陽南泉泉大道船子贊','釋紹曇','宋','宋诗','song-poetry','','[]','未透趙州關，看牛事轉繁。',24,'全唐诗/poet.song.227000.json','["未透趙州關，看牛事轉繁。", "死蛇弄不活，只好踏船翻。"]'),
('67131de3-932f-46b7-813a-08a6567788ec','趙州問牛跡圓澤扣角政黄牛平田婆贊','釋紹曇','宋','宋诗','song-poetry','','[]','這畜從來惡跡多，角尖頭也解狂歌。',32,'全唐诗/poet.song.227000.json','["這畜從來惡跡多，角尖頭也解狂歌。", "橋邊白鷺擎拳聽，急殺耕田臭老婆。"]'),
('56867667-6997-473a-89bd-83db49e0f937','代贊羅漢  其一','釋紹曇','宋','宋诗','song-poetry','','[]','古檜含烟，青山展畫。',37,'全唐诗/poet.song.227000.json','["古檜含烟，青山展畫。", "題目分明，何須管带。", "待你炷得香來，鳴磬一下。", "蹉過了也。"]'),
('7d738ded-541e-403c-a802-606918ed7eb8','代贊羅漢  其二','釋紹曇','宋','宋诗','song-poetry','','[]','靠葛藤樁，握龜毛拂。',48,'全唐诗/poet.song.227000.json','["靠葛藤樁，握龜毛拂。", "絕學無爲，黑山鬼窟。", "直饒瞥轉機輪，眼裏聞香，耳中觀色。", "我且問，瓶內底是何物。"]'),
('fdd92fd9-d24e-4ede-9e48-73f349cf54b4','蜆子和尚贊','釋紹曇','宋','宋诗','song-poetry','','[]','除了撈波一窖無，逢人謾說走江湖。',32,'全唐诗/poet.song.227000.json','["除了撈波一窖無，逢人謾說走江湖。", "蝦針取你性撈摝，不到得拏龍頷珠。"]'),
('4e2dd710-7239-4609-93e5-7e2352374a7d','郁山主贊','釋紹曇','宋','宋诗','song-poetry','','[]','落魄茶陵少見聞，進竿頭步與誰言。',32,'全唐诗/poet.song.227000.json','["落魄茶陵少見聞，進竿頭步與誰言。", "明珠打得馿腰折，不信闍梨个樣村。"]'),
('1fd63086-8cb5-4c63-bd09-ab3298501a00','政黄牛贊','釋紹曇','宋','宋诗','song-poetry','','[]','一生孤苦竊詩名，沉醉風煙兩眼青。',32,'全唐诗/poet.song.227000.json','["一生孤苦竊詩名，沉醉風煙兩眼青。", "黄犢不曾知稼穡，引渠吟得瘦竛竮。"]'),
('b614041b-75e2-45b2-991e-459b6830a59b','普化贊','釋紹曇','宋','宋诗','song-poetry','','[]','大悲院裏趁村齋，卒死無人出地埋。',32,'全唐诗/poet.song.227000.json','["大悲院裏趁村齋，卒死無人出地埋。", "捏怪凌空摇木鐸，春風處處露尸骸。"]'),
('b8d57787-cbf2-4857-9b76-58757996da29','端師子贊','釋紹曇','宋','宋诗','song-poetry','','[]','爪牙雖弄未全真，駁綠斑釐著一身。',32,'全唐诗/poet.song.227000.json','["爪牙雖弄未全真，駁綠斑釐著一身。", "彩好不曾哮吼得，聽聞將謂嚇村人。"]'),
('55a7b6d7-183d-4499-ae69-0cf7daffff73','言法華贊','釋紹曇','宋','宋诗','song-poetry','','[]','心迷幾被法華轉，狂發羅齋走帝宮。',32,'全唐诗/poet.song.227000.json','["心迷幾被法華轉，狂發羅齋走帝宮。", "對聖十三呼不正，無端咄咄强書空。"]'),
('865daebb-323c-499e-ad39-40fcc47d13df','泉大道贊','釋紹曇','宋','宋诗','song-poetry','','[]','赤身跳入毒龍潭，血戰知他死幾番。',32,'全唐诗/poet.song.227000.json','["赤身跳入毒龍潭，血戰知他死幾番。", "諍撰出來噇鉢酒，郴州六月火雲寒。"]'),
('a360350f-8453-4026-8c96-b19f104e3af4','船子贊','釋紹曇','宋','宋诗','song-poetry','','[]','心含惡毒氣炎炎，倒捉麤橈管甚天。',32,'全唐诗/poet.song.227000.json','["心含惡毒氣炎炎，倒捉麤橈管甚天。", "打得夾山攛入水，趁無入見急翻船。"]'),
('275f0593-3c1d-4dfb-bcf2-a3680a6cdc60','豐干贊','釋紹曇','宋','宋诗','song-poetry','','[]','冷坐松陰指顧誰，說無義語放憨癡。',32,'全唐诗/poet.song.227000.json','["冷坐松陰指顧誰，說無義語放憨癡。", "多方引得閭丘笑，彩好斑斑睡不知。"]'),
('8e895fdb-8c03-4b50-8dfb-79146315c977','寒拾贊','釋紹曇','宋','宋诗','song-poetry','','[]','笑裏藏刀語詐淳，握生苕箒鼓烟塵。',32,'全唐诗/poet.song.227000.json','["笑裏藏刀語詐淳，握生苕箒鼓烟塵。", "謾將心污秋潭月，未必渠儂肯比倫。"]'),
('27d231ca-c021-480e-b835-63c5a177aa53','出山相贊','釋紹曇','宋','宋诗','song-poetry','','[]','半夜逾城，六年栖雪。',36,'全唐诗/poet.song.227000.json','["半夜逾城，六年栖雪。", "餓得眼花，凍得骨折。", "死伎窮時走出山，兒孫開眼被渠瞞。"]'),
('05e50053-30b0-4652-acb6-a082316d62c7','肩袋過水布袋贊','釋紹曇','宋','宋诗','song-poetry','','[]','這漢一生弄險，愛向風波裏輥。',38,'全唐诗/poet.song.227000.json','["這漢一生弄險，愛向風波裏輥。", "肩個布袋截流，脚下不知深淺。", "劈箭機先，路通一線。"]'),
('69ebfcd2-9a36-4cb5-a2b2-9496e3c50a3f','靠布袋看髑髏不開口笑贊','釋紹曇','宋','宋诗','song-poetry','','[]','笑不露唇，見不透脫。',37,'全唐诗/poet.song.227000.json','["笑不露唇，見不透脫。", "布袋靠得雖牢，髑髏枯眼再活。", "若要活奉化，肚腸盡情拈却。"]'),
('008ee79d-8fcd-449c-91ee-e81b61f9f8e1','靠袋睡贊  其一','釋紹曇','宋','宋诗','song-poetry','','[]','自與塵勞交輥，肚裏千機萬變。',28,'全唐诗/poet.song.227000.json','["自與塵勞交輥，肚裏千機萬變。", "雖然靠布被頭，疑你睡得未穩。"]'),
('b1d8734c-10ce-4055-93ea-bbb6f157faeb','靠袋睡贊  其二','釋紹曇','宋','宋诗','song-poetry','','[]','弄盡千般死伎，布袋全身靠倚。',28,'全唐诗/poet.song.227000.json','["弄盡千般死伎，布袋全身靠倚。", "尋思總是虛花，不如打覺瞌睡。"]'),
('3841f5ec-fb03-4220-8d8d-e434bd44b201','靠布袋常思惟贊','釋紹曇','宋','宋诗','song-poetry','','[]','赤骨律窮，單靠布袋。',36,'全唐诗/poet.song.227000.json','["赤骨律窮，單靠布袋。", "子細思量，大有事在。", "平地要昇兜率天，你這漢是顛是騃。"]'),
('6aaac9b3-2271-4781-82f8-d7ff5abd8cdc','布袋贊  其一','釋紹曇','宋','宋诗','song-poetry','','[]','馱布袋，放癡憨。',34,'全唐诗/poet.song.227000.json','["馱布袋，放癡憨。", "回頭一笑，捏怪千般。", "走徧長汀人不識，誑言彌勒示人間。"]'),
('f2154363-f136-4d1f-80db-81e920dd387b','布袋贊  其二','釋紹曇','宋','宋诗','song-poetry','','[]','馱布袋，笑誾誾。',38,'全唐诗/poet.song.227000.json','["馱布袋，笑誾誾。", "智無一兩，肉重千斤，轉腦回頭等個人。", "率陀歸路遠，滿面是埃塵。"]'),
('21106bcb-b317-4ed8-8fc3-3620101bc03e','布袋贊  其三','釋紹曇','宋','宋诗','song-poetry','','[]','杖挑布袋，冷笑誾誾。',37,'全唐诗/poet.song.227000.json','["杖挑布袋，冷笑誾誾。", "肚皮無窖，眼裏無筋，走長汀等個人。", "敗闕了也，賊精賊精。"]'),
('c8408c6e-5500-449a-bf7b-5266e4b7bba4','布袋贊  其四','釋紹曇','宋','宋诗','song-poetry','','[]','橫挑布袋壓烏藤，笑裏藏刀極可憎。',32,'全唐诗/poet.song.227000.json','["橫挑布袋壓烏藤，笑裏藏刀極可憎。", "鐵奉化人渾是鐵，如何容得這般僧。"]'),
('f58f4d94-d57e-47de-844a-f30ee54f49b6','布袋贊  其五','釋紹曇','宋','宋诗','song-poetry','','[]','布袋肩馱冷笑時，肚腸惡毒是人知。',32,'全唐诗/poet.song.227000.json','["布袋肩馱冷笑時，肚腸惡毒是人知。", "重重敗缺難遮掩，猶自回頭望阿誰。"]'),
('c3dc1e43-ae9d-4356-a232-4a08c86861fd','朝陽贊  其一','釋紹曇','宋','宋诗','song-poetry','','[]','破襴衫，閑抖擻。',54,'全唐诗/poet.song.227000.json','["破襴衫，閑抖擻。", "穴鼻針，穿不透。", "穿得透，日出扶桑，朝朝如舊。", "無絲線，拽不斷。", "盡力提撕，日勢稍晚，馿年成片段。"]'),
('44076135-ad57-4536-a3ba-95efe54c0dda','朝陽贊  其二','釋紹曇','宋','宋诗','song-poetry','','[]','拶得當陽線路通，大千捏聚一針鋒。',32,'全唐诗/poet.song.227000.json','["拶得當陽線路通，大千捏聚一針鋒。", "不堪提掇堪提掇，破綻全無始見功。"]'),
('e3723911-b230-4c59-a4ee-d932fb07b8f3','待月贊  其一','釋紹曇','宋','宋诗','song-poetry','','[]','破故紙堆鑽不透，可憐業識日茫茫。',32,'全唐诗/poet.song.227000.json','["破故紙堆鑽不透，可憐業識日茫茫。", "末梢一段無分曉，猶待蝦蟆口放光。"]'),
('5bf5c18e-27cb-4a3d-8ac9-d04a14b19d05','待月贊  其二','釋紹曇','宋','宋诗','song-poetry','','[]','末後句，如何舉。',24,'全唐诗/poet.song.227000.json','["末後句，如何舉。", "眨得眼來，月圓當戶。", "何曾知落處。"]'),
('33d358f1-a9f1-4db8-ae14-63f095ecc9b8','待月贊  其三','釋紹曇','宋','宋诗','song-poetry','','[]','末後句，忒分曉。',30,'全唐诗/poet.song.227000.json','["末後句，忒分曉。", "眼無筋，覷不破。", "覷得破，心月孤圓，千差一照。"]'),
('8437542d-4bb1-4d69-b4e4-1e913d7fcdcf','拾得磨墨贊','釋紹曇','宋','宋诗','song-poetry','','[]','可憐拾得，側望徒勞。',18,'全唐诗/poet.song.227000.json','["可憐拾得，側望徒勞。", "墨有消時恨不消。"]'),
('dab0568a-8e9b-4e40-81a8-8d9493ce68b7','天台三聖圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','滿地埃塵弗掃除，無端商校潑文書。',32,'全唐诗/poet.song.227000.json','["滿地埃塵弗掃除，無端商校潑文書。", "灼然拄杖能行令，不到豐干放過渠。"]'),
('d1fe1fd4-158f-4618-b7a6-ef012b0bcc4f','四睡贊','釋紹曇','宋','宋诗','song-poetry','','[]','人無害虎心，虎無傷人意。',24,'全唐诗/poet.song.227000.json','["人無害虎心，虎無傷人意。", "彼此不關防，何妨打覺睡。"]'),
('35f97cbc-15b2-4ec3-b038-25a0e8d743e4','曹溪六祖大師贊','釋紹曇','宋','宋诗','song-poetry','','[]','辛州颺下兩肩樵，又被黄梅石墜腰。',32,'全唐诗/poet.song.227000.json','["辛州颺下兩肩樵，又被黄梅石墜腰。", "雖得栽松衣鉢在，暗思追逐幾魂銷。"]'),
('65102856-8a09-4763-99f6-c91937163327','達磨渡江贊','釋紹曇','宋','宋诗','song-poetry','','[]','聖諦義中猶不識，透清波路想應難。',32,'全唐诗/poet.song.227000.json','["聖諦義中猶不識，透清波路想應難。", "九年鬼窟深藏拙，却被神光冷眼看。"]'),
('2bbc5973-1998-4fb8-97ee-424188f578c7','觀音大士贊','釋紹曇','宋','宋诗','song-poetry','','[]','足下青蓮花半敷，倚巖危坐手輪珠。',32,'全唐诗/poet.song.227000.json','["足下青蓮花半敷，倚巖危坐手輪珠。", "普門真境難描邈，剛被人傳入畫圖。"]'),
('76fe7e1a-9d5b-427b-88fb-460ddac1fdf3','魚婦觀音贊','釋紹曇','宋','宋诗','song-poetry','','[]','不歸小白花巖住，越樣梳粧誑世人。',32,'全唐诗/poet.song.227000.json','["不歸小白花巖住，越樣梳粧誑世人。", "無底籃雖提得活，禹門未必解翻身。"]'),
('ed3b57a8-57a4-476e-89a7-9105a05f221e','布袋贊  其一','釋紹曇','宋','宋诗','song-poetry','','[]','臭布囊，有甚底。',40,'全唐诗/poet.song.227000.json','["臭布囊，有甚底。", "才倚靠，便瞌睡。", "不知何日下生，屈數尚餘一指。", "浣盆浣盆，我識得你。"]'),
('3721fa44-180c-477c-82dc-6e43e72afa17','布袋贊  其二','釋紹曇','宋','宋诗','song-poetry','','[]','緊捉布袋頭，片時放不下。',40,'全唐诗/poet.song.227000.json','["緊捉布袋頭，片時放不下。", "用盡惡機關，難瞞鐵奉化。", "重重敗缺幾曾知，猶自回頭望阿誰。"]'),
('12844b40-a3db-4006-9842-c748bc518dd4','布袋贊  其三','釋紹曇','宋','宋诗','song-poetry','','[]','赤脚走紅塵，道是真彌勒。',38,'全唐诗/poet.song.227000.json','["赤脚走紅塵，道是真彌勒。", "買弄臭皮囊，大地無人識。", "無人識，急急回頭，已遲八刻。"]'),
('661573d5-cfb8-40f0-a8cd-da51f0fccbcd','布袋浴江圖贊  其一','釋紹曇','宋','宋诗','song-poetry','','[]','柳烟羃羃浪粼粼，脫體無依尚染塵。',32,'全唐诗/poet.song.227000.json','["柳烟羃羃浪粼粼，脫體無依尚染塵。", "輥得通身是泥水，小兒戲劇誑誰人。"]'),
('05bcfe8f-d830-414e-81d9-be241ffd9927','布袋浴江圖贊  其二','釋紹曇','宋','宋诗','song-poetry','','[]','無端平地鼓波瀾，揭露娘生赤肉團。',32,'全唐诗/poet.song.227000.json','["無端平地鼓波瀾，揭露娘生赤肉團。", "瞞得嬌擬兒女子，溪頭楊柳樹難瞞。"]'),
('23d4938d-714d-491a-8be8-8f93f4167300','爲周上人贊觀音','釋紹曇','宋','宋诗','song-poetry','','[]','小白山頭花弄影，潮音洞口浪翻空。',32,'全唐诗/poet.song.227000.json','["小白山頭花弄影，潮音洞口浪翻空。", "圓通門啟無人入，閑把輪珠立曉風。"]'),
('f4576cab-ae6b-4c93-a2ba-439dcb48d6aa','爲緣知客求贊','釋紹曇','宋','宋诗','song-poetry','','[]','不假聞思修，巨闢圓通路。',24,'全唐诗/poet.song.227000.json','["不假聞思修，巨闢圓通路。", "更擬問如何，數珠木槌子。"]'),
('228a3fed-6225-4883-8d2c-51a7e06b8239','贊出山相','釋紹曇','宋','宋诗','song-poetry','','[]','六年凍得瘦竛竮，走出山來眼未醒。',32,'全唐诗/poet.song.227000.json','["六年凍得瘦竛竮，走出山來眼未醒。", "白折金輪翻不轉，謾言半夜見明星。"]'),
('9ddee409-2577-46a9-8e10-6216bd8c54a9','贊華長老真','釋紹曇','宋','宋诗','song-poetry','','["\u897f\u6e56"]','華胄兮天隨故家，清名兮應菴再來。',124,'全唐诗/poet.song.227000.json','["華胄兮天隨故家，清名兮應菴再來。", "窮教兮佛隴精華，逃禪兮蘇州思獃。", "愛梅兮冰雪襟懷，結茅兮泉石亭臺。", "搜吟兮西湖巧裁，好客兮東閤大開。", "樂歸隠兮百鳥銜花，尸浄土兮九蓮奪胎。", "瞻遺像兮瑶林瓊樹之葩，挺孫枝兮雕梁畫棟之材。", "作是贊兮無乃繪太虛之五采，點明鏡之紛埃。"]'),
('a52137fd-9443-4f34-a14f-c2c41edb88f3','贊國清靈叟和尚真入北□祖師會','釋紹曇','宋','宋诗','song-poetry','','[]','貌古神清，氣融性漫。',70,'全唐诗/poet.song.227000.json','["貌古神清，氣融性漫。", "用無準麻皮頭，瞎臨濟正法眼。", "瘞焦山鶴，不假蓬塵。", "縛豐干虎，只消錢貫。", "八怪七喬，十馬九亂。", "趁入羣牛隊裏行，一年一度教人看。"]'),
('29920c4a-5e9b-4855-97b2-afa2c18471b3','送日本爾侍者','釋紹曇','宋','宋诗','song-poetry','','[]','徑山無法與人傳，幾度親遭劈面拳。',32,'全唐诗/poet.song.227000.json','["徑山無法與人傳，幾度親遭劈面拳。", "今日大唐回首去，鼻頭元在口皮邊。"]'),
('203a4deb-3792-4db5-97b2-38ae13a13ce9','送圓爾上人歸日本','釋道㻬','宋','宋诗','song-poetry','','[]','興盡心空轉海東，定應赤手展家風。',32,'全唐诗/poet.song.227000.json','["興盡心空轉海東，定應赤手展家風。", "報言日本真天子，且喜楊岐正脉通。"]'),
('10d4459e-0423-4437-a6cd-c3f26cfa328f','送子應梅入太學','王希淮','宋','宋诗','song-poetry','','[]','璧流天下士，取友戒荒嬉。',48,'全唐诗/poet.song.227000.json','["璧流天下士，取友戒荒嬉。", "家國關身重，鄉園得夢遲。", "子行雖不惡，我老自堪疑。", "莫似遼東鶴，悠悠不可期。"]'),
('57b66ea1-57eb-46ec-9e8d-46a83c12a5f3','越王臺','吳浚','宋','宋诗','song-poetry','','[]','越王歌舞地，南國古繁雄。',48,'全唐诗/poet.song.227000.json','["越王歌舞地，南國古繁雄。", "水闊山光迥，天低海氣通。", "千舠民蛋雨，一塔賈胡風。", "欲問興亡事，松聲自半空。"]'),
('81b5c63a-ce40-4f74-a1e2-3871e9973362','寄蕭冰崖練橘里黄立軒','吳浚','宋','宋诗','song-poetry','','[]','破夢金川月，回頭玉樹風。',48,'全唐诗/poet.song.227000.json','["破夢金川月，回頭玉樹風。", "烟村涵暮紫，霜葉顫晴紅。", "謀國諸侯在，忘年古道同。", "乾坤雲一片，吾意未終窮。"]'),
('b37b6c5a-22f7-4c03-954d-c79248c61a65','早發','吳浚','宋','宋诗','song-poetry','','[]','顥氣澄初曉，清江百丈秋。',48,'全唐诗/poet.song.227000.json','["顥氣澄初曉，清江百丈秋。", "槳摇山勢動，船带日光流。", "禽噪應知曙，魚沉若避鈎。", "閑身非復昔，征棹莫遲留。"]'),
('9747a8b1-4d0a-409d-9db6-7d461d208bc6','一雨','吳浚','宋','宋诗','song-poetry','','[]','一雨千紅盡，春風奈老何。',48,'全唐诗/poet.song.227000.json','["一雨千紅盡，春風奈老何。", "暝雲含楚思，新漲動吳波。", "天地端倪出，朝廷俊傑多。", "馬蹄江上路，吾意獨蹉跎。"]'),
('d51f1916-f1b0-4790-82db-a91dcc34cb04','重過瑞金江','吳浚','宋','宋诗','song-poetry','','[]','水瘦灘聲健，天寒霜意新。',48,'全唐诗/poet.song.227000.json','["水瘦灘聲健，天寒霜意新。", "犬牙舟過石，魚貫路行人。", "到眼心應識，回頭跡易陳。", "時平刀劍息，失喜問遺民。"]'),
('37a4db6e-4d4f-4786-9693-bb4d88d76601','道中即事  其一','吳浚','宋','宋诗','song-poetry','','[]','露白霜清曉氣浮，菊花滿意爲誰秋。',32,'全唐诗/poet.song.227000.json','["露白霜清曉氣浮，菊花滿意爲誰秋。", "西風畢竟真廉吏，狼藉金錢散不收。"]'),
('dc48b272-6b78-423d-82af-bcf7c51286c0','道中即事  其二','吳浚','宋','宋诗','song-poetry','','[]','林葉聲乾山影瘦，斬新霜氣欲無秋。',32,'全唐诗/poet.song.227000.json','["林葉聲乾山影瘦，斬新霜氣欲無秋。", "菊花猶護西風局，自在籬根夢蓐收。"]'),
('f1c33086-a4b7-4d38-8351-96dd449b802a','客中','吳浚','宋','宋诗','song-poetry','','[]','斷雁嘯雲天試霜，客中何事不凄凉。',32,'全唐诗/poet.song.227000.json','["斷雁嘯雲天試霜，客中何事不凄凉。", "玉梅約住春風信，更讓黄花半月香。"]'),
('406fc7bc-b7f6-43b4-95f0-61eebd0c7367','山行','吳浚','宋','宋诗','song-poetry','','[]','溪水泠泠清見沙，鏡中歷歷走魚蝦。',32,'全唐诗/poet.song.227000.json','["溪水泠泠清見沙，鏡中歷歷走魚蝦。", "樹紅霜後無多葉，梅入冬來第一花。"]'),
('8a126912-1322-45e4-b39a-3396459c0a46','春日','吳浚','宋','宋诗','song-poetry','','[]','畫堂簾箔碧籠葱，午夢模糊燕語中。',32,'全唐诗/poet.song.227000.json','["畫堂簾箔碧籠葱，午夢模糊燕語中。", "微雨嫩晴天似醉，閙紅吹上海棠風。"]'),
('3c37dcfa-697f-4d3b-a9ab-4a227205b50e','春詞','吳浚','宋','宋诗','song-poetry','','[]','是處簫聲破碧雲，翠梅依舊鎖閑春。',32,'全唐诗/poet.song.227000.json','["是處簫聲破碧雲，翠梅依舊鎖閑春。", "東風不負庭前柳，只負年年看柳人。"]'),
('d67e62a7-5231-4439-a7e6-afe08e969ce6','六言','吳浚','宋','宋诗','song-poetry','','[]','草間路六七里，溪上梅三四花。',28,'全唐诗/poet.song.227000.json','["草間路六七里，溪上梅三四花。", "日落鳥聲何處，山空犬吠誰家。"]'),
('b0a09dcb-d3fa-492a-8b6d-0e622ad36570','採蓮曲','吳浚','宋','宋诗','song-poetry','','[]','見蓮知菂實，尋藕□絲長。',24,'全唐诗/poet.song.227000.json','["見蓮知菂實，尋藕□絲長。", "六月天邊路，何時結得霜。"]'),
('ca08d7d8-339b-4cd2-addc-efe83d07e1d7','太乙真人畫像','吳浚','宋','宋诗','song-poetry','','[]','真人讀何書，一葉凌浩溔。',24,'全唐诗/poet.song.227000.json','["真人讀何書，一葉凌浩溔。", "不見此舟輕，但覺天地小。"]'),
('ce55796b-1994-4ecb-952e-f98c1c812426','安期生','吳浚','宋','宋诗','song-poetry','','[]','安期聳身坐，揮斥遊太極。',24,'全唐诗/poet.song.227000.json','["安期聳身坐，揮斥遊太極。", "若遇謫仙人，鯨背分半席。"]'),
('9f0f8d42-1c6c-4f9a-a1b6-57c362197005','中秋聯句','吳浚','宋','宋诗','song-poetry','','[]','棘闈受得樹凉多，耿耿孤燈奈夜何。',384,'全唐诗/poet.song.227000.json','["棘闈受得樹凉多，耿耿孤燈奈夜何。", "後夜中秋可無月，雨工先爲洗銀河。", "中秋此去日無多，笑問青天雨若何。", "舊日仙槎應好在，西風吹送上天河。", "雨到中秋易得多，素娥爭奈漏天何。", "青天四壁漫漫夜，星魁誰人見渡河。", "雨聲釀得客愁多，欲賞清秋作計何。", "莫唱劉郎黄鶴句，西風舉目異江河。", "三台高處五雲多，如此好天良夜何。", "曾記長淮看月否，玉人何處唱西河。", "月下敲詩得句多，詩成句句敵陰何。", "夜凉不禁詩腸渴，欲作長鯨吸九河。", "風捲玄雲已不多，倚欄試問夜如何。", "玉輪擬把長繩繫，生怕孤蟾沒入河。", "月魄分它日影多，有盈有闕却緣何。", "世人錯認娑羅樹，半是青山半是河。", "孤蟾老矣閲人多，玉斧如霜不敢何。", "何似長圓如此夜，放教全影看山河。", "白鳳威遲舞態多，三郎此際意如何。", "霓裳一曲君休聽，曾引胡塵暗兩河。", "月中桂子種來多，知得天香定屬何。", "袍色明年沾柳汁，好尋年少到三河。", "乾坤清氣在梅多，梅屬能詩水部何。", "惜不移來月中種，却教疏影入秋河。"]'),
('dcb00afe-4efb-4cc3-a5cd-7c58405f8485','朝天宮成紀懷','張德興','宋','宋诗','song-poetry','','[]','崒律千尋玉壘開，龍盤虎踞擁金臺。',64,'全唐诗/poet.song.227000.json','["崒律千尋玉壘開，龍盤虎踞擁金臺。", "雲中雙闕天顔近，塞山孤臣鐵騎迴。", "砂壁朝疑烽火動，松風夜雜鼓笳哀。", "願將隻手扶紅日，掃盡狼烟御輦回。"]'),
('8aaca412-5a3f-4a3f-8f89-77e54b4845aa','寄友伯杲','侯畐','宋','宋诗','song-poetry','','[]','一自城南別，無書直到今。',48,'全唐诗/poet.song.227000.json','["一自城南別，無書直到今。", "凄凉春夜雨，點滴故人心。", "笋長林添竹，蠶成柘減陰。", "清溪吟歷處，曾有夢相尋。"]'),
('575b5e6a-1f7c-47b8-9a23-e2f3fe416e29','芷溪園','侯畐','宋','宋诗','song-poetry','','[]','行吟溪上園，幽思與詩便。',48,'全唐诗/poet.song.227000.json','["行吟溪上園，幽思與詩便。", "藤附多年樹，苔生廢井泉。", "瘦梅鋤月種，蔓菊就籬編。", "更有三間屋，重茅蓋竹椽。"]'),
('29113744-1895-41d7-aab0-4f1c6fe13545','長安','侯畐','宋','宋诗','song-poetry','','[]','又是故山好，誰教輕別家。',48,'全唐诗/poet.song.227000.json','["又是故山好，誰教輕別家。", "带來衣典盡，所擬事全差。", "詩債隨時解，房金累月賒。", "客懷元自苦，不涉聽吹笳。"]'),
('0166d566-f52a-4e33-a8eb-6ae5e67da5b6','湖心寺呈簫峰陳明府','侯畐','宋','宋诗','song-poetry','','[]','水邊曾看題碑石，知是詩人扁寺名。',64,'全唐诗/poet.song.227000.json','["水邊曾看題碑石，知是詩人扁寺名。", "僧趁釣舟來赴供，魚聽堂鼓候拋生。", "無多空地鋤松影，儘有寒湖載月明。", "只合閒身吟向此，細將心事共鷗評。"]'),
('c92f35af-626c-46da-8f27-a748a3d2b10f','暮雨','侯畐','宋','宋诗','song-poetry','','[]','暮雨生寒衣袂薄，楚鄉客子正傷情。',32,'全唐诗/poet.song.227000.json','["暮雨生寒衣袂薄，楚鄉客子正傷情。", "扁舟莫向蘆邊宿，夜半西風有雁聲。"]'),
('c26715a1-d278-4592-8e25-450987a4a728','柳花','侯畐','宋','宋诗','song-poetry','','[]','嫩水浴鳬芳草短，淡烟飛燕落花天。',32,'全唐诗/poet.song.227000.json','["嫩水浴鳬芳草短，淡烟飛燕落花天。", "綠楊也識春來暖，一夜東風脫却綿。"]'),
('55a51fd3-b87a-407f-bb69-00535f8d30b3','寒食','侯畐','宋','宋诗','song-poetry','','[]','滿地落花收不得，子規聲裏抱愁眠。',32,'全唐诗/poet.song.227000.json','["滿地落花收不得，子規聲裏抱愁眠。", "貧家無日非寒食，未必今朝始禁烟。"]'),
('7796db1f-5a34-4c72-a527-092a62bd9a5f','遊洞霄','李時英','宋','宋诗','song-poetry','','[]','撇開塵鞅作清遊，路轉溪回景物幽。',64,'全唐诗/poet.song.227000.json','["撇開塵鞅作清遊，路轉溪回景物幽。", "樓閣插天藏九鎖，林崖飛瀑看雙流。", "聲鏘玉佩三更月，冷浸冰壺一段秋。", "從此濯纓趨□□，□□□□□□□。"]'),
('e1ee05fb-9c8c-4abc-bbf8-3134f7b2f683','題彌勒院','章孝參','宋','宋诗','song-poetry','','[]','橋通流水綠溶溶，殿閣穹然鎮象龍。',64,'全唐诗/poet.song.227000.json','["橋通流水綠溶溶，殿閣穹然鎮象龍。", "半壁石橋通雪竇，一龕麗室占雷峯。", "挂巖屋似六和塔，入路門如九里松。", "遥想空庭明月夜，浮屠桂樹影重重。"]'),
('c00e5699-03be-49e5-9e81-30c694aacc85','挽知容州朝請陶公  其一','羅一鶚','宋','宋诗','song-poetry','','[]','月旦爭推重，邦人得範模。',48,'全唐诗/poet.song.227000.json','["月旦爭推重，邦人得範模。", "官資雖刺史，氣味一寒儒。", "簡淡根真性，清廉律薄夫。", "不知書卓行，曾入史編無。"]'),
('7976de9f-3977-4095-bfef-d7e8d9d60da3','挽知容州朝請陶公  其二','羅一鶚','宋','宋诗','song-poetry','','[]','世亦多真士，當於晚節看。',48,'全唐诗/poet.song.227000.json','["世亦多真士，當於晚節看。", "急流能勇退，袖手但旁觀。", "凡卉隨春盡，孤標耐歲寒。", "始終全所守，此事古來難。"]'),
('db0cdc2e-3c20-4fbd-ad9b-5a35c6173541','挽知容州朝請陶公  其三','羅一鶚','宋','宋诗','song-poetry','','[]','昔曾親誨色，霜凜更春溫。',48,'全唐诗/poet.song.227000.json','["昔曾親誨色，霜凜更春溫。", "貌古心猶古，年尊德亦尊。", "頓驚生死隔，奈有典型存。", "愁絕飛丹旐，憑誰爲返魂。"]'),
('1add542c-8326-441f-8b21-579e3c1f685d','天柱','謝章','宋','宋诗','song-poetry','','[]','鶑花婉娩天，晴空落紅雨。',156,'全唐诗/poet.song.227000.json','["鶑花婉娩天，晴空落紅雨。", "千里賦遠遊，山水無重數。", "武夷天下甲，清絕多奇趣。", "名峯三十六，一一拱天柱。", "隔岸分西東，回首時一顧。", "孤高自特立，不肯相朋附。", "溪流走其下，縈紆溢清泚。", "荒煙鎖寒碧，晴嵐滴空翠。", "曲曲深復深，行行止且止。", "時聞欵乃歌，恍入桃源路。", "山禽相應答，嶺雲自吞吐。", "此境非人寰，蔚爲神仙所。", "我欲深窮□，白鷗沒星渚。"]'),
('8203aa65-7078-4213-bdc6-b85306e31cb3','題小如山廟','蔡志學','宋','宋诗','song-poetry','','[]','平生事可對人說，囊無一分關節錢。',32,'全唐诗/poet.song.227000.json','["平生事可對人說，囊無一分關節錢。", "寄語江神明著眼，好分風力送歸船。"]'),
('05cb04ac-c6dc-4621-a36a-fe86ab03807e','蝙蝠洞','倪夢龍','宋','宋诗','song-poetry','','[]','懸崖多蝙蝠，往往壽千年。',48,'全唐诗/poet.song.227000.json','["懸崖多蝙蝠，往往壽千年。", "自古人難到，如今爾得先。", "所餐崖上乳，不出甕中天。", "自有攀援者，曾看抱朴篇。"]'),
('b0b382be-1ce7-4951-802e-ba4f3b9380ce','和太師平章魏國賈公遺潛侍郎之作','陳存','宋','宋诗','song-poetry','','[]','先臘催開萬玉林，人心悅處即天心。',64,'全唐诗/poet.song.227000.json','["先臘催開萬玉林，人心悅處即天心。", "山河洞徹重瞳遠，宮闕高寒一柱任。", "瑞應崆峒知有日，塵清洄曲在斯今。", "神功變化無留迹，便放陽春捲積陰。"]'),
('83346f03-76c8-4f77-a659-4c5ca1640ed8','挽趙良淳三首  其一','陳存','宋','宋诗','song-poetry','','[]','日慘天無色，城危歲迫除。',48,'全唐诗/poet.song.227000.json','["日慘天無色，城危歲迫除。", "孤忠元自許，一死不知餘。", "束衽全遺體，呼兒受訣書。", "登陴才信宿，腸斷正愁予。"]'),
('3e0174c4-ec5c-4ad5-a7e0-ffdbdb1a0328','挽趙良淳三首  其二','陳存','宋','宋诗','song-poetry','','[]','忠定扶神鼎，安邦不顧身。',48,'全唐诗/poet.song.227000.json','["忠定扶神鼎，安邦不顧身。", "曾孫能致命，屬籍豈無人。", "歸骨番江上，招魂霅水濱。", "死生均此念，老病泣遺民。"]'),
('e8294a3f-1a85-4be7-be05-c6bf9c2fe02a','挽趙良淳三首  其三','陳存','宋','宋诗','song-poetry','','[]','慷慨君酬國，奔逃我喪家。',48,'全唐诗/poet.song.227000.json','["慷慨君酬國，奔逃我喪家。", "陸沈同一壑，淵涉眇無涯。", "祈死惟嫌晚，餘生只自嗟。", "蒿萊連雉堞，落日噪棲鴉。"]'),
('8253c4ff-88f8-4f51-8cae-17f959e17f77','丹陽作','陳存','宋','宋诗','song-poetry','','[]','暫入新豐市，猶聞舊酒香。',24,'全唐诗/poet.song.227000.json','["暫入新豐市，猶聞舊酒香。", "抱琴沽一醉，盡日卧垂楊。"]'),
('21b6eb88-a950-4995-9204-ad277f1782fe','句','陳存','宋','宋诗','song-poetry','','[]','雲連京國深。',6,'全唐诗/poet.song.227000.json','["雲連京國深。"]'),
('4da3891d-9cfa-4f2d-bea3-5d906691ad0f','茉莉花  其一','江奎','宋','宋诗','song-poetry','','[]','靈種傳聞出越裳，何人提挈上蠻航。',32,'全唐诗/poet.song.227000.json','["靈種傳聞出越裳，何人提挈上蠻航。", "他年我若修花史，列作人間第一香。"]'),
('f28209ae-c4d6-4505-a1e1-74bfd0ffaedc','茉莉花  其二','江奎','宋','宋诗','song-poetry','','[]','雖無艷態驚群目，幸有濃香壓九秋。',32,'全唐诗/poet.song.227000.json','["雖無艷態驚群目，幸有濃香壓九秋。", "應是仙娥宴歸去，醉來掉下玉搔頭。"]'),
('ab0a702b-47b3-44c5-9691-4d019e0cad29','烟雨樓','葉隆禮','宋','宋诗','song-poetry','','[]','傍家亭館占湖東，寂寞爲鄰祗陸公。',64,'全唐诗/poet.song.227000.json','["傍家亭館占湖東，寂寞爲鄰祗陸公。", "竹樹一堤如有礙，乾坤萬象自無窮。", "棹歌遠入秋波綠，塔影中分晚照紅。", "尊酒待遊烟雨景，畫圖著我笠蓑翁。"]'),
('0bb5beba-f009-41b4-95c8-1a5bd81ec8af','浯溪','劉錫','宋','宋诗','song-poetry','','[]','興廢由來只靠天，三郎往事亦堪憐。',32,'全唐诗/poet.song.227000.json','["興廢由來只靠天，三郎往事亦堪憐。", "湘江直下浯溪上，翕霍于今五百年。"]'),
('36e0d9ea-c146-466d-ba89-01b8623ff534','月巖','劉錫','宋','宋诗','song-poetry','','[]','不比弋陽名浪傳，疊空三日透山巔。',64,'全唐诗/poet.song.227000.json','["不比弋陽名浪傳，疊空三日透山巔。", "巖分前後兩弦缺，天到中央一月圓。", "屋擬蟾宮新學士，臺存石磴舊遊仙。", "玲瓏望處人間近，影照奇峯千□連。"]'),
('8d2cfbfe-21d6-4aee-ac8c-3a82a1e467fe','宿沖佑觀','車柬','宋','宋诗','song-poetry','','[]','纔說昇真意豁然，此行却喜結仙緣。',64,'全唐诗/poet.song.227000.json','["纔說昇真意豁然，此行却喜結仙緣。", "步穿空翠雲生脚，仰看飛流雪滿肩。", "控鶴不來春寂寂，卧龍無底月娟娟。", "飄然便作乘風想，不待丹成到九天。"]'),
('700e0160-7db9-4b41-b18c-591f6ecd9c96','謁文公祠','車柬','宋','宋诗','song-poetry','','[]','世間萬境一蘧廬，與道俱存是此書。',64,'全唐诗/poet.song.227000.json','["世間萬境一蘧廬，與道俱存是此書。", "千載歸來人化鶴，滿腔真樂我知魚。", "要將德業參天運，莫把光陰擲歲餘。", "靜裏功夫終透澈，一庭明月夜窗虛。"]'),
('d299d063-32ff-4cf1-b22b-abb0661a6e74','平園','余季芳','宋','宋诗','song-poetry','','[]','柳暗花明自一春，青山繚繞水如襟。',64,'全唐诗/poet.song.227000.json','["柳暗花明自一春，青山繚繞水如襟。", "偶然覓得桃源路，便欲分棲竹屋陰。", "清晝平原尋小隠，夕陽歸路入閒吟。", "遲遲風袂烟堤上，遥望環溪鴨綠深。"]'),
('dd0ea1cd-45aa-487d-88d3-dc88c051c5ed','宴建昌耋老','鍾季玉','宋','宋诗','song-poetry','','[]','大老如游更老彭，迎來公宇共稱觥。',64,'全唐诗/poet.song.227000.json','["大老如游更老彭，迎來公宇共稱觥。", "問年齊說生乾道，有日重新見太平。", "八九十翁同勝會，一千餘歲侈耆英。", "燕毛序齒關風化，觀感油然孝敬生。"]'),
('270fb797-035e-40ff-8fc4-5db33edd25fd','和竹塢過曹柘嶺','程元岳','宋','宋诗','song-poetry','','[]','浮邱千載尚相聞，解轡精藍月未曛。',64,'全唐诗/poet.song.227000.json','["浮邱千載尚相聞，解轡精藍月未曛。", "一霎陰晴一霎雨，幾重山水幾重雲。", "輕簧囀處聞求友，濃綠叢邊對此君。", "更有山靈呈狀巧，殢人花木亦欣欣。"]'),
('281bfcd7-7c5a-466f-8885-c089bea847fb','雲巖','程元岳','宋','宋诗','song-poetry','','[]','直上雲嚴絕頂峯，始知塵世有仙蹤。',64,'全唐诗/poet.song.227000.json','["直上雲嚴絕頂峯，始知塵世有仙蹤。", "懸崖蘚潤經年雨，滿地花飄昨夜風。", "日月往來蒼翠杪，煙霞舒卷畫圖中。", "瓊臺禮罷笙簫歇，萬壑松聲自羽宮。"]'),
('982a8f4f-c187-4739-a721-67d1a7bf8f8c','觀黄山仙人藥臼','程元岳','宋','宋诗','song-poetry','','[]','藥臼空遺千載名，丹成人向九天行。',32,'全唐诗/poet.song.227000.json','["藥臼空遺千載名，丹成人向九天行。", "我來欲覓刀圭劑，只聽寒泉佩玉聲。"]'),
('c091abaa-7a51-4688-8589-33db74ba63b6','遊黄山次韻','程元岳','宋','宋诗','song-poetry','','[]','謾宿林間夜對牀，鐘魚衍度幾星霜。',64,'全唐诗/poet.song.227000.json','["謾宿林間夜對牀，鐘魚衍度幾星霜。", "月高花影頻開畫，風動松聲自鼓簧。", "人事懸知春日好，禪心不作少年狂。", "重來爲稱裴公約，萬綠陰中醅酒香。"]'),
('9a48c48b-8613-4a64-a5af-1450f987f26c','仙棋石','程元岳','宋','宋诗','song-poetry','','[]','傳聞棋不在中峯，曾有樵夫得一逢。',32,'全唐诗/poet.song.227000.json','["傳聞棋不在中峯，曾有樵夫得一逢。", "自後世人無處覓，雲溪花洞幾重重。"]'),
('196b82eb-c10a-4a33-9e3b-1e9eeb0b3b50','句','羅太𡉷','宋','宋诗','song-poetry','','[]','素絲不改衣冠舊，黄道從教日月新。',16,'全唐诗/poet.song.227000.json','["素絲不改衣冠舊，黄道從教日月新。"]'),
('98192bd9-0f53-425a-867a-349033dafa9f','句','紀應炎','宋','宋诗','song-poetry','','[]','三年南海清心坐，一任東君冷眼看。',16,'全唐诗/poet.song.227000.json','["三年南海清心坐，一任東君冷眼看。"]'),
('3b93d8ca-1630-4dc9-b08f-bb50f4042a55','建府戊午鹿嗚宴','葉夢鼎','宋','宋诗','song-poetry','','[]','黄堂燕衎盛衣冠，人道魁星照建安。',64,'全唐诗/poet.song.227000.json','["黄堂燕衎盛衣冠，人道魁星照建安。", "多士權衡推月旦，一番桃李屬春官。", "升歌鳴鹿陪樽俎，好與溟鵬插羽翰。", "發策致身須正學，功名久遠要人看。"]'),
('b75c4f0f-836c-4e39-aaac-026c5356186b','瀛洲亭','葉夢鼎','宋','宋诗','song-poetry','','[]','汝城高處著危闌，人在蒼寒縹緲間。',64,'全唐诗/poet.song.227000.json','["汝城高處著危闌，人在蒼寒縹緲間。", "下瞰無邊春境界，西來第一處江山。", "酒拈重碧酣詩思，柳曳輕黄入笑顔。", "閣老可能專此勝，蛾眉花底又催班。"]'),
('6655cd2e-2373-4f77-b226-156ede140b4b','武夷鼓樓巖','葉夢鼎','宋','宋诗','song-poetry','','[]','鼓樓巖下鼓樓開，舉世邯鄲夢未回。',32,'全唐诗/poet.song.227000.json','["鼓樓巖下鼓樓開，舉世邯鄲夢未回。", "安得老鼉教喚起，萬人醒眼上山來。"]'),
('481bf3cc-c67f-43ca-9fca-2bd0fb211297','隔竹','葉夢鼎','宋','宋诗','song-poetry','','[]','隔竹斜陽喚小舟，寥寥天柱訪仙遊。',64,'全唐诗/poet.song.227000.json','["隔竹斜陽喚小舟，寥寥天柱訪仙遊。", "風聲樹杪疑笙鶴，雲氣峰頭見翠虬。", "凡骨面巖那可蛻，塵容鏡水只包羞。", "幾時肝膽無羈靮，卧看中天素月流。"]'),
('a14f96bc-88dc-4b77-9930-cf897ec44412','武夷九曲','葉夢鼎','宋','宋诗','song-poetry','','[]','興窮九折更悠然，棹轉船頭障去川。',32,'全唐诗/poet.song.227000.json','["興窮九折更悠然，棹轉船頭障去川。", "留取洞中無盡意，桃花水暖鱖魚天。"]'),
('7081a42a-0448-4bb9-bb02-4bb042aa1c81','梅林八景總咏','葉夢鼎','宋','宋诗','song-poetry','','[]','黄墩巨海通昌國，花園大路連西域。',64,'全唐诗/poet.song.227000.json','["黄墩巨海通昌國，花園大路連西域。", "九頃農歌樂豐年，赤山牧唱喧朝夕。", "羅溪流水出通潮，仕岆高山古賢跡。", "方寺鐘聲誦善音，桃源擊鼓評民籍。"]'),
('134d0822-8e7e-4d5f-8626-ff493a03ad88','句','葉夢鼎','宋','宋诗','song-poetry','','[]','蘆笋滿洲銀鱠美，瓊花滴露玉醅醇。',16,'全唐诗/poet.song.227000.json','["蘆笋滿洲銀鱠美，瓊花滴露玉醅醇。"]'),
('da2abf0c-279f-4461-bd70-a4b847e4aff0','演雅  其一','汪韶','宋','宋诗','song-poetry','','[]','布谷不耕不穡，巧婦無褐無衣。',28,'全唐诗/poet.song.227000.json','["布谷不耕不穡，巧婦無褐無衣。", "提壺不可挹酒，絡緯寧來貿絲。"]'),
('9301667a-c6b0-4602-9833-63294e79fc6d','演雅  其二','汪韶','宋','宋诗','song-poetry','','[]','蜾蠃堯舜父子，鴻雁魯衛弟兄。',28,'全唐诗/poet.song.227000.json','["蜾蠃堯舜父子，鴻雁魯衛弟兄。", "鬭蟻滕薛爭長，狎鷗晉鄭尋盟。"]'),
('db73cdff-9c9e-4b4f-aa75-eb697cbb89f8','讀史','汪韶','宋','宋诗','song-poetry','','[]','南北幾離合，江山一古今。',48,'全唐诗/poet.song.227000.json','["南北幾離合，江山一古今。", "秋風駝卧棘，春雨燕巢林。", "家國興亡夢，英雄勝敗心。", "九疑呼不起，愁絕暮雲深。"]'),
('136fb223-0a64-4976-b3ce-ee4a84bea98b','孫武','汪韶','宋','宋诗','song-poetry','','[]','爲憂玩色墮軍實，故假陳兵去二姬。',32,'全唐诗/poet.song.227000.json','["爲憂玩色墮軍實，故假陳兵去二姬。", "却恨此機深莫悟，後人不諫受西施。"]'),
('ab4305ab-c073-4956-8ad1-34aaef32aaec','句','汪韶','宋','宋诗','song-poetry','','[]','十八九常如意少，百千億任化身多。',16,'全唐诗/poet.song.227000.json','["十八九常如意少，百千億任化身多。"]'),
('1303562a-698c-415a-82d2-d96d211a5b0a','東湖','李澤民','宋','宋诗','song-poetry','','[]','四圍圖畫簇鮮妍，爲托湖天匯衆川。',64,'全唐诗/poet.song.227000.json','["四圍圖畫簇鮮妍，爲托湖天匯衆川。", "蟻運筧泥千嶂滿，虹牽堤勢兩山連。", "旌旗耀日鼓鼙壯，冠蓋如雲羅綺鮮。", "才謭冒然興大役，幸而集事謝群賢。"]'),
('e5624142-e665-46fd-9439-b9d47e6e6236','呈孫元素','呂祖异','宋','宋诗','song-poetry','','[]','匹馬先來破曉雲，千章喬本翠繽紛。',64,'全唐诗/poet.song.227000.json','["匹馬先來破曉雲，千章喬本翠繽紛。", "山圍道院窗窗見，泉出丹池處處分。", "酒好便能澆磈磊，飯香何必御羶葷。", "明朝又踏紅塵去，多羨烟霞總屬君。"]'),
('b7a14f65-ccfc-446c-b272-7fd2ccaf0b25','重游洞庭','呂祖异','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','重來洞庭野，往事付行雲。',48,'全唐诗/poet.song.227000.json','["重來洞庭野，往事付行雲。", "樂奏思黄帝，珠寒訝鄂君。", "朝廷用儒術，兵甲洗妖氛。", "好在胸中策，堂堂整六軍。"]'),
('17c90496-6001-43db-9634-edeae33314f9','句  其一','俞君錫','宋','宋诗','song-poetry','','[]','洗瓢魚隠石，掃葉蟻移家。',12,'全唐诗/poet.song.227000.json','["洗瓢魚隠石，掃葉蟻移家。"]'),
('18eb807e-c75a-40ff-8461-7c267f39d745','句  其二','俞君錫','宋','宋诗','song-poetry','','[]','野猿偷果去，村僕借書還。',12,'全唐诗/poet.song.227000.json','["野猿偷果去，村僕借書還。"]'),
('459c65b3-793c-46d7-907d-b91159686815','句  其三','俞君錫','宋','宋诗','song-poetry','','[]','教僕掃枯葉，留僧煎早茶。',12,'全唐诗/poet.song.227000.json','["教僕掃枯葉，留僧煎早茶。"]'),
('559f43ce-03ae-4384-a432-b7c49476f69c','句  其四','俞君錫','宋','宋诗','song-poetry','','[]','荒店難尋酒，長途半趁船。',12,'全唐诗/poet.song.227000.json','["荒店難尋酒，長途半趁船。"]'),
('7f0654b4-0d68-4257-9255-48dc9eb3ca90','句  其五','俞君錫','宋','宋诗','song-poetry','','[]','蛩聲依壞砌，樹影倒寒池。',12,'全唐诗/poet.song.227000.json','["蛩聲依壞砌，樹影倒寒池。"]'),
('26741adb-9ae3-4c5f-85d0-77e6f81f7d66','句  其六','俞君錫','宋','宋诗','song-poetry','','[]','半身長在旅，何日定還家。',12,'全唐诗/poet.song.227000.json','["半身長在旅，何日定還家。"]'),
('003f756e-9f32-48bb-add1-0c6dea2e6424','題天慶觀碧玉堂','龔準','宋','宋诗','song-poetry','','[]','清曉叩玄關，憂時鬢已斑。',24,'全唐诗/poet.song.227000.json','["清曉叩玄關，憂時鬢已斑。", "何如閑道士，隔竹看君山。"]'),
('eb6b06ae-412c-423f-91dc-db1231b7d0cf','登浙江樓','趙與滂','宋','宋诗','song-poetry','','[]','兩岸共明月，闌干霄漢間。',48,'全唐诗/poet.song.227000.json','["兩岸共明月，闌干霄漢間。", "風波浙江水，砥柱海門山。", "晝夜潮消長，利名人往還。", "不如沙上鷺，玉立一身閑。"]'),
('da5dece9-e5ce-46ac-af7a-7a930ded4c01','花院','趙與滂','宋','宋诗','song-poetry','','[]','拆了千秋院宇空，無人楊柳自春風。',32,'全唐诗/poet.song.227000.json','["拆了千秋院宇空，無人楊柳自春風。", "薔薇性野難拘束，却過鄰家屋上紅。"]'),
('5e2e6098-9c18-463b-86e5-3b5c955d70c0','牽牛花','趙與滂','宋','宋诗','song-poetry','','[]','西風樵子谷，藤蔓絡柴關。',48,'全唐诗/poet.song.227000.json','["西風樵子谷，藤蔓絡柴關。", "名在星河上，花開曉露間。", "秋空同碧色，曉日轉紅顔。", "若挂青松頂，翛然不可攀。"]'),
('b2498f7b-6326-4626-8d93-e906fe0c1405','山居苦','趙與滂','宋','宋诗','song-poetry','','[]','隠君家翠微，茆屋竹爲扉。',48,'全唐诗/poet.song.227000.json','["隠君家翠微，茆屋竹爲扉。", "紅日自朝暮，青山絕是非。", "野花無蝶管，怪木有神依。", "益信林泉樂，年高白髮希。"]'),
('f4d3eb83-9ebd-4716-94a6-5146597bcea3','村居','趙與滂','宋','宋诗','song-poetry','','[]','郊外草爲堂，悠然世慮忘。',48,'全唐诗/poet.song.227000.json','["郊外草爲堂，悠然世慮忘。", "竹衰花結實，蜂旺子分王。", "村路規模狹，溪流曲折長。", "晚山惜餘景，未肯下斜陽。"]'),
('78c66cfa-a31b-4d4f-97b2-30084e7499a1','題晏國師喝水巖','趙與滂','宋','宋诗','song-poetry','','[]','古磚出唐井，豫識國師名。',48,'全唐诗/poet.song.227000.json','["古磚出唐井，豫識國師名。", "於此坐禪處，喝回流水聲。", "如何神晏塔，移作李綱塋。", "見說山中石，不平空自鳴。"]'),
('99ba8acb-1ae4-435f-9b33-ad3a255412f5','題湧泉亭詩石','趙與滂','宋','宋诗','song-poetry','','[]','詩題蔗境不題名，墨蹟懸巖碧蘚平。',32,'全唐诗/poet.song.227000.json','["詩題蔗境不題名，墨蹟懸巖碧蘚平。", "游宦來看心忽悟，前身應是趙先生。"]'),
('8b69f815-a9df-49d1-8b7c-e824b68aa962','瀕死自悼','徐琦','宋','宋诗','song-poetry','','[]','每說天兵出守疆，忽聞勁敵犯睢陽。',64,'全唐诗/poet.song.227000.json','["每說天兵出守疆，忽聞勁敵犯睢陽。", "火焚郡邑人民苦，血染江淮鬼物傷。", "忠報君恩名不朽，孝隨親死義難忘。", "皇天后土宜知鑒，白日英魂騰劍光。"]'),
('3ff3ce61-f067-41b9-8b28-6934f6c1f6d0','雲溪寺','曾宋珍','宋','宋诗','song-poetry','','[]','溪水年年自淺深，山雲日日半晴陰。',32,'全唐诗/poet.song.227000.json','["溪水年年自淺深，山雲日日半晴陰。", "溪山好處劃開眼，看水看山悟此心。"]'),
('513bef48-dbcd-49d5-b9fc-4b0f6f7ab4f0','送方巨山','南康士人','宋','宋诗','song-poetry','','[]','秋崖秋壑兩般秋，湖廣江東事不侔。',32,'全唐诗/poet.song.227000.json','["秋崖秋壑兩般秋，湖廣江東事不侔。", "直到南康論體統，江西自隔兩三州。"]'),
('fd77a446-2822-45d7-a06c-a0e353755117','喝水巖','徐錫之','宋','宋诗','song-poetry','','[]','重巒複嶺鎖松關，只欠泉聲入座間。',32,'全唐诗/poet.song.227000.json','["重巒複嶺鎖松關，只欠泉聲入座間。", "我若當年侍師側，不教喝水過他山。"]'),
('91ef6a8d-6ce5-4ca0-ad2e-0e8cf4492969','戲友不識硯','戴泰','宋','宋诗','song-poetry','','[]','古今天下多奇石，甲品從來只數端。',64,'全唐诗/poet.song.227000.json','["古今天下多奇石，甲品從來只數端。", "千丈割雲潭影濕，一泓貯水月光寒。", "青瞳要辨生鴝眼，紫色須求死馬肝。", "鼠璞易投荆璞價，請君試買硯箋看。"]'),
('de8b09a8-37b3-4d79-97fd-a72e143912cd','詠練川','王子昭','宋','宋诗','song-poetry','','[]','吳淞江上流來水，鴨綠粼粼漾清泚。',224,'全唐诗/poet.song.227000.json','["吳淞江上流來水，鴨綠粼粼漾清泚。", "東風無力藹清光，一片縠紋吹不起。", "夜來雨漲三尺深，鵁鶄鸂鶒爭浮沉。", "芹芽迸土抽白玉，柳線拂浪摇青金。", "錦袍先生乘一舸，此處恍然天上坐。", "閒聽漁郎唱棹歌，遥指奇峰三四朵。", "堤旁有人新結廬，軒窗瞰水宜幽居。", "村童喚渡去沽酒，野叟就船來買魚。", "風清月淡堪娛樂，笑掬滄浪纓可濯。", "何須尋訪武陵溪，不必思吞雲夢澤。", "下流香水正遲遲，草邊得句何新奇。", "地靈人傑萃斯景，尚傳靈運嚴維詩。", "桃花浪暖魚游處，三十六鱗欲飛舉。", "有龍若向此中蟠，早爲蒼生作霖雨。"]'),
('bab6be63-f003-46cd-ba7a-d31a9f3eb7d6','歌','林自然','宋','宋诗','song-poetry','','[]','訪古老洞天，撞見神仙飲三杯。',40,'全唐诗/poet.song.227000.json','["訪古老洞天，撞見神仙飲三杯。", "復三杯，又三杯，不覺醺醺醉。", "回頭看人間，身在青烟外。"]'),
('51aaaec9-b891-487d-b697-f527b789b8fa','三禽言  其一','江心宇','宋','宋诗','song-poetry','','[]','我友我友，鞠衣黄裳。',52,'全唐诗/poet.song.227000.json','["我友我友，鞠衣黄裳。", "一日不見，爾何所翔。", "爾何所藏，飛鳴高樹去。", "毋也不忘，噫。", "高樹如何，噫。", "綠陰正多，噫。"]'),
('561a0d63-79a0-45e6-8be8-ad559805ac86','三禽言  其二','江心宇','宋','宋诗','song-poetry','','[]','燕燕尾不齊，撇裂侵泥滓，翻飛烟雨裏。',42,'全唐诗/poet.song.227000.json','["燕燕尾不齊，撇裂侵泥滓，翻飛烟雨裏。", "轉眼朱門委榛杞，權門如市止復止，天際翻飛鷹斂翅。"]'),
('9a506440-a895-4002-a59a-5d545bd0d90d','三禽言  其三','江心宇','宋','宋诗','song-poetry','','[]','布布穀，哺哺雛。',29,'全唐诗/poet.song.227000.json','["布布穀，哺哺雛。", "雨苦苦，去去乎。", "吾苦苦，吾苦苦，吾宋峁謾。"]'),
('5864aa82-7bf9-4a09-b3c0-d891ac5a656c','訣別偈','湯道亨','宋','宋诗','song-poetry','','[]','八十一年饒舌，終日化緣不歇。',28,'全唐诗/poet.song.227000.json','["八十一年饒舌，終日化緣不歇。", "重陽時節歸家，一路清風明月。"]'),
('3eb9ce40-005f-4d43-abcd-fc68a67dc52b','幽居雜興','真山民','宋','宋诗','song-poetry','','[]','松桂小菟裘，山扉幽更幽。',48,'全唐诗/poet.song.227000.json','["松桂小菟裘，山扉幽更幽。", "蜂王衙早晚，燕子社春秋。", "鬢禿難遮老，心寬不貯愁。", "年來把鋤手，無復揖公侯。"]');
